    <!-- Custom Export Modal -->
    <div class="modal-overlay" id="customExportModal" style="z-index:1000012">
        <div class="modal modal-lg" style="z-index:1000013">
            <div class="modal-header" style="gap:8px;flex-wrap:wrap">
                <h3><i class="fas fa-sliders-h" style="color:var(--coupon)"></i> تصدير مخصص</h3>
                <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">
                    <button class="btn btn-sm btn-outline" id="mobileExportToggleBtn" onclick="toggleMobileExportView()"
                        style="display:none; font-size:0.75rem; padding:4px 8px; border-radius:8px; height:30px;"><i
                            class="fas fa-eye"></i> <span>معاينة الجدول</span></button>
                    <button class="header-btn" id="customExportCsvBtn" title="تصدير CSV"><i class="fas fa-file-csv"
                            style="color:var(--success)"></i></button>
                    <button class="header-btn" id="customExportPdfBtn" title="تصدير PDF"><i class="fas fa-file-pdf"
                            style="color:var(--danger)"></i></button>
                    <button class="header-btn" id="customExportImageBtn" title="تصدير صورة"><i class="fas fa-image"
                            style="color:var(--info)"></i></button>
                    <button class="close-btn" id="closeCustomExportModal">&times;</button>
                </div>
            </div>
            <div class="export-builder">
                <div class="export-controls">
                    <div class="export-panel">
                        <div class="export-panel-title"><i class="fas fa-heading"></i> اسم التقرير</div>
                        <input type="text" class="form-input" id="customExportTitle" placeholder="مثلاً: حضور فصل أولى">
                    </div>
                    <div class="export-panel">
                        <div class="export-panel-title" style="display:flex; justify-content:space-between; align-items:center;">
                            <span><i class="fas fa-sort-alpha-down"></i> ترتيب النتائج (طبقات)</span>
                            <button type="button" class="export-mini-btn" onclick="addCustomExportSortLayer()" title="إضافة طبقة ترتيب" style="padding:2px 8px; font-size:0.75rem; border-radius:10px; background:var(--brand-bg); color:var(--brand); border:none; cursor:pointer; font-weight:700;"><i class="fas fa-plus"></i> إضافة طبقة</button>
                        </div>
                        <div id="customExportSortLayersContainer" style="display:flex; flex-direction:column; gap:8px; margin-top:8px;"></div>
                    </div>
                    <div class="export-panel">
                        <div class="export-panel-title"><i class="fas fa-table-columns"></i> البيانات والترتيب</div>
                        <div class="export-field-list" id="customExportFields"></div>
                    </div>
                    <div class="export-panel">
                        <div class="export-panel-title"><i class="fas fa-calendar-days"></i> الحضور</div>
                        <div class="export-date-options">
                            <select class="form-input" id="customExportDateMode">
                                <option value="none">بدون حضور</option>
                                <option value="current">تاريخ الحضور الحالي</option>
                                <option value="range">نطاق تواريخ</option>
                                <option value="custom">تواريخ مخصصة</option>
                                <option value="all">كل تواريخ الحضور</option>
                            </select>
                            <div id="customExportRangeInputs"
                                style="display:none;grid-template-columns:1fr 1fr;gap:6px">
                                <input type="text" class="form-input" id="customExportFromDate"
                                    placeholder="من DD/MM/YYYY" maxlength="10" inputmode="numeric"
                                    oninput="autoFormatCustomDate(this)">
                                <input type="text" class="form-input" id="customExportToDate"
                                    placeholder="إلى DD/MM/YYYY" maxlength="10" inputmode="numeric"
                                    oninput="autoFormatCustomDate(this)">
                            </div>
                            <textarea class="form-input" id="customExportDates"
                                placeholder="تواريخ مخصصة: 01/01/2026, 08/01/2026" rows="2"
                                style="display:none;min-height:54px"></textarea>
                        </div>
                    </div>
                    <button class="btn" id="customExportPreviewBtn" style="width:100%;justify-content:center"><i
                            class="fas fa-eye"></i> تحديث المعاينة</button>
                </div>
                <div class="export-preview-wrap">
                    <div id="customExportPreview" class="custom-export-doc"></div>
                </div>
            </div>
        </div>
