        // ── DATA LOADING ──────────────────────────────────────────────
        function loadData() {
            // Try to load and show cached local data immediately (silently)
            const cached = localStorage.getItem('lastStudentsData');
            let cacheLoaded = false;
            if (cached) {
                try {
                    const d = JSON.parse(cached);
                    students = d.students || d.allStudents || [];
                    allStudentsData = d.allStudents || d.students || students;
                    if (d.classes && d.classes.length) {
                        classes = d.classes.sort((a, b) => getClassOrderWeight(a.arabic_name || a.code) - getClassOrderWeight(b.arabic_name || b.code));
                    }
                    const cachedUncles = localStorage.getItem('lastUnclesData');
                    if (cachedUncles) {
                        try {
                            window.allUnclesData = JSON.parse(cachedUncles);
                            window.allUnclesData.forEach(u => {
                                u._isUncle = true;
                                u['الاسم'] = u.name;
                                u['الفصل'] = 'الخدام';
                                u['رقم التليفون'] = u.phone || '';
                                u['عيد الميلاد'] = '';
                                u['النوع'] = u.gender || 'male';
                                u['صورة'] = u.image_url || '';
                                u._customInfo = u.custom_info ? (typeof u.custom_info === 'string' ? JSON.parse(u.custom_info) : u.custom_info) : {};
                            });
                        } catch (e) { }
                    }
                    const cachedGuests = localStorage.getItem('lastGuestsData');
                    if (cachedGuests) {
                        try {
                            window.allGuestsData = JSON.parse(cachedGuests);
                            window.allGuestsData.forEach(g => {
                                g._isGuest = true;
                                g['الاسم'] = g.name;
                                g['الفصل'] = 'الزوار';
                                g['رقم التليفون'] = g.phone || '';
                                g['عيد الميلاد'] = '';
                                g['النوع'] = g.gender || 'male';
                                g['صورة'] = g.image_url || '';
                                g._customInfo = {};
                            });
                        } catch (e) { }
                    }
                    if (!window.allGuestsData || !window.allGuestsData.length) {
                        window.allGuestsData = students.filter(s => s._isGuest == 1 || s._isGuest === true || s['الفصل'] === 'الزوار');
                        window.allGuestsData.forEach(g => {
                            g._isGuest = true;
                            g['الاسم'] = g.name || g['الاسم'];
                            g['الفصل'] = g['الفصل'] || 'الزوار';
                            g['رقم التليفون'] = g.phone || g['رقم التليفون'] || '';
                            g['عيد الميلاد'] = g['عيد الميلاد'] || '';
                            g['النوع'] = g.gender || g['النوع'] || 'male';
                            g['صورة'] = g.image_url || g['صورة'] || '';
                            g._customInfo = g._customInfo || {};
                        });
                    }
                    updateDashboardStats();
                    loadDashboardTrips();
                    if (!currentClass) {
                        displayClasses();
                    } else {
                        renderTodayBirthdayBanner();
                    }
                    updateCurrentDateDisplay();
                    if (currentClass) {
                        loadAttendanceDataForClass(currentClass);
                        renderAttendanceList(currentClass);
                        updateClassStats();
                        loadClassUncles(currentClass);
                        loadPendingRegistrationsForClass(currentClass);
                    }
                    // Restore hash view
                    if (window._pendingHashRestore) {
                        const { type, value } = window._pendingHashRestore;
                        window._pendingHashRestore = null;
                        if (type === 'class') {
                            const found = students.some(s => s['الفصل'] === value);
                            if (found) showClassViewInternal(value);
                            else if (value) showClassViewInternal(value);
                        } else if (type === 'combined' && value) {
                            showCombinedClassView(value);
                        } else if (type === 'account') {
                            showAccountModalInternal();
                        }
                    }
                    setTimeout(updateSaveBtns, 300);
                    cacheLoaded = true;
                } catch (e) {
                    console.error("Cache load error:", e);
                }
            }

            if (!navigator.onLine) {
                isDashboardDataLoading = false;
                if (!cacheLoaded) {
                    _loadDataFromCache();
                }
                return;
            }

            isDashboardDataLoading = true;
            if (!cacheLoaded) {
                const grid = document.getElementById('classesGrid');
                if (grid && !currentClass) {
                    renderClassesSkeleton();
                }
                const list = document.getElementById('attendanceList');
                if (list && currentClass) {
                    list.innerHTML = '<div class="skeleton-loader" style="grid-column:1/-1">' + Array(5).fill('<div class="skeleton-row"></div>').join('') + '</div>';
                }
            }

            makeApiCall({ action: 'getData' }, r => {
                const freshString = JSON.stringify(r);
                const dataChanged = cached !== freshString;

                if (dataChanged || !cacheLoaded) {
                    if (r.data && Array.isArray(r.data)) students = r.data;
                    else if (r.allStudents && Array.isArray(r.allStudents)) students = r.allStudents;
                    allStudentsData = students;
                    if (r.classes && Array.isArray(r.classes)) {
                        classes = r.classes.sort((a, b) => getClassOrderWeight(a.arabic_name || a.code) - getClassOrderWeight(b.arabic_name || b.code));
                    }

                    try {
                        localStorage.setItem('lastStudentsData', freshString);
                    } catch (e) { }

                    if (window._prunePhotoCache) {
                        const activeUrls = new Set(students.map(s => s['صورة']).filter(Boolean));
                        window._prunePhotoCache(activeUrls);
                    }

                    updateDashboardStats();
                    loadDashboardTrips();
                    if (!currentClass) displayClasses();
                    else renderTodayBirthdayBanner();
                    _maybeSendBirthdayNotification();
                    if (currentClass) {
                        loadAttendanceDataForClass(currentClass);
                        renderAttendanceList(currentClass);
                        updateClassStats();
                        loadClassUncles(currentClass);
                        loadPendingRegistrationsForClass(currentClass);
                    }
                    prefetchStudentPhotos(students);
                }

                // Always fetch uncles online if the user is logged in
                const userRole = (window.currentUncle && window.currentUncle.role) || localStorage.getItem('uncleRole') || '';
                if (userRole) {
                    makeApiCall({ action: 'getAllUncles' }, ru => {
                        if (ru.success && Array.isArray(ru.uncles)) {
                            window.allUnclesData = ru.uncles;
                            window.allUnclesData.forEach(u => {
                                u._isUncle = true;
                                u['الاسم'] = u.name;
                                u['الفصل'] = 'الخدام';
                                u['رقم التليفون'] = u.phone || '';
                                u['عيد الميلاد'] = '';
                                u['النوع'] = u.gender || 'male';
                                u['صورة'] = u.image_url || '';
                                u._customInfo = u.custom_info ? (typeof u.custom_info === 'string' ? JSON.parse(u.custom_info) : u.custom_info) : {};
                            });
                            try {
                                localStorage.setItem('lastUnclesData', JSON.stringify(ru.uncles));
                            } catch (e) { }
                            displayClasses();
                            if (currentClass === 'الخدام') {
                                loadAttendanceDataForClass('الخدام');
                                renderAttendanceList('الخدام');
                                updateClassStats();
                            }
                        }
                    });
                    // Derive guests data from students
                    window.allGuestsData = students.filter(s => s._isGuest == 1 || s._isGuest === true || s['الفصل'] === 'الزوار');
                    window.allGuestsData.forEach(g => {
                        g._isGuest = true;
                        g['الاسم'] = g.name || g['الاسم'];
                        g['الفصل'] = g['الفصل'] || 'الزوار';
                        g['رقم التليفون'] = g.phone || g['رقم التليفون'] || '';
                        g['عيد الميلاد'] = g['عيد الميلاد'] || '';
                        g['النوع'] = g.gender || g['النوع'] || 'male';
                        g['صورة'] = g.image_url || g['صورة'] || '';
                        g._customInfo = g._customInfo || {};
                    });
                    try {
                        localStorage.setItem('lastGuestsData', JSON.stringify(window.allGuestsData));
                    } catch (e) { }
                    displayClasses();
                    if (currentClass === 'الزوار') {
                        renderAttendanceList('الزوار');
                        updateClassStats();
                    }
                }

                if (window._pendingHashRestore) {
                    const { type, value } = window._pendingHashRestore;
                    window._pendingHashRestore = null;
                    if (type === 'class' && value) {
                        const match = students.some(s => s['الفصل'] === value);
                        if (match) {
                            showClassViewInternal(value);
                        } else {
                            const found = [...new Set(students.map(s => s['الفصل']))].find(n => n && n.trim() === value.trim());
                            if (found) showClassViewInternal(found);
                            else showClassViewInternal(value);
                        }
                    } else if (type === 'combined' && value) {
                        showCombinedClassView(value);
                    } else if (type === 'account') {
                        showAccountModalInternal();
                    }
                }
                setTimeout(updateSaveBtns, 300);
                isDashboardDataLoading = false;
            }, () => {
                if (!cacheLoaded) {
                    _loadDataFromCache();
                } else {
                    isDashboardDataLoading = false;
                    showToast('فشلت مزامنة البيانات مع السيرفر، تعمل حالياً من الذاكرة المحلية', 'warning');
                }
            });
        }

        function _loadDataFromCache(silent = false) {
            isDashboardDataLoading = false;
            const cached = localStorage.getItem('lastStudentsData');
            if (cached) {
                try {
                    const d = JSON.parse(cached);
                    students = d.students || d.allStudents || [];
                    allStudentsData = d.allStudents || d.students || students;
                    if (d.classes && d.classes.length) {
                        classes = d.classes.sort((a, b) => getClassOrderWeight(a.arabic_name || a.code) - getClassOrderWeight(b.arabic_name || b.code));
                    }
                    updateDashboardStats();
                    loadDashboardTrips();
                    if (!currentClass) {
                        if (silent) renderClassesSkeleton();
                        else displayClasses();
                    } else renderTodayBirthdayBanner();
                    updateCurrentDateDisplay();
                    if (currentClass) {
                        loadAttendanceDataForClass(currentClass);
                        renderAttendanceList(currentClass);
                        updateClassStats();
                        loadClassUncles(currentClass);
                        loadPendingRegistrationsForClass(currentClass);
                    }
                    // Restore hash view
                    if (window._pendingHashRestore) {
                        const { type, value } = window._pendingHashRestore;
                        window._pendingHashRestore = null;
                        if (type === 'class') {
                            const found = students.some(s => s['الفصل'] === value);
                            if (found) showClassViewInternal(value);
                            else if (value) showClassViewInternal(value); // try anyway with cached data
                        } else if (type === 'combined' && value) {
                            showCombinedClassView(value);
                        } else if (type === 'account') {
                            showAccountModalInternal();
                        }
                    }
                    if (!silent) showToast('تعمل بدون إنترنت — البيانات من الذاكرة المحلية', 'warning');
                } catch (e) {
                    if (!silent) showToast('لا يمكن تحميل البيانات بدون إنترنت', 'error');
                }
            } else {
                if (!silent) showToast('لا يوجد بيانات محفوظة — يرجى الاتصال بالإنترنت', 'error');
            }
            setTimeout(updateSaveBtns, 300);
        }

        // ── DISPLAY ───────────────────────────────────────────────────
        // ── TODAY'S BIRTHDAY BANNER ───────────────────────────────────
        function getTodayBirthdays() {
            const now = new Date();
            const todayDay = now.getDate(), todayMonth = now.getMonth(); // month 0-based
            return (allStudentsData.length ? allStudentsData : students).filter(s => {
                if (!s['عيد الميلاد']) return false;
                const p = s['عيد الميلاد'].split('/');
                if (p.length < 2) return false;
                return parseInt(p[0]) === todayDay && parseInt(p[1]) - 1 === todayMonth;
            });
        }

        function toggleStats() {
            const row = document.getElementById('mainStatsRow');
            const btn = document.getElementById('toggleStatsBtn');
            if (!row || !btn) return;
            const isHidden = row.style.display === 'none';

            const items = getWeekBirthdays();
            const todayItems = items.filter(item => item.isToday);
            const todayCount = todayItems.length;
            const badgeHtml = todayCount > 0 ? `<span class="bday-badge-count"> (${todayCount})</span>` : '';

            if (isHidden) {
                row.style.display = 'block';
                btn.innerHTML = `<i class="fas fa-chevron-up" id="statsCollapseIcon" style="margin-left: 5px;"></i> إخفاء أعياد الميلاد${badgeHtml}`;
                localStorage.setItem('statsCollapsed', 'false');
            } else {
                row.style.display = 'none';
                btn.innerHTML = `<i class="fas fa-chevron-down" id="statsCollapseIcon" style="margin-left: 5px;"></i> عرض أعياد الميلاد${badgeHtml}`;
                localStorage.setItem('statsCollapsed', 'true');
            }
        }

        function getWeekBirthdays() {
            const today = new Date();
            const todayDay = today.getDate(), todayMonth = today.getMonth();
            const jsDay = dbDayToJsDay(churchAttendanceDay || 'Friday');

            // Next celebration date (closest configured attendance day, today or future)
            let celebrationDate = new Date(today);
            let diff = (jsDay - today.getDay() + 7) % 7;
            celebrationDate.setDate(today.getDate() + diff);

            // Generate the 7 dates of the week cycle (from Saturday to Friday, or equivalent)
            const cycleDates = [];
            for (let i = 0; i < 7; i++) {
                const d = new Date(celebrationDate);
                d.setDate(celebrationDate.getDate() - i);
                cycleDates.push(d);
            }

            const srcList = allStudentsData.length ? allStudentsData : students;
            const results = [];

            srcList.forEach(s => {
                if (!s['عيد الميلاد']) return;
                const parts = s['عيد الميلاد'].split('/');
                if (parts.length < 2) return;
                const bdayDay = parseInt(parts[0]);
                const bdayMonth = parseInt(parts[1]) - 1; // 0-based

                // Find if this birth day/month matches any date in the cycle
                const matchDate = cycleDates.find(d => d.getDate() === bdayDay && d.getMonth() === bdayMonth);
                if (matchDate) {
                    const isToday = bdayDay === todayDay && bdayMonth === todayMonth;

                    // Determine weekday name in Arabic
                    const arabicDays = ['الأحد', 'الإثنين', 'الثلاثاء', 'الأربعاء', 'الخميس', 'الجمعة', 'السبت'];
                    const dayName = arabicDays[matchDate.getDay()];

                    results.push({
                        student: s,
                        isToday,
                        dayName,
                        birthDateStr: s['عيد الميلاد'],
                        matchDate
                    });
                }
            });

            // Sort results by the cycle day order (from Saturday to Friday)
            results.sort((a, b) => {
                const idxA = cycleDates.indexOf(a.matchDate);
                const idxB = cycleDates.indexOf(b.matchDate);
                return idxB - idxA;
            });

            return results;
        }

        function toggleBdayView() {
            const list = document.getElementById('todayBirthdayList');
            const icon = document.getElementById('bdayCollapseIcon');
            if (!list) return;
            const isGrid = list.classList.toggle('grid-view');
            if (icon) {
                icon.style.transform = isGrid ? 'rotate(180deg)' : 'rotate(0deg)';
            }
            if (!isGrid) {
                const items = getWeekBirthdays();
                let targetIndex = items.findIndex(item => item.isToday);
                if (targetIndex === -1 && items.length > 0) {
                    targetIndex = items.length - 1;
                }
                if (targetIndex !== -1) {
                    setTimeout(() => {
                        const targetEl = document.getElementById(`bday_chip_${targetIndex}`);
                        if (targetEl && list) {
                            targetEl.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
                        }
                    }, 50);
                }
            }
        }

        // Collapse/expand the birthday list by clicking the header
        function toggleBdayCollapse() {
            const list = document.getElementById('todayBirthdayList');
            const icon = document.getElementById('bdayCollapseIcon');
            if (!list) return;
            const isCollapsed = list.style.display === 'none';
            if (isCollapsed) {
                list.style.display = '';
                if (icon) icon.style.transform = 'rotate(0deg)';
                localStorage.setItem('bdayCollapsed', 'false');
            } else {
                list.style.display = 'none';
                if (icon) icon.style.transform = 'rotate(-90deg)';
                localStorage.setItem('bdayCollapsed', 'true');
            }
        }


        function renderTodayBirthdayBanner() {
            const banner = document.getElementById('mainStatsRow');
            const list = document.getElementById('todayBirthdayList');
            const title = document.getElementById('todayBirthdayTitle');
            const icon = document.getElementById('bdayCollapseIcon');

            if (!banner || !list) return;
            const items = getWeekBirthdays();

            const todayItems = items.filter(item => item.isToday);
            const todayCount = todayItems.length;

            if (!items.length) {
                banner.style.display = 'none';
                return;
            } else {
                banner.style.display = 'block';
            }

            if (todayCount > 0) {
                title.textContent = `أعياد ميلاد اليوم`;
            } else {
                title.textContent = `أعياد ميلاد هذا الأسبوع`;
            }

            // Restore collapsed state
            let bdayPref = localStorage.getItem('bdayCollapsed');
            if (bdayPref === null) {
                bdayPref = 'false'; // Open by default!
            }
            const isCollapsed = bdayPref === 'true';
            if (isCollapsed) {
                list.style.display = 'none';
                if (icon) icon.style.transform = 'rotate(-90deg)';
            } else {
                list.style.display = '';
                if (icon) icon.style.transform = 'rotate(0deg)';
            }

            list.innerHTML = items.map((item, index) => {
                const s = item.student;
                const name = s['الاسم'] || '---';
                const cls = s['الفصل'] || '';
                const photo = s['صورة'] || s['photo'] || s['الصورة'] || '';
                const safe = name.replace(/'/g, "\\'");
                const avatar = photo ? ((typeof window.photoUrl === 'function') ? window.photoUrl(photo) : photo) : `https://ui-avatars.com/api/?name=${encodeURIComponent(name)}&background=fdf4ff&color=db2777&bold=true`;
                return `
                <div class="bday-banner-chip${item.isToday ? ' today' : ''}" id="bday_chip_${index}" onclick="showStudentDetails('${safe}')">
                    <img src="${avatar}" class="bday-chip-img">
                    <div class="bday-chip-info">
                        <div class="bday-chip-name">${name}</div>
                        <div class="bday-chip-meta-row">
                            ${item.isToday ? `<span class="bday-chip-day today">اليوم 🎉</span>` : `<span class="bday-chip-day text-muted">${item.dayName}</span>`}
                            ${cls ? `<span class="bday-chip-class">${cls}</span>` : ''}
                        </div>
                    </div>
                </div>`;
            }).join('');

            // Scroll to target element (today's birthday, or last birthday of the week cycle)
            let targetIndex = items.findIndex(item => item.isToday);
            if (targetIndex === -1 && items.length > 0) {
                targetIndex = items.length - 1;
            }

            if (targetIndex !== -1) {
                setTimeout(() => {
                    const targetEl = document.getElementById(`bday_chip_${targetIndex}`);
                    const bdayList = document.getElementById('todayBirthdayList');
                    // Only scroll if we are in horizontal scroll view (not grid-view)
                    if (targetEl && bdayList && !bdayList.classList.contains('grid-view')) {
                        targetEl.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
                    }
                }, 100);
            }
        }

        function getUnsavedChangesCount(clsName, isCombined = false, grpClasses = []) {
            let count = 0;
            const allKeys = Object.keys(localStorage);

            if (clsName === '__ALL__') {
                allKeys.forEach(k => {
                    if (k.startsWith('changedStudents_') || k.startsWith('changedCouponStudents_')) {
                        try {
                            const changedIds = JSON.parse(localStorage.getItem(k) || '[]');
                            count += changedIds.length;
                        } catch (e) { }
                    }
                });
            } else if (isCombined && grpClasses && grpClasses.length) {
                allKeys.forEach(k => {
                    const prefix = `changedStudents_${clsName}_`;
                    if (k.startsWith(prefix)) {
                        try {
                            const changedIds = JSON.parse(localStorage.getItem(k) || '[]');
                            count += changedIds.length;
                        } catch (e) { }
                    }
                });
                try {
                    const couponKey = `changedCouponStudents_${clsName}`;
                    const couponIds = JSON.parse(localStorage.getItem(couponKey) || '[]');
                    count += couponIds.length;
                } catch (e) { }

                grpClasses.forEach(c => {
                    allKeys.forEach(k => {
                        const prefix = `changedStudents_${c}_`;
                        if (k.startsWith(prefix)) {
                            try {
                                const changedIds = JSON.parse(localStorage.getItem(k) || '[]');
                                count += changedIds.length;
                            } catch (e) { }
                        }
                    });
                    try {
                        const couponKey = `changedCouponStudents_${c}`;
                        const couponIds = JSON.parse(localStorage.getItem(couponKey) || '[]');
                        count += couponIds.length;
                    } catch (e) { }
                });
            } else {
                allKeys.forEach(k => {
                    const prefix = `changedStudents_${clsName}_`;
                    if (k.startsWith(prefix)) {
                        try {
                            const changedIds = JSON.parse(localStorage.getItem(k) || '[]');
                            count += changedIds.length;
                        } catch (e) { }
                    }
                });
                try {
                    const couponKey = `changedCouponStudents_${clsName}`;
                    const couponIds = JSON.parse(localStorage.getItem(couponKey) || '[]');
                    count += couponIds.length;
                } catch (e) { }
            }
            return count;
        }

        function isUncleAssignedClass(className) {
            if (!className) return false;
            if (window.currentUncle && Array.isArray(window.currentUncle.classes)) {
                const assigned = window.currentUncle.classes.map(c => c.class_name || c.arabic_name || c);
                if (assigned.includes(className)) return true;
            }
            try {
                const cached = JSON.parse(localStorage.getItem('uncleAssignedClasses') || '[]');
                if (Array.isArray(cached) && cached.includes(className)) return true;
            } catch (e) { }
            return false;
        }

        function displayClasses() {
            const grid = document.getElementById('classesGrid');
            if (!grid) return;
            if (isDashboardDataLoading && (!students || !students.length)) {
                renderClassesSkeleton();
                return;
            }
            let list = classes;
            if (!list || !list.length) {
                const names = [...new Set(students.map(s => s['الفصل'] || 'بدون فصل'))];
                list = names.map((n, i) => ({ id: i + 1, code: n, arabic_name: n }));
            }
            // If church settings lock classes to assigned uncles, only show those classes
            try {
                const role = (window.currentUncle && window.currentUncle.role) || localStorage.getItem('uncleRole') || '';
                if (uncleClassNavPermission === 'own' && list && list.length && !['admin', 'developer'].includes(String(role).toLowerCase())) {
                    const assigned = (window.currentUncle && Array.isArray(window.currentUncle.classes))
                        ? window.currentUncle.classes.map(c => c.class_name || c.arabic_name || c)
                        : [];

                    // If we have assigned classes from currentUncle or cached storage, use them
                    if (assigned.length) {
                        list = list.filter(cls => assigned.includes(cls.arabic_name || cls.code));
                        _uncleAssignedClassesLoaded = true;
                    } else {
                        try {
                            const cached = JSON.parse(localStorage.getItem('uncleAssignedClasses') || '[]');
                            if (Array.isArray(cached) && cached.length) {
                                list = list.filter(cls => cached.includes(cls.arabic_name || cls.code));
                                _uncleAssignedClassesLoaded = true;
                            }
                        } catch (e) { }
                    }

                    // If still no assigned classes and we're online, fetch currentUncle to get assignments then re-run
                    if (!_uncleAssignedClassesLoaded && navigator.onLine) {
                        // Avoid recursive loops — mark as loading
                        _uncleAssignedClassesLoaded = true;
                        makeApiCall({ action: 'getCurrentUncle' }, r => {
                            if (r.uncle && Array.isArray(r.uncle.classes) && r.uncle.classes.length) {
                                window.currentUncle = r.uncle;
                                try { localStorage.setItem('uncleAssignedClasses', JSON.stringify(r.uncle.classes.map(c => c.class_name || c.arabic_name || c))); } catch (e) { }
                            }
                            // Re-run display after we've fetched assignments
                            displayClasses();
                        }, () => {
                            // Failed to fetch — proceed without filtering to avoid blocking UI
                        });
                        // Return now; displayClasses will be called again after fetch
                        return;
                    }
                }
            } catch (e) { }
            if (!list.length) {
                if (isDashboardDataLoading) {
                    renderClassesSkeleton();
                } else {
                    grid.innerHTML = '<div style="text-align:center;padding:2rem;color:var(--text-3)">لا توجد فصول</div>';
                }
                return;
            }

            // ── "View all together" card — only if view_mode includes 'all' ─
            const showAllCard = (churchViewMode === 'all' || churchViewMode === 'both');
            const showClassCards = (churchViewMode === 'classes' || churchViewMode === 'both' || !churchViewMode);

            const allLabel = window.IS_YOUTH ? 'كل الشباب' : 'كل الأطفال';
            const allIcon = window.IS_YOUTH ? 'fa-users' : 'fa-children';
            const allColor = window.IS_YOUTH ? '#8b5cf6' : '#4f46e5';
