            const guestsUnsavedHtml = guestsUnsaved > 0 ? `
                <div class="class-unsaved-badge" title="${guestsUnsaved} تغييرات غير محفوظة">
                    <i class="fas fa-save" style="font-size: .75rem;"></i> ${guestsUnsaved}
