            ` : '';
            let guestsCardHtml = '';
            if (guestsCount > 0 || guestsUnsaved > 0) {
                guestsCardHtml = `
                    <div class="class-card" onclick="showClassView('الزوار')" style="--cls-color:#f59e0b; border:2px solid #f59e0b; position:relative;">
