            const visibleCombined = showClassCards ? combinedHtml : '';
            const visibleRegular = showClassCards ? regularHtml : '';
            grid.innerHTML = allTogetherHtml + servantsCardHtml + visibleCombined + visibleRegular + guestsCardHtml;
