        // ── VIEW ALL TOGETHER ─────────────────────────────────────────
        // Shows every student across all classes in a single attendance list.
        // Each student still has their class recorded — this is purely a
        // display/attendance convenience mode; no data is changed.
        function showAllTogetherView() {
            combinedGroupLabel = '__ALL__';
            isCombinedView = true;
            combinedStudents = [...students];

            const label = window.IS_YOUTH ? 'كل الشباب' : 'كل الأطفال';

            document.getElementById('classesView').style.display = 'none';
            document.getElementById('classView').classList.add('active');
            document.getElementById('className').textContent = label;
            currentClass = '__ALL__';

            // Restore last selected date if any
            updateCurrentDateDisplay();

            // Show back button
            const backBtn = document.getElementById('backBtn');
            if (backBtn) backBtn.style.display = 'inline-flex';

            updateHash('all');

            loadAttendanceDataForCombinedAll();
            renderAttendanceList('__ALL__');
            updateClassStats();
            updateSaveBtns();
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        // Loads attendance for the virtual "all" combined view
        function loadAttendanceDataForCombinedAll() {
            const dateKey = currentFriday;
            combinedStudents.forEach(s => {
                const id = getStudentId(s);
                const srv = getServerAttendanceStatus(s, dateKey);
                originalAttendanceData[id] = srv;
                const localKey = `attendanceData_${s['الفصل']}_${dateKey}`;
                const local = JSON.parse(localStorage.getItem(localKey) || '{}');
                if (srv !== 'pending') { attendanceData[id] = srv; savedStudents.add(id); }
                else if (id in local) { attendanceData[id] = local[id]; if (local[id] !== 'pending') changedStudents.add(id); }
                else attendanceData[id] = 'pending';
            });
        }

        function escJs(str) {
            return (str || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '\\"');
        }
        function getClassIcon(name, cls) {
            // If the class object has a custom icon defined, use it
            if (cls && cls.icon) {
                if (/^\d+$/.test(cls.icon)) return `<span style="font-weight:900;font-size:1.4em">${cls.icon}</span>`;
                return `<i class="fas ${cls.icon}"></i>`;
            }
            // Fallback built-in map
            const icons = {
                'حضانة': '<i class="fas fa-baby"></i>',
                'أولى': '<span style="font-weight:900;font-size:1.3em">١</span>',
                'تانية': '<span style="font-weight:900;font-size:1.3em">٢</span>',
                'تالتة': '<span style="font-weight:900;font-size:1.3em">٣</span>',
                'رابعة': '<span style="font-weight:900;font-size:1.3em">٤</span>',
                'خامسة': '<span style="font-weight:900;font-size:1.3em">٥</span>',
                'سادسة': '<span style="font-weight:900;font-size:1.3em">٦</span>',
                'سابعة': '<span style="font-weight:900;font-size:1.3em">٧</span>',
                'ثامنة': '<span style="font-weight:900;font-size:1.3em">٨</span>',
            };
            return icons[name] || `<i class="fas fa-chalkboard-teacher"></i>`;
        }
        function updateDashboardStats() {
            const total = allStudentsData.length, cm = new Date().getMonth();
            const births = allStudentsData.filter(s => { if (!s['عيد الميلاد']) return false; const p = s['عيد الميلاد'].split('/'); return p.length >= 2 && parseInt(p[1]) - 1 === cm; }).length;
            const avgC = total > 0 ? Math.round(allStudentsData.reduce((a, s) => a + (parseInt(s['كوبونات']) || 0), 0) / total) : 0;
            const classNames = [...new Set(allStudentsData.map(s => s['الفصل']))];
            const se = id => document.getElementById(id);
            if (se('totalStudents')) se('totalStudents').textContent = total;
            if (se('totalClasses')) se('totalClasses').textContent = classNames.length;
            if (se('birthdaysThisMonth')) se('birthdaysThisMonth').textContent = births;
            if (se('averageCoupons')) se('averageCoupons').textContent = avgC;
        }

        let isFetchingTrips = false;
        function getTripsCacheKey() {
            const code = (localStorage.getItem('churchCode') || <?php echo json_encode($churchCode); ?> || '').trim();
            const id = <?php echo intval($_SESSION['church_id'] ?? 0); ?>;
            return code ? `lastTripsData_${code}` : (id ? `lastTripsData_id_${id}` : 'lastTripsData');
        }

        async function loadDashboardTrips() {
            const container = document.getElementById('tripsContainer');
            const head = document.getElementById('tripsSectionHead');
            if (!container || !head) return;

            const tripsCacheKey = getTripsCacheKey();
            try { localStorage.removeItem('lastTripsData'); } catch (e) { }

            // Load from cache first (scoped to this church only)
            const cachedTrips = localStorage.getItem(tripsCacheKey);
            if (cachedTrips) {
                try {
                    const trips = JSON.parse(cachedTrips);
                    renderDashboardTripsHtml(trips);
                } catch (e) { }
            }

            // Show skeleton if empty and no cache
            if (!container.innerHTML.trim()) {
                head.style.display = 'flex';
                container.style.display = 'flex';
                container.innerHTML = '<div class="trip-skeleton"></div><div class="trip-skeleton"></div><div class="trip-skeleton"></div>';
            }

            if (isFetchingTrips) return;
            isFetchingTrips = true;

            try {
                const fd = new FormData();
                fd.append('action', 'getTrips');
                const d = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(r => r.json());

                if (!d.success || !d.trips || !d.trips.length) {
                    try { localStorage.setItem(tripsCacheKey, '[]'); } catch (e) { }
                    container.innerHTML = '';
                    container.style.display = 'none';
                    head.style.display = 'none';
                    isFetchingTrips = false;
                    return;
                }

                const activeTrips = d.trips.filter(t => t.status === 'active' || t.status === 'planned');
                try { localStorage.setItem(tripsCacheKey, JSON.stringify(activeTrips)); } catch (e) { }
                if (!activeTrips.length) {
                    container.innerHTML = '';
                    container.style.display = 'none';
                    head.style.display = 'none';
                    isFetchingTrips = false;
                    return;
                }

                renderDashboardTripsHtml(activeTrips);
            } catch (e) {
                if (!localStorage.getItem(tripsCacheKey)) {
                    container.style.display = 'none';
                    head.style.display = 'none';
                }
            } finally {
                isFetchingTrips = false;
            }
        }

        function renderDashboardTripsHtml(activeTrips) {
            const container = document.getElementById('tripsContainer');
            const head = document.getElementById('tripsSectionHead');
            const icon = document.getElementById('tripsCollapseIcon');
            if (!container || !head) return;

            head.style.display = 'flex';

            // Restore collapsed state
            let tripsPref = localStorage.getItem('tripsCollapsed');
            if (tripsPref === null) {
                tripsPref = 'false'; // Open by default!
            }
            const isCollapsed = tripsPref === 'true';
            if (isCollapsed) {
                container.style.display = 'none';
                if (icon) icon.style.transform = 'rotate(-90deg)';
            } else {
                container.style.display = 'flex';
                if (icon) icon.style.transform = 'rotate(0deg)';
            }

            container.innerHTML = activeTrips.map(t => {
                const dateStr = t.start_date ? new Date(t.start_date).toLocaleDateString('ar-EG', { day: 'numeric', month: 'short' }) : 'قريباً';
                const img = t.image_url || '';
                const imgHtml = img ? `<img src="${img}" class="trip-slim-img" onerror="this.parentElement.innerHTML='<div class=\\'trip-slim-img\\' style=\\'display:flex;align-items:center;justify-content:center;background:var(--brand-bg);color:var(--brand);\\'><i class=\\'fas fa-map-marked-alt\\'></i></div>'">` : `<div class="trip-slim-img" style="display:flex;align-items:center;justify-content:center;background:var(--brand-bg);color:var(--brand);"><i class="fas fa-map-marked-alt"></i></div>`;
                const registeredCount = t.registered_count || 0;
                const kidsCountHtml = `<span class="trip-slim-kids-count"><i class="fas fa-users"></i> ${registeredCount} طفل</span>`;
                const tripBaseUrl = window.location.pathname.indexOf('/testing/') !== -1 ? '/testing/uncle/trip/' : '/uncle/trip/';
                return `
                    <a href="${tripBaseUrl}?trip_id=${t.id}" class="trip-slim-card">
                        ${imgHtml}
                        <div class="trip-slim-info">
                            <div class="trip-slim-name">${t.title}</div>
                            <div class="trip-slim-meta-row">
                                <div class="trip-slim-date"><i class="far fa-calendar-alt"></i> ${dateStr}</div>
                                ${kidsCountHtml}
                            </div>
                        </div>
                    </a>
                `;
            }).join('');
        }

        function toggleTripsCollapse() {
            const container = document.getElementById('tripsContainer');
            const icon = document.getElementById('tripsCollapseIcon');
            if (!container || !icon) return;
            const isCollapsed = container.style.display === 'none';
            if (isCollapsed) {
                container.style.display = 'flex';
                if (icon) icon.style.transform = 'rotate(0deg)';
                localStorage.setItem('tripsCollapsed', 'false');
            } else {
                container.style.display = 'none';
                if (icon) icon.style.transform = 'rotate(-90deg)';
                localStorage.setItem('tripsCollapsed', 'true');
            }
        }

        function toggleCustomSortDropdown(e) {
            e.stopPropagation();
            const menu = document.getElementById('customSortDropdownMenu');
            if (!menu) return;
            menu.style.display = ''; // Clear inline style if set
            const isVisible = menu.classList.contains('open');

            // Close standard dropdowns
            closeAllDropdowns();

            // Close other custom dropdowns
            document.querySelectorAll('.custom-dropdown-menu').forEach(m => m.classList.remove('open'));

            if (!isVisible) {
                menu.classList.add('open');
            } else {
                menu.classList.remove('open');
            }

            // Toggle icon rotate
            const btn = document.getElementById('customSortDropdownBtn');
            const icon = btn?.querySelector('.fa-chevron-down');
            if (icon) {
                icon.style.transform = !isVisible ? 'rotate(180deg)' : 'rotate(0deg)';
            }
        }

        function syncSortControls(value, label) {
            const select = document.getElementById('classSortSelect');
            if (select) select.value = value;

            const swipeSelect = document.getElementById('swipeSortSelect');
            if (swipeSelect) swipeSelect.value = value;

            const labelEl = document.getElementById('customSortDropdownLabel');
            if (labelEl && label) labelEl.innerText = label;

            const menu = document.getElementById('customSortDropdownMenu');
            if (menu) {
                menu.querySelectorAll('.custom-dropdown-item').forEach(item => {
                    item.classList.toggle('active', item.dataset.value === value);
                });
            }
        }

        function getSortLabel(value) {
            const item = document.querySelector(`#customSortDropdownMenu .custom-dropdown-item[data-value="${value}"]`);
            return item ? item.textContent.trim() : 'الاسم أ-ي';
        }

        function selectCustomSortOption(el, value, label) {
            const menu = document.getElementById('customSortDropdownMenu');
            if (menu) {
                menu.classList.remove('open');
            }
            syncSortControls(value, label);

            const btn = document.getElementById('customSortDropdownBtn');
            const icon = btn?.querySelector('.fa-chevron-down');
            if (icon) icon.style.transform = 'rotate(0deg)';

            const select = document.getElementById('classSortSelect');
            if (select) {
                select.value = value;
                select.dispatchEvent(new Event('change'));
            }
        }

        function changeSwipeSort(value) {
            classSortMode = value;
            syncSortControls(value, getSortLabel(value));
            if (_swipeList.length && document.getElementById('swipeOverlay')?.classList.contains('active')) {
                _sortSwipeRemaining();
            }
            renderAttendanceList(currentClass);
        }

        // Close dropdown when clicking outside
        document.addEventListener('click', (e) => {
            const menu = document.getElementById('customSortDropdownMenu');
            const btn = document.getElementById('customSortDropdownBtn');
            if (menu && !menu.contains(e.target) && btn && !btn.contains(e.target)) {
                menu.classList.remove('open');
                const icon = btn?.querySelector('.fa-chevron-down');
                if (icon) icon.style.transform = 'rotate(0deg)';
            }
        });

        // ── CLASS STATS ───────────────────────────────────────────────
        function updateClassStats() {
            if (isCombinedView) { updateCombinedClassStats(); return; }
            if (!currentClass) return;
            const cs = students.filter(s => s['الفصل'] === currentClass);
            let present = 0, absent = 0, totalC = 0;
            cs.forEach(s => {
                const id = getStudentId(s), st = attendanceData[id];
                if (st === 'present') present++;
                else if (st === 'absent') absent++;
                totalC += (parseInt(s['كوبونات']) || 0) + (parseInt(couponData[id]) || 0);
            });
            const avg = cs.length > 0 ? Math.round(totalC / cs.length) : 0;
            const se = id => document.getElementById(id);
            if (se('tbTotalVal')) se('tbTotalVal').textContent = cs.length;
            if (se('tbPresentVal')) se('tbPresentVal').textContent = present;
            if (se('tbAbsentVal')) se('tbAbsentVal').textContent = absent;
            if (se('tbCouponsVal')) se('tbCouponsVal').textContent = avg;
        }

        // ── ATTENDANCE DATA ───────────────────────────────────────────
        function getServerAttendanceStatus(student, date) {
            if (!student || !date) return 'pending';
            const check = v => { v = v?.toString().trim(); return v === 'ح' || v === 'حاضر' || v === 'present' ? 'present' : (v === 'غ' || v === 'غائب' || v === 'absent' ? 'absent' : null); };
            let r = check(student[date]); if (r) return r;
            if (student._allAttendance) { r = check(student._allAttendance[date]); if (r) return r; }
            return 'pending';
        }
        function loadAttendanceDataForClass(className, date = null) {
            if (!className) return;
            const dateKey = date || currentFriday;
            const localKey = `attendanceData_${className}_${dateKey}`;
            const chKey = `changedStudents_${className}_${dateKey}`;
            const local = JSON.parse(localStorage.getItem(localKey) || '{}');
            const savedChanged = localStorage.getItem(chKey);
            const cs = className === 'الخدام' ? (window.allUnclesData || []) : students.filter(s => s['الفصل'] === className);
            let restoredChanged = new Set();
            if (savedChanged) { try { const arr = JSON.parse(savedChanged); const ids = cs.map(s => getStudentId(s)); restoredChanged = new Set(arr.filter(id => ids.includes(id))); } catch (e) { } }
            changedStudents = restoredChanged;
            cs.forEach(s => {
                const id = getStudentId(s), srv = getServerAttendanceStatus(s, dateKey);
                originalAttendanceData[id] = srv;
                if (changedStudents.has(id) && id in local) {
                    if (srv !== 'pending' && local[id] === srv) {
                        changedStudents.delete(id);
                        attendanceData[id] = srv;
                        savedStudents.add(id);
                    } else {
                        attendanceData[id] = local[id];
                    }
                }
                else if (srv !== 'pending') { attendanceData[id] = srv; savedStudents.add(id); }
                else if (id in local) {
                    if (srv !== 'pending' && local[id] === srv) {
                        attendanceData[id] = srv;
                        savedStudents.add(id);
                    } else {
                        attendanceData[id] = local[id];
                        if (local[id] !== 'pending') changedStudents.add(id);
                    }
                }
                else attendanceData[id] = 'pending';
            });
            saveChangedStudentsToLocalStorage(className, dateKey);
        }
        function saveAttendanceDataForClass(className, date = null) {
            if (!className) return;
            const dateKey = date || currentFriday;
            let cs = [];
            if (className === '__ALL__') {
                cs = students;
            } else if (className === 'الخدام') {
                cs = window.allUnclesData || [];
            } else {
                const grp = (typeof combinedClassGroups !== 'undefined' && combinedClassGroups)
                    ? combinedClassGroups.find(g => g.label === className)
                    : null;
                if (grp) {
                    cs = students.filter(s => grp.classes.includes(s['الفصل']));
                } else {
                    cs = students.filter(s => s['الفصل'] === className);
                }
            }
            const data = {};
            cs.forEach(s => {
                const id = getStudentId(s), cur = attendanceData[id] || 'pending';
                if (changedStudents.has(id)) data[id] = cur;
                else if (cur !== 'pending') data[id] = cur;
            });
            localStorage.setItem(`attendanceData_${className}_${dateKey}`, JSON.stringify(data));
        }
        function saveChangedStudentsToLocalStorage(className, date = null) {
            if (!className) return;
            localStorage.setItem(`changedStudents_${className}_${date || currentFriday}`, JSON.stringify([...changedStudents]));
        }
        function getCouponValueIdx(studentId) {
            const idx = couponValueIdxByStudent[studentId];
            const defaultIdx = couponPresetValues.indexOf(50) !== -1 ? couponPresetValues.indexOf(50) : Math.min(2, couponPresetValues.length - 1);
            return Number.isInteger(idx) && idx >= 0 && idx < couponPresetValues.length ? idx : Math.max(0, defaultIdx);
        }
        function getCouponValueForStudent(studentId) {
            const idx = getCouponValueIdx(studentId);
            return couponPresetValues[idx] || (couponPresetValues[0] || 50);
        }
        function setCouponValueDisplay(studentId, animate = false) {
            const el = document.getElementById(`cv-${studentId}`);
            if (!el) return;
            const idx = getCouponValueIdx(studentId);
            el.textContent = couponPresetValues[idx] || 50;
            el.setAttribute('data-idx', String(idx));
            if (animate) {
                el.classList.remove('coupon-toggle-pop');
                void el.offsetWidth;
                el.classList.add('coupon-toggle-pop');
                window.setTimeout(() => el.classList.remove('coupon-toggle-pop'), 320);
            }
        }
        function loadCouponDataForClass(className) {
            couponData = JSON.parse(localStorage.getItem(`couponData_${className}`) || '{}');
            const sc = localStorage.getItem(`savedCoupons_${className}`);
            savedCouponStudents = sc ? new Set(JSON.parse(sc)) : new Set();
            const chk = localStorage.getItem(`changedCouponStudents_${className}`);
            changedCouponStudents = chk ? new Set(JSON.parse(chk)) : new Set();
            try {
                couponValueIdxByStudent = JSON.parse(localStorage.getItem(`couponValueIdx_${className}`) || '{}') || {};
            } catch (e) {
                couponValueIdxByStudent = {};
            }
            const cs = className === 'الخدام' ? (window.allUnclesData || []) : students.filter(s => s['الفصل'] === className);
            cs.forEach(s => { const id = getStudentId(s); originalCouponData[id] = parseInt(s['كوبونات الالتزام'] || 0); });
        }
        function saveCouponDataForClass(className) {
            if (!className) return;
            localStorage.setItem(`couponData_${className}`, JSON.stringify(couponData || {}));
            localStorage.setItem(`changedCouponStudents_${className}`, JSON.stringify([...changedCouponStudents]));
            localStorage.setItem(`couponValueIdx_${className}`, JSON.stringify(couponValueIdxByStudent || {}));
        }

        // ── SWIPE TO CLOSE ────────────────────────────────────────────
        function initSwipeToClose(overlay) {
            if (overlay.id === 'kidQrScannerModal') return;
            const modal = overlay.querySelector('.modal');
            if (!modal) return;

            let startY = 0;
            let startX = 0;
            let swipeStartY = 0;
            let lastY = 0;
            let lastTime = 0;
            let velocityY = 0;
            let isDragging = false;
            let isSwipingDown = false;
            let initialScrollTop = 0;
            let startedOnHeader = false;

            const onStart = e => {
                const target = e.target;
                if (target && target.closest && (
                    target.closest('.table-zoom-wrap') ||
                    target.closest('.table-container') ||
                    target.closest('.sheet-container')
                )) {
                    isDragging = false;
                    return;
                }

                const t = e.touches ? e.touches[0] : e;
                startY = t.clientY;
                startX = t.clientX;
                swipeStartY = startY;
                lastY = startY;
                lastTime = Date.now();
                isDragging = true;
                isSwipingDown = false;
                velocityY = 0;
                initialScrollTop = modal.scrollTop;
                startedOnHeader = !!(target.closest('.modal-header') || target.closest('.modal-head'));

                modal.style.transition = 'none';
                overlay.style.transition = 'none';
            };

            const onMove = e => {
                if (!isDragging) return;

                const t = e.touches ? e.touches[0] : e;
                const now = Date.now();
                const dt = now - lastTime;

                if (dt > 0) {
                    velocityY = (t.clientY - lastY) / dt;
                }
                lastY = t.clientY;
                lastTime = now;

                if (!isSwipingDown) {
                    const isAtTop = modal.scrollTop <= 0;
                    const dyTotal = t.clientY - startY;
                    const dxTotal = t.clientX - startX;

                    if (dyTotal > 10 && Math.abs(dyTotal) > Math.abs(dxTotal)) {
                        if (startedOnHeader || (initialScrollTop <= 0 && isAtTop)) {
                            isSwipingDown = true;
                            swipeStartY = startY;
                        }
                    }
                }

                if (isSwipingDown) {
                    if (e.cancelable) e.preventDefault();
                    const translateY = Math.max(0, t.clientY - swipeStartY);
                    modal.style.transform = `translateY(${translateY}px)`;

                    const progress = translateY / modal.offsetHeight;
                    const opacity = Math.max(0, 0.45 * (1 - progress));
                    overlay.style.background = `rgba(0,0,0,${opacity})`;
                    overlay.style.backdropFilter = `blur(${Math.max(0, 6 * (1 - progress))}px)`;
                }
            };

            const onEnd = () => {
                if (!isDragging) return;
                isDragging = false;

                modal.style.transition = '';
                overlay.style.transition = '';

                if (isSwipingDown) {
                    const dy = lastY - swipeStartY;
                    const modalHeight = modal.offsetHeight;
                    const threshold = modalHeight * 0.22;
                    const isFastSwipe = velocityY > 0.6;

                    if (dy > threshold || isFastSwipe) {
                        modal.style.transition = 'transform 0.28s cubic-bezier(0.16, 1, 0.3, 1), opacity 0.25s ease';
                        overlay.style.transition = 'background-color 0.28s ease, backdrop-filter 0.28s ease';
                        modal.style.transform = 'translateY(100%)';
                        modal.style.opacity = '0';
                        overlay.style.background = 'rgba(0,0,0,0)';
                        overlay.style.backdropFilter = 'blur(0px)';

                        setTimeout(() => {
                            overlay.classList.remove('active');
                            modal.style.transform = '';
                            modal.style.opacity = '';
                            modal.style.transition = '';
                            overlay.style.background = '';
                            overlay.style.backdropFilter = '';
                            overlay.style.transition = '';
                            startAutoRefresh();

                            if (overlay.id === 'studentModal') currentStudentForEdit = null;
                            if (overlay.id === 'accountModal') hideAccountEditForm();
                        }, 280);
                    } else {
                        modal.style.transition = 'transform 0.3s cubic-bezier(0.16, 1, 0.3, 1)';
                        overlay.style.transition = 'background-color 0.3s ease, backdrop-filter 0.3s ease';
                        modal.style.transform = '';
                        overlay.style.background = '';
                        overlay.style.backdropFilter = '';

                        setTimeout(() => {
                            modal.style.transition = '';
                            overlay.style.transition = '';
                        }, 300);
                    }
                }

                isSwipingDown = false;
            };

            overlay.addEventListener('touchstart', onStart, { passive: true });
            overlay.addEventListener('touchmove', onMove, { passive: false });
            overlay.addEventListener('touchend', onEnd);
            overlay.addEventListener('touchcancel', onEnd);
        }

        // ── RENDER ATTENDANCE ─────────────────────────────────────────
        function renderAttendanceList(className) {
            if (isCombinedView) { renderCombinedAttendanceList(); return; }
            const list = document.getElementById('attendanceList'); if (!list) return;
            if (isBulkSelectMode) list.classList.add('bulk-active');
            else list.classList.remove('bulk-active');
            let cs = filterAndSortActiveStudents();
            updateKidsCountDisplay(cs.length);
            if (searchQuery && !cs.length) {
                list.innerHTML = `<div style="text-align:center;padding:2rem;grid-column:1/-1"><i class="fas fa-search" style="font-size:2rem;color:var(--text-3);margin-bottom:1rem;display:block"></i><p style="color:var(--text-3)">لا نتائج لـ "${searchQuery}"</p><button class="btn btn-sm btn-ghost" onclick="clearSearch()" style="margin-top:10px"><i class="fas fa-times"></i> عرض الكل</button></div>`;
                updateSearchResultsInfo(0); return;
            }
            if (!cs.length) {
                const emptyMsg = (currentClass === 'الخدام') ? 'لا يوجد خدام في هذا الفصل' : 'لا يوجد أطفال في هذا الفصل';
                list.innerHTML = `<div style="text-align:center;padding:2rem;grid-column:1/-1;color:var(--text-3)">${emptyMsg}</div>`;
                return;
            }

            list.innerHTML = cs.map(s => {
                const id = getStudentId(s), st = attendanceData[id] || 'pending';
                const srv = getServerAttendanceStatus(s, currentFriday);
                const isInChanged = changedStudents.has(id), isCouponChanged = changedCouponStudents.has(id);
                const isSynced = srv !== 'pending' && st === srv && !isInChanged;

                const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
                const offAttList = JSON.parse(localStorage.getItem(`offlineSavedAttendance_${cls}_${currentFriday}`) || '[]');
                const offCoupList = JSON.parse(localStorage.getItem(`offlineSavedCoupons_${cls}`) || '[]');
                const accKey = `offlineAccumulatedCoupons_${cls}`;
                const acc = JSON.parse(localStorage.getItem(accKey) || '{}');
                const offlineC = parseInt(acc[id] || 0);

                const isOfflineAttSaved = offAttList.includes(id);
                const isOfflineCoupSaved = offCoupList.includes(id);

                const baseC = parseInt(s['كوبونات'] || 0), addC = parseInt(couponData[id] || 0), totC = baseC + addC + offlineC;

                // Birthday today check
                const _now = new Date();
                const _bdParts = (s['عيد الميلاد'] || '').split('/');
                const isBdayToday = _bdParts.length >= 2 && parseInt(_bdParts[0]) === _now.getDate() && parseInt(_bdParts[1]) - 1 === _now.getMonth();

                let badges = '';
                if (isBdayToday) badges += '<span class="bday-row-badge"><i class="fas fa-birthday-cake"></i> عيد ميلاد سعيد! 🎂</span>';
                if (isOfflineAttSaved) {
                    badges += '<span class="status-badge offline-saved"><i class="fas fa-cloud-upload-alt"></i> محفوظ أوفلاين</span>';
                } else if (st === 'pending' && !isInChanged) {
                    badges += '<span class="status-badge pending"><i class="fas fa-minus"></i> لا بيانات</span>';
                } else if (st === 'pending' && isInChanged) {
                    badges += '<span class="status-badge local"><i class="fas fa-times-circle"></i> مسح — محلياً</span>';
                } else if (isSynced) {
                    badges += '<span class="status-badge saved"><i class="fas fa-check"></i> محفوظ</span>';
                } else if (isInChanged) {
                    badges += '<span class="status-badge local-unsaved"><i class="fas fa-clock"></i> محفوظ محلياً</span>';
                }

                if (isOfflineCoupSaved) {
                    badges += `<span class="status-badge offline-coupon"><i class="fas fa-star"></i> أوفلاين ${offlineC >= 0 ? '+' : ''}${offlineC}</span>`;
                }
                if (isCouponChanged) {
                    badges += `<span class="status-badge coupon-unsaved"><i class="fas fa-star"></i> ${addC >= 0 ? '+' : ''}${addC}</span>`;
                }

                const isKhodam = (className === 'الخدام');
                const inlineCoupons = isKhodam ? '' : `<span class="student-coupons-inline"><i class="fas fa-star" style="font-size:.7rem"></i> ${totC}${addC > 0 ? `<small style="opacity:.65;font-size:.7em"> +${addC}</small>` : (addC < 0 ? `<small style="opacity:.65;font-size:.7em"> ${addC}</small>` : '')}${offlineC > 0 ? `<small style="opacity:.8;font-size:.7em;color:#0ea5e9"> +${offlineC}</small>` : ''}</span>`;

                const gender = (s['النوع'] === 'female' || s['gender'] === 'female') ? 'female' : 'male';
                let name = s['الاسم'] || '---';
                if (searchQuery) name = name.replace(new RegExp(`(${searchQuery})`, 'gi'), '<mark style="background:#fde047;border-radius:3px;padding:0 2px;color:#000">$1</mark>');
                if (s._isGuest) {
                    name += ' <span class="guest-badge" style="font-size:0.65rem; background:#f59e0b; color:#fff; padding:2px 6px; border-radius:4px; margin-right:4px; vertical-align:middle; display:inline-block;">زائر</span>';
                }
                const safeImg = (s['صورة'] || '').replace(/'/g, "\\'");
                const safeName = (s['الاسم'] || '').replace(/'/g, "\\'");
                const img = s['صورة']
                    ? `<img src="${window.photoUrl(s['صورة'])}" alt="" class="student-avatar ${gender}" onclick="showImageModal('${safeImg}',event)" onerror="this.style.display='none';var n=this.nextElementSibling;if(n)n.style.display='flex'">`
                    : '';
                const fallback = `<div class="student-avatar ${gender}" ${s['صورة'] ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;
                const localClass = (isInChanged || isCouponChanged || isOfflineAttSaved || isOfflineCoupSaved) ? ' has-local' : '';
                const bdayClass = isBdayToday ? ' bday-row' : '';
                const dbId = Number(getStudentDbId(s));
                const isSelected = selectedStudentIds.has(dbId);
                const selectClass = isSelected ? ' selected' : '';
                return `<div class="attendance-item ${st}${localClass}${bdayClass}${selectClass}" id="ai-${id}" data-db-id="${dbId}"
            ontouchstart="${isKhodam ? '' : `_holdStart(event,'${safeName}')`}"
            ontouchmove="${isKhodam ? '' : '_holdMove(event)'}"
            ontouchend="${isKhodam ? '' : '_holdEnd()'}"
            ontouchcancel="${isKhodam ? '' : '_holdEnd()'}"
            oncontextmenu="${isKhodam ? 'event.preventDefault()' : `_rowContextMenu(event,'${safeName}')`}">
            <div class="student-info" onclick="isBulkSelectMode ? toggleStudentSelection(event, ${dbId}) : showStudentDetails('${safeName}')" style="cursor:pointer">
                <div class="bulk-check-wrap">
                    <div class="bulk-check-circle ${isSelected ? 'checked' : ''}"><i class="fas fa-check"></i></div>
                </div>
                ${img}${fallback}
                <div>
                    <div class="student-name profile-link">${name}</div>
                    <div class="status-indicator">${badges}${inlineCoupons}</div>
                </div>
            </div>
            <div class="attendance-actions">
                ${isKhodam ? '' : `
                <span class="student-coupons"><i class="fas fa-star" style="font-size:.7rem"></i> ${totC}${addC > 0 ? `<small style="opacity:.65;font-size:.7em"> +${addC}</small>` : (addC < 0 ? `<small style="opacity:.65;font-size:.7em"> ${addC}</small>` : '')}${offlineC > 0 ? `<small style="opacity:.8;font-size:.7em;color:#0ea5e9"> +${offlineC}</small>` : ''}</span>
                <div class="coupon-toggle-row">
                    <button class="coupon-toggle-btn minus" onclick="adjustStudentCoupons('${id}',-1)"><i class="fas fa-minus"></i></button>
                    <div class="coupon-value-display" id="cv-${id}" data-idx="${getCouponValueIdx(id)}" onclick="toggleCouponValue('${id}')">${getCouponValueForStudent(id)}</div>
                    <button class="coupon-toggle-btn plus" onclick="adjustStudentCoupons('${id}',1)"><i class="fas fa-plus"></i></button>
                </div>
                `}
                <div class="attend-btn-row">
                    <button class="present-btn" onclick="markStudentAttendance('${id}','present')"><i class="fas fa-check"></i> حضور</button>
                    <button class="absent-btn" onclick="markStudentAttendance('${id}','absent')"><i class="fas fa-times"></i> غياب</button>
                </div>
            </div>
        </div>`;
            }).join('');
            updateSearchResultsInfo(cs.length);
            updateClassStats();
            setTimeout(updateSaveBtns, 50);
            // Animate only items that are already in the viewport — no waiting for off-screen ones
            _animateVisibleCards(list);
        }

        // ── ATTENDANCE ACTIONS ────────────────────────────────────────
        function markStudentAttendance(studentId, status, force = false) {
            const cur = attendanceData[studentId] || 'pending';
            const srv = originalAttendanceData[studentId] || 'pending';

            if (cur === status && !force) {
                attendanceData[studentId] = 'pending';
                if (srv === 'pending') changedStudents.delete(studentId);
                else changedStudents.add(studentId);
            } else {
                attendanceData[studentId] = status;
                if (status === srv) changedStudents.delete(studentId);
                else changedStudents.add(studentId);
            }
            saveAttendanceDataForClass(currentClass); saveChangedStudentsToLocalStorage(currentClass);
            // Update only the affected row — no full list re-render (avoids blink)
            _updateAttendanceRow(studentId);
            updateClassStats(); updateSaveBtns();
        }

        function executeBulkCouponsDirect(amount) {
            if (selectedStudentIds.size === 0) {
                showToast('الرجاء تحديد أطفال أولاً', 'warning');
                return;
            }

            showLoading('جاري حفظ الكوبونات...');
            makeApiCall({
                action: 'bulkUpdateStudentsCoupons',
                student_ids: Array.from(selectedStudentIds).join(','),
                change_amount: amount,
                reason: 'تعديل جماعي'
            }, d => {
                showToast(d.message || 'تم تعديل الكوبونات بنجاح', 'success');
                selectedStudentIds.clear();
                updateBulkUI();
                loadData();
            }, err => {
                showToast(err || 'فشل التعديل', 'error');
            });
        }

        function _updateAttendanceRow(studentId) {
            const row = document.getElementById('ai-' + studentId);
            if (!row) { renderAttendanceList(currentClass); return; }

            const st = attendanceData[studentId] || 'pending';
            const isInChanged = changedStudents.has(studentId);
            const isCouponChanged = changedCouponStudents.has(studentId);

            const allList = isCombinedView ? combinedStudents : students;
            const s = allList.find(x => getStudentId(x) === studentId);
            const srv = s ? getServerAttendanceStatus(s, currentFriday) : 'pending';
            const isSynced = srv !== 'pending' && st === srv && !isInChanged;

            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
            const offAttList = JSON.parse(localStorage.getItem(`offlineSavedAttendance_${cls}_${currentFriday}`) || '[]');
            const offCoupList = JSON.parse(localStorage.getItem(`offlineSavedCoupons_${cls}`) || '[]');
            const accKey = `offlineAccumulatedCoupons_${cls}`;
            const acc = JSON.parse(localStorage.getItem(accKey) || '{}');
            const offlineC = parseInt(acc[studentId] || 0);

            const isOfflineAttSaved = offAttList.includes(studentId);
            const isOfflineCoupSaved = offCoupList.includes(studentId);

            // Birthday today
            const _now = new Date();
            const _bdParts = (s ? (s['عيد الميلاد'] || '') : '').split('/');
            const isBdayToday = _bdParts.length >= 2 && parseInt(_bdParts[0]) === _now.getDate() && parseInt(_bdParts[1]) - 1 === _now.getMonth();

            // Update row class
            let rowCls = 'attendance-item ' + st;
            if (isInChanged || isCouponChanged || isOfflineAttSaved || isOfflineCoupSaved) rowCls += ' has-local';
            if (isBdayToday) rowCls += ' bday-row';
            const dbId = s ? Number(getStudentDbId(s)) : null;
            if (dbId && selectedStudentIds.has(dbId)) rowCls += ' selected';
            row.className = rowCls;

            // Update badges
            let badges = '';
            if (isBdayToday) badges += '<span class="bday-row-badge"><i class="fas fa-birthday-cake"></i> عيد ميلاد سعيد! 🎂</span>';
            if (isOfflineAttSaved) {
                badges += '<span class="status-badge offline-saved"><i class="fas fa-cloud-upload-alt"></i> محفوظ أوفلاين</span>';
            } else if (st === 'pending' && !isInChanged) {
                badges += '<span class="status-badge pending"><i class="fas fa-minus"></i> لا بيانات</span>';
            } else if (st === 'pending' && isInChanged) {
                badges += '<span class="status-badge local"><i class="fas fa-times-circle"></i> مسح — محلياً</span>';
            } else if (isSynced) {
                badges += '<span class="status-badge saved"><i class="fas fa-check"></i> محفوظ</span>';
            } else if (isInChanged) {
                badges += '<span class="status-badge local-unsaved"><i class="fas fa-clock"></i> محفوظ محلياً</span>';
            }
            const addC = parseInt(couponData[studentId] || 0);
            if (isOfflineCoupSaved) {
                badges += `<span class="status-badge offline-coupon"><i class="fas fa-star"></i> أوفلاين ${offlineC >= 0 ? '+' : ''}${offlineC}</span>`;
            }
            if (isCouponChanged) {
                badges += `<span class="status-badge coupon-unsaved"><i class="fas fa-star"></i> ${addC >= 0 ? '+' : ''}${addC}</span>`;
            }

            const baseC = parseInt(s ? s['كوبونات'] || 0 : 0);
            const totC = baseC + addC + offlineC;
            const inlineCoupons = `<span class="student-coupons-inline"><i class="fas fa-star" style="font-size:.7rem"></i> ${totC}${addC > 0 ? `<small style="opacity:.65;font-size:.7em"> +${addC}</small>` : (addC < 0 ? `<small style="opacity:.65;font-size:.7em"> ${addC}</small>` : '')}${offlineC > 0 ? `<small style="opacity:.8;font-size:.7em;color:#0ea5e9"> +${offlineC}</small>` : ''}</span>`;

            const indicator = row.querySelector('.status-indicator');
            if (indicator) indicator.innerHTML = badges + inlineCoupons;

            // Update coupons display in-place
            const couponsEl = row.querySelector('.student-coupons');
            if (couponsEl) {
                couponsEl.innerHTML = `<i class="fas fa-star" style="font-size:.7rem"></i> ${totC}${addC > 0 ? `<small style="opacity:.65;font-size:.7em"> +${addC}</small>` : (addC < 0 ? `<small style="opacity:.65;font-size:.7em"> ${addC}</small>` : '')}${offlineC > 0 ? `<small style="opacity:.8;font-size:.7em;color:#0ea5e9"> +${offlineC}</small>` : ''}`;
            }

            // Update bulk checkbox checked state
            const isSelected = dbId ? selectedStudentIds.has(dbId) : false;
            const checkCircle = row.querySelector('.bulk-check-circle');
            if (checkCircle) {
                if (isSelected) {
                    checkCircle.classList.add('checked');
                    row.classList.add('selected');
                } else {
                    checkCircle.classList.remove('checked');
                    row.classList.remove('selected');
                }
            }
        }
        function markAllPresent() {
            const list = isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass);
            list.forEach(s => markStudentAttendance(getStudentId(s), 'present'));
        }
        function markAllAbsent() {
            const list = isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass);
            list.forEach(s => markStudentAttendance(getStudentId(s), 'absent'));
        }

        // ── COUPON TOGGLE ─────────────────────────────────────────────
        function toggleCouponValue(id) {
            const currentIdx = getCouponValueIdx(id);
            const newIdx = (currentIdx + 1) % couponPresetValues.length;
            // Toggle ALL students to the same value, but only animate the clicked one
            const list = getActiveViewStudents();
            list.forEach(s => {
                const sid = getStudentId(s);
                couponValueIdxByStudent[sid] = newIdx;
                setCouponValueDisplay(sid, sid === id);
            });
            saveCouponDataForClass(currentClass);
        }
        function adjustStudentCoupons(studentId, dir) {
            const val = getCouponValueForStudent(studentId);
            const cur = parseInt(couponData[studentId] || 0);
            couponData[studentId] = cur + dir * val;
            if (couponData[studentId] !== 0) { changedCouponStudents.add(studentId); savedCouponStudents.delete(studentId); } else changedCouponStudents.delete(studentId);
            saveCouponDataForClass(currentClass);
            _updateAttendanceRow(studentId);
            updateClassStats(); updateSaveBtns();
            animateCouponDelta(studentId, dir * val);
        }
        function addCouponsToAll(amount) {
            const list = students.filter(s => s['الفصل'] === currentClass);
            list.forEach(s => {
                const id = getStudentId(s);
                couponData[id] = (couponData[id] || 0) + amount;
                changedCouponStudents.add(id);
                savedCouponStudents.delete(id);
                _updateAttendanceRow(id);
                animateCouponDelta(id, amount);
            });
            saveCouponDataForClass(currentClass); updateClassStats(); updateSaveBtns();
        }
        function resetCouponDataForClass(className) {
            couponData = {}; changedCouponStudents.clear(); savedCouponStudents.clear();
            couponValueIdxByStudent = {};
            localStorage.removeItem(`couponData_${className}`); localStorage.removeItem(`changedCouponStudents_${className}`); localStorage.removeItem(`savedCoupons_${className}`);
            localStorage.removeItem(`couponValueIdx_${className}`);
            renderAttendanceList(currentClass); updateClassStats(); updateSaveBtns();
        }

        let isBulkSelectMode = false;
        let isMergeChoosingMode = false;
        const selectedStudentIds = new Set();

        function openModal(id) {
            const m = document.getElementById(id);
            if (m) {
                m.classList.add('active');
                stopAutoRefresh();
            }
        }

        function closeModal(id) {
            const m = document.getElementById(id);
            if (m) {
                m.classList.remove('active');
                startAutoRefresh();
            }
        }

        function toggleBulkSelectMode() {
            const list = document.getElementById('attendanceList');
            let topBefore = 0;
            if (list) {
                topBefore = list.getBoundingClientRect().top;
            }

            isBulkSelectMode = !isBulkSelectMode;
            const toggleBtn = document.getElementById('bulkSelectToggleBtn');
            const actionsBar = document.getElementById('bulkActionsBar');

            if (isBulkSelectMode) {
                document.body.classList.add('bulk-active');
                if (toggleBtn) {
                    toggleBtn.classList.add('active');
                    toggleBtn.innerHTML = '<i class="fas fa-times"></i><span class="save-btn-bottom"><span class="save-btn-label">إلغاء</span></span>';
                }
                if (actionsBar) {
                    actionsBar.style.display = 'flex';
                    actionsBar.classList.add('show');
                }
                if (list) {
                    list.classList.add('bulk-active');
                }
                // Run synchronously to calculate and apply offset instantly
                updateBulkBarHeight();
            } else {
                document.body.classList.remove('bulk-active');
                if (toggleBtn) {
                    toggleBtn.classList.remove('active');
                    toggleBtn.innerHTML = '<i class="fas fa-check-circle"></i><span class="save-btn-bottom"><span class="save-btn-label">تحديد</span></span>';
                }
                if (actionsBar) {
                    actionsBar.style.display = 'none';
                    actionsBar.classList.remove('show');
                }
                if (list) {
                    list.classList.remove('bulk-active');
                    // In-place clear of selected classes on cards
                    list.querySelectorAll('.attendance-item.selected').forEach(item => {
                        item.classList.remove('selected');
                        const cc = item.querySelector('.bulk-check-circle');
                        if (cc) cc.classList.remove('checked');
                    });
                }
                selectedStudentIds.clear();
                isMergeChoosingMode = false;
                updateBulkUI();
            }

            // Correct scroll offset if a shift occurred
            if (list) {
                const topAfter = list.getBoundingClientRect().top;
                const diff = topAfter - topBefore;
                if (diff !== 0) {
                    window.scrollBy(0, diff);
                }
            }
        }

        function updateBulkBarHeight() {
            const bar = document.getElementById('bulkActionsBar');
            if (bar && isBulkSelectMode) {
                const height = bar.offsetHeight;
                document.documentElement.style.setProperty('--bulk-bar-height', height + 'px');
                document.documentElement.style.setProperty('--bulk-active-padding', height + 'px');
            }
        }
        window.addEventListener('resize', updateBulkBarHeight);

        function disableBulkSelectMode() {
            if (isBulkSelectMode) {
                toggleBulkSelectMode();
            }
        }

        function toggleStudentSelection(event, dbId) {
            if (event) {
                event.preventDefault();
                event.stopPropagation();
            }
            const numId = Number(dbId);
            if (selectedStudentIds.has(numId)) {
                selectedStudentIds.delete(numId);
            } else {
                if (isMergeChoosingMode && selectedStudentIds.size >= 2) {
                    showToast('يمكنك تحديد طفلين فقط في وضع الدمج', 'warning');
                    return;
                }
                selectedStudentIds.add(numId);
            }

            // Find student node and update row class/checkbox in-place
            const allList = isCombinedView ? combinedStudents : students;
            const s = allList.find(x => Number(getStudentDbId(x)) === numId);
            if (s) {
                const sid = getStudentId(s);
                _updateAttendanceRow(sid);
            }

            updateBulkUI();

            if (isMergeChoosingMode && selectedStudentIds.size === 2) {
                isMergeChoosingMode = false;
                triggerBulkMerge();
            }
        }

        function toggleSelectAllBulk(event) {
            if (event) {
                event.preventDefault();
                event.stopPropagation();
            }
            isMergeChoosingMode = false;
            const displayed = filterAndSortActiveStudents();
            if (!displayed.length) return;

            const isAllSel = displayed.every(s => selectedStudentIds.has(Number(getStudentDbId(s))));

            displayed.forEach(s => {
                const dbId = Number(getStudentDbId(s));
                if (isAllSel) {
                    selectedStudentIds.delete(dbId);
                } else {
                    selectedStudentIds.add(dbId);
                }
                _updateAttendanceRow(getStudentId(s));
            });

            updateBulkUI();
        }

        function bulkSelectByFilter(filter) {
            isMergeChoosingMode = false;
            const displayed = filterAndSortActiveStudents();
            if (!displayed.length) return;

            // Clear current selections first
            selectedStudentIds.clear();

            displayed.forEach(s => {
                const dbId = Number(getStudentDbId(s));
                const sid = getStudentId(s);
                const st = attendanceData[sid] || 'pending';
                const gender = (s && (s['النوع'] === 'female' || s['gender'] === 'female')) ? 'female' : 'male';

                let select = false;
                if (filter === 'all') {
                    select = true;
                } else if (filter === 'pending' && st === 'pending') {
                    select = true;
                } else if (filter === 'present' && st === 'present') {
                    select = true;
                } else if (filter === 'absent' && st === 'absent') {
                    select = true;
                } else if (filter === 'boys' && gender === 'male') {
                    select = true;
                } else if (filter === 'girls' && gender === 'female') {
                    select = true;
                }

                if (select) {
                    selectedStudentIds.add(dbId);
                }
                _updateAttendanceRow(sid);
            });

            updateBulkUI();
        }

        function bulkMarkAttendance(status) {
            if (selectedStudentIds.size === 0) {
                const warnMsg = (currentClass === 'الخدام') ? 'الرجاء تحديد خدام أولاً' : 'الرجاء تحديد أطفال أولاً';
                showToast(warnMsg, 'warning');
                return;
            }

            // Iterate and mark attendance locally for all selected
            const allList = (currentClass === 'الخدام')
                ? (window.allUnclesData || [])
                : (isCombinedView ? combinedStudents : students);
            selectedStudentIds.forEach(dbId => {
                const s = allList.find(x => getStudentDbId(x) === dbId);
                if (s) {
                    const sid = getStudentId(s);
                    markStudentAttendance(sid, status, true);
                }
            });

            selectedStudentIds.clear();
            updateBulkUI();
            renderAttendanceList(currentClass);
        }

        function updateBulkUI() {
            const countEl = document.getElementById('bulkSelectedCount');
            if (countEl) {
                countEl.textContent = selectedStudentIds.size;
            }
            const mergeBtn = document.getElementById('bulkMergeBtn');
            if (mergeBtn) {
                if (selectedStudentIds.size === 2) {
                    mergeBtn.style.display = 'inline-flex';
                } else {
                    mergeBtn.style.display = 'none';
                }
            }
            updateSelectAllHeaderCheckbox();
        }

        function updateSelectAllHeaderCheckbox() {
            const displayed = filterAndSortActiveStudents();
            const barCircle = document.getElementById('bulkBarSelectAllCircle');

            const isAllSel = displayed.length && displayed.every(s => selectedStudentIds.has(Number(getStudentDbId(s))));

            if (barCircle) {
                if (isAllSel) {
                    barCircle.classList.add('checked');
                } else {
                    barCircle.classList.remove('checked');
                }
            }
        }

        let customConfirmCallback = null;
        function showCustomConfirm(options) {
            const title = options.title || 'تأكيد الإجراء';
            const message = options.message || '';
            const iconHtml = options.icon || '<i class="fas fa-exclamation-triangle"></i>';
            const btnText = options.btnText || 'تأكيد';
            const btnClass = options.btnClass || 'btn-primary';
            customConfirmCallback = options.onConfirm || null;

            const titleEl = document.getElementById('customConfirmTitle');
            const msgEl = document.getElementById('customConfirmMessage');
            const iconEl = document.getElementById('customConfirmIcon');
            const yesBtn = document.getElementById('customConfirmYesBtn');

            if (titleEl) titleEl.textContent = title;
            if (msgEl) msgEl.textContent = message;
            if (iconEl) {
                iconEl.innerHTML = iconHtml;
                iconEl.style.color = options.iconColor || 'var(--danger)';
            }
            if (yesBtn) {
                yesBtn.innerHTML = '';
                if (options.btnIconClass) {
                    yesBtn.innerHTML = `<i class="${options.btnIconClass}"></i> `;
                }
                yesBtn.innerHTML += btnText;
                yesBtn.className = 'btn ' + btnClass;
                yesBtn.onclick = function () {
                    closeModal('customConfirmModal');
                    if (customConfirmCallback) customConfirmCallback();
                };
            }

            openModal('customConfirmModal');
        }

        // ── MERGE DUPLICATES CONTROLLER ─────────────────────────────
        let _mergeData = null;
        let _mergeSelectedTarget = 'A'; // Default Target profile is A

        async function triggerBulkMerge() {
            if (selectedStudentIds.size !== 2) {
                showToast('يرجى تحديد طفلين فقط لإجراء الدمج', 'warning');
                return;
            }
            const ids = Array.from(selectedStudentIds);
            const idA = ids[0];
            const idB = ids[1];

            showLoading('جاري تحميل بيانات المقارنة...');
            try {
                const fd = new FormData();
                fd.append('action', 'getMergeComparison');
                fd.append('studentIdA', idA);
                fd.append('studentIdB', idB);

                const resp = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                    .then(r => r.json())
                    .catch(() => ({ success: false, message: 'خطأ في الاتصال بالخادم' }));

                hideLoading();
                if (!resp.success) {
                    showToast(resp.message || 'فشل تحميل بيانات المقارنة', 'error');
                    return;
                }

                _mergeData = resp;
                _mergeSelectedTarget = 'A'; // default primary target is A

                renderMergeComparison();

                const modal = document.getElementById('mergeDuplicateModal');
                if (modal) modal.classList.add('active');
                stopAutoRefresh();
            } catch (e) {
                hideLoading();
                console.error(e);
                showToast('حدث خطأ غير متوقع: ' + e.message, 'error');
            }
        }

        function startMergeChooseMode() {
            if (currentClass === 'الخدام') {
                showToast('غير مسموح بدمج حسابات الخدام', 'error');
                return;
            }
            if (selectedStudentIds.size === 2) {
                triggerBulkMerge();
                return;
            }

            selectedStudentIds.clear();
            isMergeChoosingMode = true;

            if (!isBulkSelectMode) {
                toggleBulkSelectMode();
            } else {
                updateBulkUI();
                renderAttendanceList(currentClass);
            }

            showToast('يرجى تحديد طفلين فقط من القائمة لدمج حساباتهما', 'info');
        }

        function closeMergeModal() {
            const modal = document.getElementById('mergeDuplicateModal');
            if (modal) modal.classList.remove('active');
            _mergeData = null;
            startAutoRefresh();
        }

        function selectMergeTarget(targetLetter) {
            _mergeSelectedTarget = targetLetter;
            document.querySelectorAll('.merge-kid-card').forEach(card => {
                card.classList.remove('active-target');
            });
            const selectedCard = document.getElementById(`mergeCard${targetLetter}`);
            if (selectedCard) {
                selectedCard.classList.add('active-target');
            }

            // Auto check credentials radio button ONLY if both have credentials
            if (_mergeData && _mergeData.hasPasswordA && _mergeData.hasPasswordB) {
                const credRadio = document.querySelector(`input[name="merge_credentials"][value="${targetLetter}"]`);
                if (credRadio) {
                    credRadio.checked = true;
                    document.querySelectorAll('input[name="merge_credentials"]').forEach(r => {
                        const item = r.closest('.merge-radio-item');
                        if (item) {
                            if (r.checked) item.classList.add('selected');
                            else item.classList.remove('selected');
                        }
                    });
                }
            }
        }

        function renderMergeComparison() {
            if (!_mergeData) return;
            const content = document.getElementById('mergeModalContent');
            if (!content) return;

            const sA = _mergeData.studentA;
            const sB = _mergeData.studentB;
            const hasPassA = _mergeData.hasPasswordA;
            const hasPassB = _mergeData.hasPasswordB;
            const tasksA = _mergeData.taskCountA || 0;
            const tasksB = _mergeData.taskCountB || 0;
            const conflicts = _mergeData.attendanceConflicts || [];
            const unionAtt = _mergeData.attendanceUnion || [];

            const getAvatarHtml = (s, letter) => {
                const gender = (s.gender === 'female' || s['النوع'] === 'female') ? 'female' : 'male';
                const avatar = s.image_url
                    ? `<img src="${window.photoUrl ? window.photoUrl(s.image_url) : s.image_url}" alt="" class="merge-avatar" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
                    : '';
                const fallback = `<div class="merge-avatar-fallback ${gender}" ${s.image_url ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;
                return `
                    <div id="mergeCard${letter}" class="merge-kid-card ${letter === 'A' ? 'active-target' : ''}" onclick="selectMergeTarget('${letter}')">
                        <span class="merge-kid-card-badge">${letter === 'A' ? 'الحساب الرئيسي' : 'حساب مكرر'}</span>
                        ${avatar}${fallback}
                        <div style="font-weight:800;font-size:0.86rem;margin-top:6px;">${escHtml(s.name)}</div>
                        <div style="font-size:0.7rem;color:var(--text-3)">${escHtml(s.class_name || '---')}</div>
                    </div>
                `;
            };

            const headerHtml = `
                <div class="merge-header-cards" style="margin-bottom: 16px;">
                    ${getAvatarHtml(sA, 'A')}
                    ${getAvatarHtml(sB, 'B')}
                </div>
            `;

            // Field configurations
            const fields = [
                { key: 'name', label: 'الاسم الكامل' },
                { key: 'gender', label: 'النوع', format: v => v === 'female' ? 'بنت' : 'ولد' },
                { key: 'class_id', displayKey: 'class_name', label: 'الفصل' },
                { key: 'phone', label: 'رقم التليفون' },
                { key: 'emergency_phone', label: 'تليفون الطوارئ' },
                { key: 'email', label: 'البريد الإلكتروني' },
                { key: 'birthday', label: 'تاريخ الميلاد' },
                { key: 'address', label: 'العنوان' },
                { key: 'medical_notes', label: 'ملاحظات طبية' },
                {
                    key: 'image_url',
                    label: 'الصورة الشخصية',
                    isHtml: true,
                    format: v => v ? `<img src="${window.photoUrl ? window.photoUrl(v) : v}" style="width:40px;height:40px;border-radius:50%;object-fit:cover;border:2px solid var(--border-color);vertical-align:middle;">` : 'لا توجد صورة'
                }
            ];

            let tableRowsHtml = '';

            fields.forEach(f => {
                const valA = (sA[f.key] || '').toString().trim();
                const valB = (sB[f.key] || '').toString().trim();

                const dispValA = f.displayKey ? sA[f.displayKey] : valA;
                const dispValB = f.displayKey ? sB[f.displayKey] : valB;

                const dispA = f.format ? f.format(dispValA) : dispValA;
                const dispB = f.format ? f.format(dispValB) : dispValB;

                const isIdentical = valA && valB && (valA.toLowerCase() === valB.toLowerCase());

                if (isIdentical) {
                    tableRowsHtml += `
                        <tr>
                            <td class="merge-field-label">${f.label}</td>
                            <td colspan="2" class="merge-cell-option identical" style="text-align:center;">
                                ${f.isHtml ? dispA : escHtml(dispA || '---')} <span style="color:var(--success);margin-right:8px;"><i class="fas fa-check-circle"></i> متطابق</span>
                            </td>
                        </tr>
                    `;
                } else {
                    // Auto-choose non-empty
                    const isMissingA = !valA;
                    const isMissingB = !valB;

                    const checkedA = !isMissingA ? 'checked' : '';
                    const checkedB = isMissingB ? '' : (isMissingA ? 'checked' : '');

                    const classA = isMissingB && !isMissingA ? 'auto-selected' : '';
                    const classB = isMissingA && !isMissingB ? 'auto-selected' : '';

                    tableRowsHtml += `
                        <tr>
                            <td class="merge-field-label">${f.label}</td>
                            <td class="merge-cell-option ${classA}">
                                <label>
                                    <input type="radio" name="field_${f.key}" value="A" ${checkedA}>
                                    <span>${f.isHtml ? dispA : escHtml(dispA || '---')}</span>
                                    ${classA ? '<span style="font-size:0.6rem;margin-right:auto;">(تلقائي)</span>' : ''}
                                </label>
                            </td>
                            <td class="merge-cell-option ${classB}">
                                <label>
                                    <input type="radio" name="field_${f.key}" value="B" ${checkedB}>
                                    <span>${f.isHtml ? dispB : escHtml(dispB || '---')}</span>
                                    ${classB ? '<span style="font-size:0.6rem;margin-right:auto;">(تلقائي)</span>' : ''}
                                </label>
                            </td>
                        </tr>
                    `;
                }
            });

            // Parse Custom Fields
            let parsedCustomA = {};
            let parsedCustomB = {};
            try { parsedCustomA = JSON.parse(sA.custom_info) || {}; } catch (e) { }
            try { parsedCustomB = JSON.parse(sB.custom_info) || {}; } catch (e) { }

            const allCustomKeys = Array.from(new Set([...Object.keys(parsedCustomA), ...Object.keys(parsedCustomB)]))
                .filter(k => k !== 'username' && k !== 'sibling_group');

            if (allCustomKeys.length > 0) {
                tableRowsHtml += `
                    <tr>
                        <th colspan="3" style="text-align:right;background:var(--surface-3);font-size:0.82rem;font-weight:800;color:var(--brand)">
                            <i class="fas fa-sliders"></i> الحقول المخصصة
                        </th>
                    </tr>
                `;
                allCustomKeys.forEach(k => {
                    const valA = (parsedCustomA[k] || '').toString().trim();
                    const valB = (parsedCustomB[k] || '').toString().trim();

                    const isIdentical = valA && valB && (valA.toLowerCase() === valB.toLowerCase());

                    if (isIdentical) {
                        tableRowsHtml += `
                            <tr>
                                <td class="merge-field-label">${escHtml(k)}</td>
                                <td colspan="2" class="merge-cell-option identical" style="text-align:center;">
                                    ${escHtml(valA || '---')} <span style="color:var(--success);margin-right:8px;"><i class="fas fa-check-circle"></i> متطابق</span>
                                </td>
                            </tr>
                        `;
                    } else {
                        const isMissingA = !valA;
                        const isMissingB = !valB;

                        const checkedA = !isMissingA ? 'checked' : '';
                        const checkedB = isMissingB ? '' : (isMissingA ? 'checked' : '');

                        const classA = isMissingB && !isMissingA ? 'auto-selected' : '';
                        const classB = isMissingA && !isMissingB ? 'auto-selected' : '';

                        tableRowsHtml += `
                            <tr>
                                <td class="merge-field-label">${escHtml(k)}</td>
                                <td class="merge-cell-option ${classA}">
                                    <label>
                                        <input type="radio" name="customfield_${k}" value="A" ${checkedA}>
                                        <span>${escHtml(valA || '---')}</span>
                                        ${classA ? '<span style="font-size:0.6rem;margin-right:auto;">(تلقائي)</span>' : ''}
                                    </label>
                                </td>
                                <td class="merge-cell-option ${classB}">
                                    <label>
                                        <input type="radio" name="customfield_${k}" value="B" ${checkedB}>
                                        <span>${escHtml(valB || '---')}</span>
                                        ${classB ? '<span style="font-size:0.6rem;margin-right:auto;">(تلقائي)</span>' : ''}
                                    </label>
                                </td>
                            </tr>
                        `;
                    }
                });
            }

            // Credentials box (username & password)
            let credentialsHtml = '';
            const userA = parsedCustomA.username || '';
            const userB = parsedCustomB.username || '';

            if (!hasPassA && !hasPassB) {
                credentialsHtml = `
                    <div style="font-size:0.75rem;color:var(--text-3);background:var(--surface-3);padding:10px;border-radius:var(--r-md);text-align:center;">
                        <i class="fas fa-info-circle"></i> لا يمتلك أي من الحسابين كلمة مرور أو حساب دخول نشط.
                        <input type="hidden" name="merge_credentials" value="auto">
                    </div>
                `;
            } else {
                const checkedCredA = hasPassA ? 'checked' : '';
                const checkedCredB = !hasPassA && hasPassB ? 'checked' : '';

                const classCredA = checkedCredA ? 'selected' : '';
                const classCredB = checkedCredB ? 'selected' : '';

                credentialsHtml = `
                    <div class="merge-radio-group">
                        <label class="merge-radio-item ${classCredA}" onclick="document.querySelectorAll('input[name=\\'merge_credentials\\']').forEach(r => r.closest('.merge-radio-item').classList.remove('selected')); this.classList.add('selected')">
                            <input type="radio" name="merge_credentials" value="A" ${checkedCredA}>
                            <div>
                                <div style="font-weight:700;font-size:0.78rem;">بيانات حساب: ${escHtml(sA.name)}</div>
                                <div style="font-size:0.7rem;color:var(--text-3)">اسم المستخدم: ${escHtml(userA || '(لا يوجد)')} | كلمة المرور: ${hasPassA ? '✓ متوفرة' : '✗ غير متوفرة'}</div>
                            </div>
                            ${hasPassA && !hasPassB ? '<span style="font-size:0.66rem;color:var(--success);margin-right:auto;font-weight:700;"><i class="fas fa-check-circle"></i> اختيار تلقائي</span>' : ''}
                        </label>
                        <label class="merge-radio-item ${classCredB}" onclick="document.querySelectorAll('input[name=\\'merge_credentials\\']').forEach(r => r.closest('.merge-radio-item').classList.remove('selected')); this.classList.add('selected')">
                            <input type="radio" name="merge_credentials" value="B" ${checkedCredB}>
                            <div>
                                <div style="font-weight:700;font-size:0.78rem;">بيانات حساب: ${escHtml(sB.name)}</div>
                                <div style="font-size:0.7rem;color:var(--text-3)">اسم المستخدم: ${escHtml(userB || '(لا يوجد)')} | كلمة المرور: ${hasPassB ? '✓ متوفرة' : '✗ غير متوفرة'}</div>
                            </div>
                            ${hasPassB && !hasPassA ? '<span style="font-size:0.66rem;color:var(--success);margin-right:auto;font-weight:700;"><i class="fas fa-check-circle"></i> اختيار تلقائي</span>' : ''}
                        </label>
                    </div>
                `;
            }

            // Coupon strategy
            const couponsSum = (sA.coupons || 0) + (sB.coupons || 0);
            const couponHtml = `
                <div class="merge-radio-group">
                    <label class="merge-radio-item selected" onclick="document.querySelectorAll('input[name=\\'merge_coupons\\']').forEach(r => r.closest('.merge-radio-item').classList.remove('selected')); this.classList.add('selected')">
                        <input type="radio" name="merge_coupons" value="sum" checked>
                        <div>
                            <div style="font-weight:700;font-size:0.78rem;">جمع كوبونات المحفظتين (الكوبونات الإجمالية: ${couponsSum})</div>
