                        </div>
                        ${attendanceHtml}
                    </div>
                </div>
            `;
        }

        async function submitMergeDuplicate() {
            if (!_mergeData) return;
            const sA = _mergeData.studentA;
            const sB = _mergeData.studentB;

            const isTargetA = _mergeSelectedTarget === 'A';
            const targetId = isTargetA ? sA.id : sB.id;
            const duplicateId = isTargetA ? sB.id : sA.id;

            const targetName = isTargetA ? sA.name : sB.name;
            const duplicateName = isTargetA ? sB.name : sA.name;

            const fields = ['name', 'gender', 'class_id', 'phone', 'emergency_phone', 'email', 'birthday', 'address', 'medical_notes', 'image_url'];
            const profileFields = {};

            fields.forEach(f => {
                const radio = document.querySelector(`input[name="field_${f}"]:checked`);
                if (radio) {
                    profileFields[f] = radio.value;
                } else {
                    profileFields[f] = 'A';
                }
            });

            let parsedCustomA = {};
            let parsedCustomB = {};
            try { parsedCustomA = JSON.parse(sA.custom_info) || {}; } catch (e) { }
            try { parsedCustomB = JSON.parse(sB.custom_info) || {}; } catch (e) { }
            const allCustomKeys = Array.from(new Set([...Object.keys(parsedCustomA), ...Object.keys(parsedCustomB)]))
                .filter(k => k !== 'username' && k !== 'sibling_group');

            const customFieldsSources = {};
            allCustomKeys.forEach(k => {
                const radio = document.querySelector(`input[name="customfield_${k}"]:checked`);
                if (radio) {
                    customFieldsSources[k] = radio.value;
                } else {
                    customFieldsSources[k] = 'A';
                }
            });
            profileFields['custom_fields'] = customFieldsSources;

            const credentialsRadio = document.querySelector('input[name="merge_credentials"]:checked');
            const credentialsFrom = credentialsRadio ? credentialsRadio.value : 'A';

            const couponsRadio = document.querySelector('input[name="merge_coupons"]:checked');
            const couponsMode = couponsRadio ? couponsRadio.value : 'sum';

            const attRadio = document.querySelector('input[name="merge_attendance"]:checked');
            const attendanceMode = attRadio ? attRadio.value : 'combine';

            const attendanceConflicts = {};
            const conflicts = _mergeData.attendanceConflicts || [];
            conflicts.forEach(c => {
                const radio = document.querySelector(`input[name="attconflict_${c.date}"]:checked`);
                if (radio) {
                    attendanceConflicts[c.date] = radio.value;
                }
            });

            const confirmMsg = `أنت على وشك دمج حساب الطفل "${duplicateName}" مع حساب الطفل الرئيسي "${targetName}".\nسيتم حذف حساب "${duplicateName}" بالكامل وتحويل كافة سجلاته التاريخية وحل التعارضات كما اخترت.\nهل تريد المتابعة؟`;

            showCustomConfirm({
                title: 'تأكيد دمج الحسابين',
                message: confirmMsg,
                icon: '<i class="fas fa-code-merge"></i>',
                iconColor: '#8b5cf6',
                btnText: 'تأكيد ودمج',
                btnClass: 'btn-success',
                btnIconClass: 'fas fa-check-double',
                onConfirm: () => {
                    showLoading('جاري دمج الحسابات المكررة...');
                    makeApiCall({
                        action: 'mergeDuplicateStudents',
                        target_id: targetId,
                        duplicate_id: duplicateId,
                        is_target_a: isTargetA,
                        profile_fields: profileFields,
                        credentials_from: credentialsFrom,
                        attendance_mode: attendanceMode,
                        attendance_conflicts: attendanceConflicts,
                        coupons_mode: couponsMode
                    }, d => {
                        showToast(d.message || 'تم دمج الحسابين بنجاح', 'success');
                        closeMergeModal();
                        disableBulkSelectMode();
                        loadData();
                    }, err => {
                        showToast(err || 'فشل الدمج', 'error');
                    });
                }
            });
        }

        // Bulk operations triggers for class uncle
        async function triggerBulkDelete() {
            if (selectedStudentIds.size === 0) {
                showToast('الرجاء تحديد أطفال أولاً', 'warning');
                return;
            }

            const msg = `هل أنت متأكد من حذف ${selectedStudentIds.size} من الأطفال المحددين؟\nلا يمكن التراجع عن هذا الإجراء وسيتم مسح سجلاتهم تماماً.`;

            showCustomConfirm({
                title: 'تأكيد الحذف الجماعي',
                message: msg,
                icon: '<i class="fas fa-exclamation-triangle"></i>',
                iconColor: 'var(--danger)',
                btnText: 'نعم، احذف',
                btnClass: 'btn-danger',
                btnIconClass: 'fas fa-trash-alt',
                onConfirm: () => {
                    showLoading('جاري الحذف...');
                    makeApiCall({
                        action: 'bulkDeleteStudents',
                        student_ids: Array.from(selectedStudentIds).join(',')
                    }, d => {
                        showToast(d.message || 'تم حذف الأطفال بنجاح', 'success');
                        selectedStudentIds.clear();
                        updateBulkUI();
                        loadData();
                    }, err => {
                        showToast(err || 'فشل في الحذف الجماعي', 'error');
                    });
                }
            });
        }



        function triggerBulkClass() {
            if (selectedStudentIds.size === 0) {
                showToast('الرجاء تحديد أطفال أولاً', 'warning');
                return;
            }

            document.getElementById('bulkClassCountLabel').textContent = `تغيير الفصل لـ ${selectedStudentIds.size} من الأطفال المحددين`;

            const selectEl = document.getElementById('bulkClassSelect');
            if (selectEl) {
                selectEl.innerHTML = '';
                classes.forEach(c => {
                    const opt = document.createElement('option');
                    opt.value = c.id;
                    opt.textContent = c.arabic_name;
                    selectEl.appendChild(opt);
                });
            }

            openModal('bulkEditClassModal');
        }

        async function executeBulkClass(e) {
            e.preventDefault();
            const classId = parseInt(document.getElementById('bulkClassSelect').value);

            if (isNaN(classId) || classId <= 0) {
                showToast('الرجاء تحديد فصل صالح', 'warning');
                return;
            }

            showLoading('جاري الحفظ...');
            makeApiCall({
                action: 'bulkUpdateStudentsClass',
                student_ids: Array.from(selectedStudentIds).join(','),
                class_id: classId
            }, d => {
                showToast(d.message || 'تم تغيير الفصل بنجاح', 'success');
                closeModal('bulkEditClassModal');
                selectedStudentIds.clear();
                updateBulkUI();
                loadData();
            }, err => {
                showToast(err || 'فشل نقل الأطفال', 'error');
            });
        }

        function animateCouponDelta(studentId, delta) {
            const row = document.getElementById('ai-' + studentId);
            if (!row) return;
            const couponsEl = row.querySelector('.student-coupons');
            if (!couponsEl) return;

            const rect = couponsEl.getBoundingClientRect();

            // Create a floating badge element
            const badge = document.createElement('div');
            badge.className = 'coupon-delta-badge' + (delta >= 0 ? ' plus' : ' minus');
            badge.textContent = (delta >= 0 ? '+' : '') + delta;

            // Position absolutely on document.body using page coordinates
            badge.style.position = 'absolute';
            badge.style.left = (rect.left + window.scrollX + rect.width / 2) + 'px';
            badge.style.top = (rect.top + window.scrollY - 10) + 'px';
            badge.style.zIndex = '100000';
            badge.style.pointerEvents = 'none'; // click-through

            document.body.appendChild(badge);

            setTimeout(() => {
                badge.remove();
            }, 800);
        }

        // ── SAVE BUTTONS ──────────────────────────────────────────────
        function buildKidProfileQrLink(studentId) {
            const id = String(studentId || '').trim();
            if (!id) return '';
            return `${window.location.origin}/user/profile/?id=${encodeURIComponent(id)}`;
        }

        function getKidIdFromQrText(decodedText) {
            if (!decodedText) return '';
            try {
                const cleaned = String(decodedText).trim();

                // Detect temp QR code and redirect immediately
                let tempid = null;
                if (cleaned.includes('tempid=')) {
                    try {
                        const url = new URL(cleaned.startsWith('/') || !cleaned.includes('://') ? window.location.origin + (cleaned.startsWith('/') ? '' : '/') + cleaned : cleaned);
                        tempid = url.searchParams.get('tempid');
                    } catch (e) {
                        const match = cleaned.match(/[?&]tempid=([^&]+)/);
                        if (match) tempid = match[1];
                    }
                } else if (cleaned.startsWith('tempid_')) {
                    tempid = cleaned;
                }
                if (tempid) {
                    window.location.href = `/user/profile/?tempid=${encodeURIComponent(tempid)}`;
                    return '';
                }

                // If it's a URL
                if (cleaned.includes('://') || cleaned.includes('?')) {
                    const url = new URL(cleaned, window.location.origin);
                    const id = url.searchParams.get('student_id') ||
                        url.searchParams.get('studentId') ||
                        url.searchParams.get('id');
                    if (id) return id.trim();
                }

                // If it's a raw integer
                if (/^\d+$/.test(cleaned)) {
                    return cleaned;
                }

                // Direct lookup fallback
                const pool = isCombinedView ? combinedStudents : students;
                const match = pool.find(s => String(getStudentId(s)) === cleaned || String(getStudentDbId(s)) === cleaned);
                if (match) return getStudentId(match);

                return cleaned;
            } catch (e) {
                return '';
            }
        }

        function findStudentById(studentId) {
            const id = String(studentId || '').trim();
            if (!id) return null;
            const pool = isCombinedView ? combinedStudents : students;
            return pool.find(s => String(getStudentId(s)) === id || String(getStudentDbId(s)) === id) ||
                allStudentsData.find(s => String(getStudentId(s)) === id || String(getStudentDbId(s)) === id) || null;
        }

        function switchModalScanMode(mode) {
            if (['attendance', 'coupons', 'profile', 'profile-in-class'].includes(mode)) {
                kidQrScanMode = mode;
                const savedPreferenceMode = mode === 'profile-in-class' ? 'profile' : mode;
                localStorage.setItem('scanner_mode_preference', savedPreferenceMode);

                // Update active tab style
                document.querySelectorAll('.modal-mode-tab').forEach(btn => {
                    btn.style.background = 'none';
                    btn.style.color = 'var(--text-3)';
                });
                const tabId = mode === 'profile-in-class' ? 'modalTab_profile' : 'modalTab_' + mode;
                const activeBtn = document.getElementById(tabId);
                if (activeBtn) {
                    activeBtn.style.background = 'var(--surface)';
                    activeBtn.style.color = 'var(--brand)';
                }

                // Show/hide coupon select container
                const container = document.getElementById('kidQrCouponSelectContainer');
                if (container) {
                    if (mode === 'coupons') {
                        container.style.display = 'block';
                        const selectEl = document.getElementById('kidQrCouponSelect');
                        kidQrScanAmount = selectEl ? parseInt(selectEl.value, 10) || 10 : 10;
                    } else {
                        container.style.display = 'none';
                        kidQrScanAmount = 0;
                    }
                }

                refreshKidQrScanUI();
            }
        }

        function refreshKidQrScanUI() {
            const title = document.getElementById('kidQrScannerTitle');
            const subtitle = document.getElementById('kidQrScannerSubtitle');
            const summary = document.getElementById('kidQrScanSummary');
            const list = document.getElementById('kidQrScanList');
            const doneBtn = document.getElementById('kidQrDoneBtn');
            const saveBtn = document.getElementById('kidQrSaveAllBtn');

            if (title) {
                title.innerHTML = kidQrScanMode === 'coupons'
                    ? '<i class="fas fa-qrcode"></i> مسح QR الكوبونات'
                    : kidQrScanMode === 'attendance'
                        ? '<i class="fas fa-qrcode"></i> مسح QR الحضور'
                        : '<i class="fas fa-qrcode"></i> مسح QR الطفل';
            }

            if (subtitle) {
                subtitle.textContent = kidQrScanMode === 'coupons'
                    ? `سيتم إضافة ${kidQrScanAmount} كوبون لكل طفل تقوم بمسحه`
                    : kidQrScanMode === 'attendance'
                        ? 'قم بمسح كود حضور الأطفال.'
                        : 'امسح QR الطفل لفتح ملفه مباشرة.';
            }

            if (saveBtn) {
                if (kidQrScanMode === 'profile' || kidQrScanMode === 'profile-in-class') {
                    saveBtn.style.display = 'none';
                } else {
                    saveBtn.style.display = 'block';
                    const hasChanges = (changedStudents.size > 0 || changedCouponStudents.size > 0);
                    saveBtn.disabled = !hasChanges;
                    saveBtn.style.opacity = hasChanges ? '1' : '0.5';
                }
            }

            if (doneBtn) {
                if (kidQrScanMode === 'profile' || kidQrScanMode === 'profile-in-class') {
                    doneBtn.style.display = 'none';
                } else {
                    doneBtn.style.display = 'block';
                    doneBtn.innerHTML = kidQrScanMode === 'coupons'
                        ? '<i class="fas fa-check"></i> تم إضافة الكوبونات'
                        : '<i class="fas fa-check"></i> تم تسجيل الحضور';
                }
            }

            if (list) {
                if (!kidQrScanEntries.length) {
                    if (summary) summary.innerHTML = '';
                    list.innerHTML = '<div style="text-align:center;padding:18px 12px;color:var(--text-3);font-size:.84rem;background:var(--surface-2);border:1px dashed var(--border);border-radius:12px">لم يتم مسح أي طفل بعد</div>';
                } else {
                    if (summary) {
                        const alertHtml = kidQrScanMode === 'coupons'
                            ? `<div style="background:var(--coupon-bg);border:1px solid rgba(124,58,237,.16);color:var(--coupon-dark);padding:10px 12px;border-radius:12px;font-size:.82rem;line-height:1.5;margin-bottom:10px;">تم اختيار <strong>${kidQrScanAmount}</strong> كوبون لكل طفل ممسوح.</div>`
                            : kidQrScanMode === 'attendance'
                                ? `<div style="background:var(--success-bg);border:1px solid rgba(16,185,129,.16);color:var(--success);padding:10px 12px;border-radius:12px;font-size:.82rem;line-height:1.5;margin-bottom:10px;">الأطفال الممسوحون هنا سيُسجَّلون كحاضرِين محلياً فقط، ثم تضغط حفظ لاحقاً.</div>`
                                : '';

                        summary.innerHTML = alertHtml + `
                            <div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px;margin-bottom:6px;direction:rtl;">
                                <span style="font-weight:800;font-size:0.85rem;color:var(--text-2)">الأطفال الممسوحون (${kidQrScanEntries.length})</span>
                                <button type="button" onclick="clearAllKidQrScans()" style="color:var(--danger);font-size:0.75rem;padding:2px 8px;border:none;background:none;cursor:pointer;font-weight:700;display:flex;align-items:center;gap:4px;margin-right:auto;">
                                    <i class="fas fa-trash-alt"></i> مسح الكل
                                </button>
                            </div>
                        `;
                    }
                    list.innerHTML = kidQrScanEntries.map((entry, idx) => `
                        <div style="display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;border:1px solid var(--border);border-radius:12px;background:var(--surface)">
                            <div style="min-width:0;flex:1">
                                <div style="font-weight:800;color:var(--text);font-size:.9rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${entry.name}</div>
                                <div style="font-size:.74rem;color:var(--text-3);margin-top:2px">${entry.className || ''}</div>
                            </div>
                            <div style="display:flex;align-items:center;gap:8px;">
                                <div style="flex:none;display:inline-flex;align-items:center;gap:6px;padding:6px 10px;border-radius:999px;background:${entry.scanType === 'coupons' ? 'var(--coupon-bg)' : 'var(--success-bg)'};color:${entry.scanType === 'coupons' ? 'var(--coupon-dark)' : 'var(--success)'};font-weight:800;font-size:.8rem">
                                    <i class="fas ${entry.scanType === 'coupons' ? 'fa-star' : 'fa-user-check'}"></i>
                                    ${entry.scanType === 'coupons' ? `+${entry.amount}` : 'حاضر'}
                                </div>
                                <button type="button" class="btn btn-ghost btn-sm" onclick="deleteKidQrScanEntry(${idx})" title="حذف من السجل" style="color:var(--danger);padding:4px 8px;min-width:32px;height:32px;display:flex;align-items:center;justify-content:center;border-radius:8px;border:none;background:none;cursor:pointer;">
                                    <i class="fas fa-trash-alt"></i>
                                </button>
                            </div>
                        </div>
                    `).join('');
                }
            }
        }

        function deleteKidQrScanEntry(index) {
            if (index < 0 || index >= kidQrScanEntries.length) return;
            const entry = kidQrScanEntries[index];

            // Undo the changes made by the entry
            if (entry.scanType === 'attendance') {
                const srvStatus = originalAttendanceData[entry.id] || 'pending';
                markStudentAttendance(entry.id, srvStatus, true);
            } else if (entry.scanType === 'coupons') {
                const amount = entry.amount || 0;
                const cur = parseInt(couponData[entry.id] || 0);
                const newVal = cur - amount;
                couponData[entry.id] = newVal;
                if (newVal !== 0) {
                    changedCouponStudents.add(entry.id);
                } else {
                    changedCouponStudents.delete(entry.id);
                }
                saveCouponDataForClass(entry.className);
                if (currentClass) {
                    renderAttendanceList(currentClass);
                    updateClassStats();
                }
                updateSaveBtns();
            }

            // Remove the composite ID and scan type from kidQrScanSeen
            const seenKey = entry.id + '_' + entry.scanType;
            kidQrScanSeen.delete(seenKey);

            // Remove from the array
            kidQrScanEntries.splice(index, 1);

            // Refresh UI
            refreshKidQrScanUI();
        }

        function clearAllKidQrScans() {
            if (!kidQrScanEntries.length) return;

            // Loop backwards to undo all entries
            for (let i = kidQrScanEntries.length - 1; i >= 0; i--) {
                const entry = kidQrScanEntries[i];
                if (entry.scanType === 'attendance') {
                    const srvStatus = originalAttendanceData[entry.id] || 'pending';
                    markStudentAttendance(entry.id, srvStatus, true);
                } else if (entry.scanType === 'coupons') {
                    const amount = entry.amount || 0;
                    const cur = parseInt(couponData[entry.id] || 0);
                    const newVal = cur - amount;
                    couponData[entry.id] = newVal;
                    if (newVal !== 0) {
                        changedCouponStudents.add(entry.id);
                    } else {
                        changedCouponStudents.delete(entry.id);
                    }
                    saveCouponDataForClass(entry.className);
                }
            }

            // Clear lists/states
            kidQrScanSeen.clear();
            kidQrScanEntries = [];

            if (currentClass) {
                renderAttendanceList(currentClass);
                updateClassStats();
            }
            updateSaveBtns();

            // Refresh UI
            refreshKidQrScanUI();
        }

        function recordKidQrScan(studentId) {
            const id = String(studentId || '').trim();
            if (!id) {
                playErrorSound();
                return false;
            }

            const student = findStudentById(id);
            if (!student) {
                playErrorSound();
                showToast('لم يتم العثور على الطفل في هذه الصفحة', 'warning');
                return false;
            }

            // Green Flash UI feedback
            const reader = document.getElementById('kidQrReader');
            if (reader) {
                reader.style.setProperty('border', '3px solid #10b981', 'important');
                reader.style.setProperty('box-shadow', '0 0 25px rgba(16, 185, 129, 0.7)', 'important');
                setTimeout(() => {
                    reader.style.removeProperty('border');
                    reader.style.removeProperty('box-shadow');
                }, 500);
            }

            const studentCompositeId = getStudentId(student);
            const className = student['الفصل'] || student.class || '';

            const seenKey = studentCompositeId + '_' + kidQrScanMode;
            if (kidQrScanSeen.has(seenKey)) {
                playErrorSound();
                showToast('تمت إضافة هذا الطفل بالفعل في هذا الوضع', 'info');
                return false;
            }

            // If in class view, restrict to children in the class
            if (currentClass) {
                const activePool = isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass);
                const inCurrentView = activePool.some(s => getStudentId(s) === studentCompositeId);
                if (!inCurrentView) {
                    playErrorSound();
                    showToast('هذا الطفل ليس داخل الفصل الحالي', 'warning');
                    return false;
                }
            }

            // Ensure class attendance data is loaded if scanning attendance
            if (kidQrScanMode === 'attendance' && !(studentCompositeId in attendanceData)) {
                loadAttendanceDataForClass(className);
            }

            kidQrScanSeen.add(seenKey);
            const name = student['الاسم'] || student.name || 'طفل';

            if (kidQrScanMode === 'attendance') {
                markStudentAttendance(studentCompositeId, 'present', true);
                saveAttendanceDataForClass(className);
                saveChangedStudentsToLocalStorage(className);
                kidQrScanEntries.push({ id: studentCompositeId, name, className, scanType: 'attendance' });
                if (currentClass) {
                    renderAttendanceList(currentClass);
                    updateClassStats();
                }
                updateSaveBtns();
            } else if (kidQrScanMode === 'coupons') {
                const amount = Math.max(1, parseInt(kidQrScanAmount, 10) || 1);
                const cur = parseInt(couponData[studentCompositeId] || 0);
                couponData[studentCompositeId] = cur + amount;
                changedCouponStudents.add(studentCompositeId);
                savedCouponStudents.delete(studentCompositeId);
                saveCouponDataForClass(className);
                kidQrScanEntries.push({ id: studentCompositeId, name, className, scanType: 'coupons', amount });
                if (currentClass) {
                    renderAttendanceList(currentClass);
                    updateClassStats();
                }
                updateSaveBtns();
            } else if (kidQrScanMode === 'profile' || kidQrScanMode === 'profile-in-class') {
                kidQrScanEntries.push({ id: studentCompositeId, name, className, scanType: 'profile' });
                playSuccessSound();
                setTimeout(() => {
                    stopKidQrScan();
                    showStudentDetails(name);
                }, 500);
                return true;
            }

            playSuccessSound();
            refreshKidQrScanUI();
            showToast(`تم مسح ${name}`, 'success');
            return true;
        }

        function stopKidQrScan() {
            kidQrScanInProgress = false;
            kidQrLastScanTime = 0;
            kidQrLastScanText = '';
            const modal = document.getElementById('kidQrScannerModal');
            if (kidQrScanner) {
                try {
                    const scanner = kidQrScanner;
                    kidQrScanner = null;
                    scanner.stop().then(() => {
                        scanner.clear?.();
                        if (modal) modal.classList.remove('active');
                    }).catch(() => {
                        if (modal) modal.classList.remove('active');
                    });
                } catch (e) {
                    if (modal) modal.classList.remove('active');
                }
            } else if (modal) {
                modal.classList.remove('active');
            }
        }

        function finishKidQrScan() {
            stopKidQrScan();
            if (currentClass) {
                renderAttendanceList(currentClass);
                updateClassStats();
                updateSaveBtns();
            }
        }

        let scannerSource = 'camera';

        function switchScannerSource(source) {
            if (['camera', 'usb'].includes(source)) {
                scannerSource = source;
                localStorage.setItem('scanner_source_preference', source);

                // Update tabs styling
                document.querySelectorAll('.scanner-source-tab').forEach(btn => {
                    btn.style.background = 'none';
                    btn.style.color = 'var(--text-3)';
                });
                const activeBtn = document.getElementById('scannerSourceTab_' + source);
                if (activeBtn) {
                    activeBtn.style.background = 'var(--surface)';
                    activeBtn.style.color = 'var(--brand)';
                }

                const readerEl = document.getElementById('kidQrReader');
                if (source === 'usb') {
                    // Stop camera scanner if running
                    if (kidQrScanner) {
                        const scanner = kidQrScanner;
                        kidQrScanner = null;
                        scanner.stop().then(() => {
                            scanner.clear?.();
                        }).catch(() => { });
                    }
                    // Show a clean placeholder in readerEl
                    if (readerEl) {
                        readerEl.style.minHeight = '180px';
                        readerEl.style.background = 'var(--surface-3)';
                        readerEl.style.border = '2px dashed var(--border)';
                        readerEl.style.display = 'flex';
                        readerEl.style.flexDirection = 'column';
                        readerEl.style.alignItems = 'center';
                        readerEl.style.justifyContent = 'center';
                        readerEl.style.color = 'var(--brand)';
                        readerEl.style.gap = '10px';
                        readerEl.style.padding = '20px';
                        readerEl.innerHTML = `
                            <i class="fas fa-barcode" style="font-size:2.8rem;opacity:0.85;"></i>
                            <div style="font-weight:800;font-size:1.0rem;text-align:center;">الماسح الخارجي نشط</div>
                            <div style="font-size:0.8rem;color:var(--text-3);text-align:center;max-width:280px;line-height:1.4;">قم بتوجيه قارئ الـ QR الخارجي نحو كروت الأطفال والمسح.</div>
                        `;
                    }
                } else {
                    // Source is camera
                    if (readerEl) {
                        readerEl.style.minHeight = '280px';
                        readerEl.style.background = '#000';
                        readerEl.style.border = 'none';
                        readerEl.innerHTML = '';
                    }
                    // Restart camera
                    restartCameraOnly();
                }
            }
        }

        async function restartCameraOnly() {
            if (kidQrScanner) return;
            const modal = document.getElementById('kidQrScannerModal');
            if (!modal || !modal.classList.contains('active')) return;
            if (scannerSource !== 'camera') return;

            kidQrScanner = new Html5Qrcode('kidQrReader');
            try {
                await kidQrScanner.start(
                    { facingMode: 'environment' },
                    { fps: 10, qrbox: (w, h) => { const min = Math.min(w, h); return { width: Math.max(160, min - 60), height: Math.max(160, min - 60) }; } },
                    async (decodedText) => {
                        if (kidQrScanInProgress) return;
                        kidQrScanInProgress = true;

                        const now = Date.now();
                        const kidId = getKidIdFromQrText(decodedText);
                        if (!kidId) {
                            showToast('QR غير صالح', 'error');
                            kidQrScanInProgress = false;
                            return;
                        }
                        if (kidId === kidQrLastScanText && (now - kidQrLastScanTime < 3000)) {
                            kidQrScanInProgress = false;
                            return;
                        }
                        kidQrLastScanTime = now;
                        kidQrLastScanText = kidId;

                        const success = recordKidQrScan(kidId);
                        if (!success) {
                            kidQrScanInProgress = false;
                        } else {
                            setTimeout(() => {
                                kidQrScanInProgress = false;
                            }, 1500);
                        }
                    },
                    () => { }
                );

                // Unmirror webcam
                let forceCount = 0;
                const forceInterval = setInterval(() => {
                    const videoEl = document.querySelector('#kidQrReader video');
                    if (videoEl) {
                        videoEl.style.setProperty('transform', 'scaleX(1)', 'important');
                        videoEl.style.setProperty('-webkit-transform', 'scaleX(1)', 'important');
                    }
                    forceCount++;
                    if (forceCount > 20) clearInterval(forceInterval);
                }, 100);
            } catch (err) {
                showToast('فشل تشغيل الكاميرا', 'error');
                stopKidQrScan();
            }
        }

        function showUnsavedModal() {
            const getStatusBadgeHtml = (status) => {
                let bc = '', lbl = '';
                if (status === 'present') {
                    bc = 'background: rgba(16,185,129,0.1); color: #10b981; border: 1.5px solid rgba(16,185,129,0.15); padding: 2px 8px; border-radius: 20px; font-weight: 700; font-size: 0.72rem; display: inline-flex; align-items: center; gap: 4px; white-space: nowrap;';
                    lbl = 'حاضر';
                } else if (status === 'absent') {
                    bc = 'background: rgba(239,68,68,0.1); color: #ef4444; border: 1.5px solid rgba(239,68,68,0.15); padding: 2px 8px; border-radius: 20px; font-weight: 700; font-size: 0.72rem; display: inline-flex; align-items: center; gap: 4px; white-space: nowrap;';
                    lbl = 'غائب';
                } else {
                    bc = 'background: rgba(156,163,175,0.1); color: #9ca3af; border: 1.5px solid rgba(156,163,175,0.15); padding: 2px 8px; border-radius: 20px; font-weight: 700; font-size: 0.72rem; display: inline-flex; align-items: center; gap: 4px; white-space: nowrap;';
                    lbl = 'غير مسجل';
                }
                return `<span style="${bc}">${lbl}</span>`;
            };

            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
            const list = (cls === 'الخدام')
                ? (window.allUnclesData || [])
                : (isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === cls));
            const ids = list.map(s => getStudentId(s));

            const allKeys = Object.keys(localStorage);
            const atDateEntries = []; // {date, id, name, status, student}
            const cpItems = [...changedCouponStudents].filter(id => ids.includes(id));

            allKeys.forEach(k => {
                const prefix = `changedStudents_${cls}_`;
                if (!k.startsWith(prefix)) return;
                const date = k.slice(prefix.length);
                try {
                    const changedIds = JSON.parse(localStorage.getItem(k) || '[]');
                    const localData = JSON.parse(localStorage.getItem(`attendanceData_${cls}_${date}`) || '{}');
                    changedIds.forEach(id => {
                        if (!ids.includes(id)) return;
