            });

            let html = '';

            const totalChanges = atDateEntries.length + cpItems.length;

            if (totalChanges > 0) {
                html += `<div style="display: flex; flex-direction: column; gap: 12px; max-height: 320px; overflow-y: auto; padding: 4px 0;">`;

                // Group Attendance entries by date
