        }

        async function startKidQrScan(mode = 'profile') {
            const normalizedMode = ['attendance', 'coupons', 'profile', 'profile-in-class', 'general'].includes(mode) ? mode : 'profile';

            let initialTabMode = normalizedMode;
            if (normalizedMode === 'general') {
                const savedMode = localStorage.getItem('scanner_mode_preference') || 'attendance';
                initialTabMode = savedMode;
            } else if (normalizedMode !== 'profile' && !currentClass) {
                showToast('اختر فصلًا أولًا', 'info');
                return false;
            }

            if (location.protocol !== 'https:' && location.hostname !== 'localhost' && !location.hostname.startsWith('127.')) {
                showToast('تنبيه: لتجنب طلب إذن الكاميرا في كل مرة، يرجى استخدام رابط HTTPS الآمن للموقع.', 'warning');
            }

            // Open modal first so DOM elements exist
            const modal = document.getElementById('kidQrScannerModal');
            if (modal) modal.classList.add('active');

            // Switch to the mode
            switchModalScanMode(initialTabMode);

            // Load scanner source preference from localStorage
            const pref = localStorage.getItem('scanner_source_preference') || 'camera';
            switchScannerSource(pref);

            return true;
        }

        // Global USB/Wireless Keyboard Scanner Listener
        (function () {
            let scanBuffer = '';
            let lastKeyTime = 0;
            const SCAN_TIMEOUT = 50; // ms

            document.addEventListener('keydown', function (e) {
                if (e.ctrlKey || e.altKey || e.metaKey) return;

                const modal = document.getElementById('kidQrScannerModal');
                const isModalActive = modal && modal.classList.contains('active');

                // If focusing editing input field and scanner modal is NOT active, ignore
                const activeTag = document.activeElement ? document.activeElement.tagName.toLowerCase() : '';
                const isEditing = activeTag === 'input' || activeTag === 'textarea';
                if (isEditing && !isModalActive) {
                    return;
                }

                const now = Date.now();
                if (e.key && e.key.length === 1) {
                    if (scanBuffer === '' || (now - lastKeyTime) < SCAN_TIMEOUT) {
                        scanBuffer += e.key;
                        lastKeyTime = now;
                    } else {
                        scanBuffer = e.key;
                        lastKeyTime = now;
                    }
                } else if (e.key === 'Enter') {
                    if (scanBuffer.length > 0) {
                        const kidId = getKidIdFromQrText(scanBuffer);
                        if (kidId) {
                            e.preventDefault();

                            const studentModal = document.getElementById('studentModal');
                            const isStudentModalOpen = studentModal && studentModal.classList.contains('active');

                            if (isStudentModalOpen) {
                                const student = findStudentById(kidId);
                                if (student) {
                                    const studentCompositeId = getStudentId(student);
                                    if (currentClass) {
                                        const activePool = isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass);
                                        const inCurrentView = activePool.some(s => getStudentId(s) === studentCompositeId);
                                        if (!inCurrentView) {
                                            playErrorSound();
                                            showToast('هذا الطفل ليس داخل الفصل الحالي', 'warning');
                                            scanBuffer = '';
                                            return;
                                        }
                                    }
                                    playSuccessSound();
                                    hideStudentModal();
                                    showStudentDetails(student['الاسم']);
                                } else {
                                    playErrorSound();
                                    showToast('لم يتم العثور على الطفل', 'warning');
                                }
                            } else {
                                if (!isModalActive) {
                                    const savedMode = currentClass
                                        ? (localStorage.getItem('scanner_mode_preference') || 'attendance')
                                        : 'profile';
                                    startKidQrScan(savedMode).then((success) => {
                                        if (success) {
                                            recordKidQrScan(kidId);
                                        }
                                    });
                                } else {
                                    recordKidQrScan(kidId);
                                }
                            }
                            scanBuffer = '';
                        }
                    }
                }
            });
        })();

        async function saveAllGeneralChanges() {
            let date = currentFriday;
            if (!date) { updateCurrentDateDisplay(); date = currentFriday; }

            // Group changed attendance by class
            const attByClass = {};
            changedStudents.forEach(id => {
                const s = students.find(s => getStudentId(s) === id);
                if (!s) return;
                const realClass = s['الفصل'];
                if (!attByClass[realClass]) attByClass[realClass] = [];
                attByClass[realClass].push({ studentName: s['الاسم'].trim(), status: attendanceData[id] || 'pending' });
            });

            // Group changed coupons by class
            const coupByClass = {};
            changedCouponStudents.forEach(id => {
                const s = students.find(s => getStudentId(s) === id);
                if (!s) return;
                const realClass = s['الفصل'];
                if (!coupByClass[realClass]) coupByClass[realClass] = [];
                coupByClass[realClass].push({ studentName: s['الاسم'].trim(), coupons: Math.max(0, (parseInt(s['كوبونات الالتزام'] || 0)) + (parseInt(couponData[id] || 0))) });
            });

            const totalCalls = Object.keys(attByClass).length + Object.keys(coupByClass).length;
            if (totalCalls === 0) {
                showToast('لا توجد تغييرات للحفظ', 'info');
                return;
            }

            const saveBtn = document.getElementById('kidQrSaveAllBtn');
            const originalHtml = saveBtn ? saveBtn.innerHTML : '';
            if (saveBtn) {
                saveBtn.disabled = true;
                saveBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> جاري الحفظ...';
            }

            let completedCalls = 0;
            let errors = [];

            const checkDone = () => {
                completedCalls++;
                if (completedCalls === totalCalls) {
                    if (saveBtn) {
                        saveBtn.disabled = false;
                        saveBtn.innerHTML = originalHtml;
                    }
                    if (errors.length > 0) {
                        showToast('حدث خطأ أثناء حفظ بعض البيانات', 'error');
                    } else {
                        showToast('تم حفظ جميع التغييرات بنجاح', 'success');

                        changedStudents.forEach(id => { savedStudents.add(id); originalAttendanceData[id] = attendanceData[id] || 'pending'; });
                        changedStudents.clear();

                        changedCouponStudents.forEach(id => { savedCouponStudents.add(id); });
                        changedCouponStudents.clear();
                        couponData = {};

                        const affectedClasses = new Set([...Object.keys(attByClass), ...Object.keys(coupByClass)]);
                        affectedClasses.forEach(cn => {
                            saveAttendanceDataForClass(cn);
                            saveCouponDataForClass(cn);
                        });

                        if (currentClass) {
                            renderAttendanceList(currentClass);
                        }
                        updateClassStats();
                        updateSaveBtns();
                        setTimeout(loadData, 1200);
                        stopKidQrScan();
                    }
                }
            };

            // Fire API calls for attendance
            Object.entries(attByClass).forEach(([cn, records]) => {
                makeApiCall({ action: 'submitAttendance', className: cn, attendanceData: JSON.stringify(records), date }, r => {
                    checkDone();
                }, e => {
                    errors.push(e);
                    checkDone();
                });
            });

            // Fire API calls for coupons
            Object.entries(coupByClass).forEach(([cn, records]) => {
                makeApiCall({ action: 'updateCoupons', className: cn, couponData: JSON.stringify(records) }, d => {
                    checkDone();
                }, e => {
                    errors.push(e);
                    checkDone();
                });
            });
        }

        function updateSaveBtns() {
            const at = document.getElementById('submitAttendance');
            const ct = document.getElementById('submitCoupons');
            const un = document.getElementById('saveAllBtn');
            if (!un) return;

            const list = (currentClass === 'الخدام')
                ? (window.allUnclesData || [])
                : (isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass));
            const ids = list.map(s => getStudentId(s));
            const achg = [...changedStudents].filter(id => ids.includes(id)).length;
            const cchg = [...changedCouponStudents].filter(id => ids.includes(id)).length;
            const tot = achg + cchg;

            // helper: icon + label/count wrapped together
            const btn = (icon, label, count) =>
                `<i class="${icon}"></i>`
                + `<span class="save-btn-bottom">`
                + `<span class="save-btn-label">${label}</span>`
                + (count > 0 ? `<span class="save-count">${count}</span>` : '')
                + `</span>`;

            // Attendance
            if (at) {
                at.disabled = achg === 0;
                at.innerHTML = btn('fas fa-user-check', 'الحضور', achg);
                at.title = achg > 0 ? ((currentClass === 'الخدام') ? `حفظ حضور ${achg} خادم` : `حفظ حضور ${achg} طفل`) : 'لا تغييرات في الحضور';
            }

            // Coupons
            if (ct) {
                ct.disabled = cchg === 0;
                ct.innerHTML = btn('fas fa-star', 'الكوبونات', cchg);
                ct.title = cchg > 0 ? `حفظ كوبونات ${cchg} طفل` : 'لا تغييرات في الكوبونات';
            }

            // Status / unsaved indicator
            un.disabled = tot === 0;
            if (tot > 0) {
                un.innerHTML = `<i class="fas fa-save" style="font-size: 0.95rem;"></i>`
                    + `<span class="save-btn-bottom" style="display: flex; align-items: center; gap: 4px; line-height: 1;">`
                    + `<span class="save-btn-label" style="font-size: 0.85rem; font-weight: 700;">حفظ</span>`
                    + `<span style="font-size: 0.85rem; font-weight: 700; margin-inline-start: 6px;">(${tot})</span>`
                    + `</span>`;
                un.title = `التغييرات: يوجد ${tot} تعديل غير محفوظ`;
                un.className = 'btn btn-success btn-sm save-btn';
                un.style.opacity = '';
                un.style.cursor = '';
            } else {
                un.innerHTML = `<i class="fas fa-save" style="font-size: 0.95rem; color: var(--text-3);"></i>`
                    + `<span class="save-btn-bottom" style="display: flex; align-items: center; gap: 4px; line-height: 1;">`
                    + `<span class="save-btn-label" style="font-size: 0.85rem; font-weight: 700;">حفظ</span>`
                    + `</span>`;
                un.title = 'التغييرات: لا توجد تعديلات معلقة';
                un.className = 'btn btn-ghost btn-sm save-btn';
                un.style.opacity = '';
                un.style.cursor = '';
            }
        }

        async function submitCoupons() {
            if (!currentClass || changedCouponStudents.size === 0) { showToast('لا توجد تغييرات', 'info'); return; }
            const btn = document.getElementById('submitCoupons');
            if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i>'; }
            const sourceList = isCombinedView ? combinedStudents : students;
            const records = [];
            changedCouponStudents.forEach(id => {
                const s = sourceList.find(s => getStudentId(s) === id);
                if (s) records.push({ studentName: s['الاسم'].trim(), coupons: Math.max(0, (parseInt(s['كوبونات الالتزام'] || 0)) + (parseInt(couponData[id] || 0))) });
            });
            makeApiCall({ action: 'updateCoupons', className: currentClass, couponData: JSON.stringify(records) }, d => {
                if (d.offline) {
                    showToast(d.message || 'الكوبونات محفوظة محلياً وستُرفع عند عودة الإنترنت', 'warning', { dur: 6000 });
                    markCouponsAsOfflineSaved();
                } else {
                    showToast(`تم حفظ كوبونات ${records.length} طفل`, 'success', { dur: 7000, refresh: true });
                    changedCouponStudents.forEach(id => { savedCouponStudents.add(id); });
                    changedCouponStudents.clear(); couponData = {};
                    saveCouponDataForClass(currentClass);
                    const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
                    localStorage.removeItem(`offlineSavedCoupons_${cls}`);
                    localStorage.removeItem(`offlineAccumulatedCoupons_${cls}`);
                    renderAttendanceList(currentClass); updateSaveBtns();
                    _sendSyncCompletePush(records.length, 'coupons');
                    setTimeout(loadData, 1200);
                }
            }, e => showToast('فشل: ' + e, 'error'));
            if (btn) { btn.disabled = false; updateSaveBtns(); }
        }


        function _removeUnsavedEntry(studentId, date) {
            // Remove from changedStudents for that date
            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
            const key = `changedStudents_${cls}_${date}`;
            try {
                let arr = JSON.parse(localStorage.getItem(key) || '[]');
                arr = arr.filter(id => id !== studentId);
                localStorage.setItem(key, JSON.stringify(arr));
                // Also update the local attendance data back to server value
                const localKey = `attendanceData_${cls}_${date}`;
                const local = JSON.parse(localStorage.getItem(localKey) || '{}');
                delete local[studentId];
                localStorage.setItem(localKey, JSON.stringify(local));
            } catch (e) { }
            // If it's the current date, also update in-memory state
            if (date === currentFriday) {
                changedStudents.delete(studentId);
                attendanceData[studentId] = originalAttendanceData[studentId] || 'pending';
                renderAttendanceList(currentClass);
                updateSaveBtns();
            }
            showUnsavedModal(); // refresh modal
        }

        function _removeUnsavedCoupon(studentId) {
            changedCouponStudents.delete(studentId);
            delete couponData[studentId];
            saveCouponDataForClass(currentClass);
            renderAttendanceList(currentClass);
            updateSaveBtns();
            showUnsavedModal();
        }

        function _jumpToDate(date) {
            document.getElementById('unsavedModal').classList.remove('active');
            loadFridayAttendance(date);
        }

        // ── SUBMIT ────────────────────────────────────────────────────
        async function submitAttendance() {
            if (!currentClass || changedStudents.size === 0) { showToast('لا توجد تغييرات للحفظ', 'info'); return; }
            const btn = document.getElementById('submitAttendance');
            if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i>'; }

            let date = currentFriday;
            if (!date) { updateCurrentDateDisplay(); date = currentFriday; }

            if (isCombinedView) {
                // Group changed students by their real class name
                const byClass = {};
                changedStudents.forEach(id => {
                    const s = combinedStudents.find(s => getStudentId(s) === id);
                    if (!s) return;
                    const realClass = s['الفصل'];
                    if (!byClass[realClass]) byClass[realClass] = [];
                    byClass[realClass].push({ studentName: s['الاسم'].trim(), status: attendanceData[id] || 'pending' });
                });

                // Fire one API call per real class
                const classNames = Object.keys(byClass);
                let done = 0, totalSaved = 0;
                classNames.forEach(cn => {
                    const records = byClass[cn];
                    makeApiCall({ action: 'submitAttendance', className: cn, attendanceData: JSON.stringify(records), date }, r => {
                        if (r.offline) {
                            done++;
                            if (done === classNames.length) {
                                showToast(r.message || 'التغييرات محفوظة محلياً وستُرفع عند عودة الإنترنت', 'warning', { dur: 6000 });
                                markAttendanceAsOfflineSaved(date);
                                if (btn) btn.disabled = false;
                                updateSaveBtns();
                            }
                            return;
                        }
                        totalSaved += r.savedCount || 0;
                        done++;
                        if (done === classNames.length) {
                            showToast(`تم حفظ ${totalSaved} طفل`, 'success', { dur: 7000, refresh: true });
                            changedStudents.forEach(id => { savedStudents.add(id); originalAttendanceData[id] = attendanceData[id] || 'pending'; });
                            changedStudents.clear();
                            const groupKey = combinedGroupLabel || currentClass;
                            localStorage.removeItem(`offlineSavedAttendance_${groupKey}_${date}`);
                            renderAttendanceList(currentClass); updateSaveBtns();
                            _sendSyncCompletePush(totalSaved, 'attendance');
                            setTimeout(loadData, 1200);
                        }
                    }, e => { showToast('فشل الحفظ: ' + e, 'error'); if (btn) btn.disabled = false; updateSaveBtns(); });
                });
                return;
            }

            // Normal single-class submit
            const records = [];
            changedStudents.forEach(id => {
                const s = (currentClass === 'الخدام')
                    ? (window.allUnclesData || []).find(u => getStudentId(u) === id)
                    : students.find(s => getStudentId(s) === id);
                if (!s) return;
                const st = attendanceData[id] || 'pending';
                if (currentClass === 'الخدام') {
                    records.push({ uncle_id: s.id, status: st });
                } else {
                    records.push({ studentName: s['الاسم'].trim(), status: st });
                }
            });
            if (!records.length) { if (btn) btn.disabled = false; updateSaveBtns(); return; }

            const actionName = (currentClass === 'الخدام') ? 'submitUncleAttendance' : 'submitAttendance';
            makeApiCall({ action: actionName, className: currentClass, attendanceData: JSON.stringify(records), date }, r => {
                if (r.offline) {
                    showToast(r.message || 'التغييرات محفوظة محلياً وستُرفع عند عودة الإنترنت', 'warning', { dur: 6000 });
                    markAttendanceAsOfflineSaved(date);
                    if (btn) btn.disabled = false;
                    updateSaveBtns();
                    return;
                }
                const successMsg = (currentClass === 'الخدام') ? `تم حفظ حضور ${records.length} خادم` : `تم حفظ ${records.length} طفل`;
                showToast(successMsg, 'success', { dur: 7000, refresh: true });
                changedStudents.forEach(id => { savedStudents.add(id); originalAttendanceData[id] = attendanceData[id] || 'pending'; });
                changedStudents.clear();
                localStorage.removeItem(`changedStudents_${currentClass}_${date}`);
                saveAttendanceDataForClass(currentClass, date);
                localStorage.removeItem(`offlineSavedAttendance_${currentClass}_${date}`);
                updateAbsentData(); renderAttendanceList(currentClass); updateSaveBtns();
                _sendSyncCompletePush(records.length, (currentClass === 'الخدام') ? 'uncle_attendance' : 'attendance');
                setTimeout(loadData, 1200);
            }, e => { showToast('فشل الحفظ: ' + e, 'error'); if (btn) btn.disabled = false; updateSaveBtns(); });
        }
        function saveAllData() {
            const hA = changedStudents.size > 0, hC = changedCouponStudents.size > 0;
            if (!hA && !hC) { showToast('لا توجد تغييرات', 'info'); return; }
            if (hA) submitAttendance();
            if (hC) setTimeout(submitCoupons, hA ? 1500 : 0);
        }

        // ── ABSENT DATA ───────────────────────────────────────────────
        let absentDataStore = {};
        function getAttendanceStatusStudents(status) {
            return sortStudentsForCurrentView(getActiveViewStudents().filter(s => attendanceData[getStudentId(s)] === status));
        }
        function buildAttendanceShareText(status, label, icon) {
            if (!currentClass) return '';
            const rows = getAttendanceStatusStudents(status);
            let txt = `\u202B━━━━━━━━━━━━━━━━━━\n${icon} *قائمة ${label}*\n🏫 ${getActiveViewLabel()}\n👤 ${rows.length} ${label}\n📅 ${currentFriday}\n━━━━━━━━━━━━━━━━━━\n\n`;
            rows.forEach((s, i) => {
                txt += `*${i + 1}.* ${s['الاسم']}\n`;
                if (isCombinedView || currentClass === '__ALL__') txt += `   🏫 ${s['الفصل'] || ''}\n`;
                if (s['رقم التليفون']) txt += `   📱 ${s['رقم التليفون'].replace(/\D/g, '')}\n`;
                if (i < rows.length - 1) txt += '   ─────────────\n';
            });
            return txt + '\n━━━━━━━━━━━━━━━━━━\n\u200F';
        }
        function updateAbsentData() {
            if (!currentClass) return;
            absentDataStore[currentClass] = getAttendanceStatusStudents('absent')
                .map(s => ({ id: getStudentId(s), name: s['الاسم'], phone: s['رقم التليفون'] || '', address: s['العنوان'] || '' }));
        }
        function copyAbsentData(mode = 'phones') {
            if (!currentClass) { showToast('اختر فصلاً أولاً', 'info'); return; }
            const absent = getAttendanceStatusStudents('absent');
            if (!absent.length) { showToast('لا يوجد غائبون', 'info'); return; }
            const txt = buildAbsentMessageText(mode);
            if (!txt) return;
            copyToClipboard(txt); showToast(`تم نسخ ${absent.length} غائب`, 'success');
        }
        function copyAttendedData() {
            if (!currentClass) { showToast('اختر فصلاً أولاً', 'info'); return; }
            const attended = getAttendanceStatusStudents('present');
            if (!attended.length) { showToast('لا يوجد حاضرون', 'info'); return; }
            copyToClipboard(buildAttendanceShareText('present', 'الحاضرين', '✅'));
            showToast(`تم نسخ ${attended.length} حاضر`, 'success');
        }

        function redirectToKidProfile() {
            if (!currentStudentForEdit) return;
            const id = getStudentDbId(currentStudentForEdit);
            if (!id) return;
            const url = `${window.location.origin}/user/profile/?id=${encodeURIComponent(id)}`;
            window.open(url, '_blank');
        }

        // ── GUEST DETAILS ─────────────────────────────────────────────
        function buildGuestDetails(g) {
            const gender = (g.gender === 'female' || g['النوع'] === 'female') ? 'female' : 'male';
            const imageUrl = g.image_url || g['صورة'] || '';
            const img = imageUrl
                ? `<div class="detail-avatar-wrap"><img src="${window.photoUrl(imageUrl)}" class="detail-avatar" onclick="showImageModal('${escStr(imageUrl)}')" onerror="this.style.display='none';var el=document.querySelector('.detail-avatar-fallback');if(el)el.style.display='flex'"><div class="detail-student-name">${escStr(g.name || '')}</div><div class="detail-student-class">زائر</div></div>`
                : `<div class="detail-avatar-wrap"><div class="detail-avatar-fallback ${gender}"><i class="fas fa-user-tag"></i></div><div class="detail-student-name">${escStr(g.name || '')}</div><div class="detail-student-class">زائر</div></div>`;

            let rowsList = [
                ['معرّف الزائر (ID)', String(g.id || g.guest_id || ''), 'blue', 'fa-fingerprint', String(g.id || g.guest_id || '')],
                ['الاسم الكامل', g.name || '---', 'blue', 'fa-id-card', g.name || '---'],
                ['النوع', formatGenderLabel(g.gender || g['النوع']), 'purple', 'fa-venus-mars', formatGenderLabel(g.gender || g['النوع'])],
                ['رقم التليفون', g.phone || '---', 'green', 'fa-phone', g.phone || '---'],
                ['اسم ولي الأمر', g.guardian_name || '---', 'green', 'fa-user-friends', g.guardian_name || '---'],
                ['ملاحظات', g.notes || '---', 'red', 'fa-comment-alt', g.notes || '---']
            ];

            let rowHtml = rowsList.map(item => {
                const label = item[0];
                const val = item[1];
                const color = item[2];
                const icon = item[3];
                const rawVal = item[4];
                const isPhone = label.includes('تليفون') || label.includes('Phone') || label.includes('الهاتف');
                const viewCallIcon = isPhone && rawVal && rawVal !== '---'
                    ? `<a href="tel:${escHtml(rawVal)}" class="btn btn-ghost phone-call-btn" style="color:var(--brand);margin-right:auto;margin-left:8px;"><i class="fas fa-phone-alt"></i></a>`
                    : '';
                return `
                    <div class="detail-row">
                        <div class="detail-icon ${color}"><i class="fas ${icon}"></i></div>
                        <div class="detail-label">${escHtml(label)}</div>
                        <div class="detail-val copy-holdable" data-copy-text="${escAttr(rawVal || val)}">${val}</div>
                        ${viewCallIcon}
                    </div>
                `;
            }).join('');

            const content = `
                <div class="student-details-scrollable">
                    ${img}
                    <div style="padding:16px;">
                        ${rowHtml}
                    </div>
                </div>
            `;
            document.getElementById('studentDetails').innerHTML = content;
        }

        // ── STUDENT DETAILS ───────────────────────────────────────────
        function showStudentDetails(name) {
            const s = (currentClass === 'الخدام')
                ? (window.allUnclesData || []).find(u => u['الاسم'] === name)
                : (currentClass === 'الزوار'
                    ? (window.allGuestsData || []).find(g => g['الاسم'] === name)
                    : (isCombinedView
                        ? (combinedStudents.find(s => s['الاسم'] === name) || students.find(s => s['الاسم'] === name))
                        : students.find(s => s['الاسم'] === name)));
            if (!s) { showToast('لم يتم العثور على الشخص', 'error'); return; }
            currentStudentForEdit = s;
            document.getElementById('studentModalTitle').textContent = s._isUncle ? 'معلومات الخادم: ' + name : (s._isGuest ? 'معلومات الزائر: ' + name : 'معلومات: ' + name);
            const gender = (s['النوع'] === 'female' || s['gender'] === 'female') ? 'female' : 'male';
            // Basic avatar + header (kept from local cache)
            const detailNameStr = (s['الاسم'] || '') + (s._isGuest ? ' <span class="guest-badge" style="font-size:0.65rem; background:#f59e0b; color:#fff; padding:2px 6px; border-radius:4px; margin-right:4px; vertical-align:middle; display:inline-block;">زائر</span>' : '');
            const img = s['صورة']
                ? `<div class="detail-avatar-wrap"><img src="${window.photoUrl(s['صورة'])}" class="detail-avatar" onclick="showImageModal('${s['صورة']}')" onerror="this.style.display='none';var el=document.querySelector('.detail-avatar-fallback');if(el)el.style.display='flex'"><div class="detail-student-name">${detailNameStr}</div><div class="detail-student-class">${s['الفصل'] || ''}</div></div>`
                : `<div class="detail-avatar-wrap"><div class="detail-avatar-fallback ${gender}"><i class="fas fa-user${s._isGuest ? '-tag' : ''}"></i></div><div class="detail-student-name">${detailNameStr}</div><div class="detail-student-class">${s['الفصل'] || ''}</div></div>`;

            // Reset edit/delete buttons visibility to default
            const editBtn = document.getElementById('editStudentBtn');
            const deleteBtn = document.getElementById('deleteStudentBtn');
            const viewProfileBtn = document.getElementById('viewProfileBtn');
            if (editBtn) editBtn.style.display = '';
            if (deleteBtn) deleteBtn.style.display = '';
            const dbId = getStudentDbId(s);
            const isLegacyGuest = s._isGuest && !dbId;
            if (viewProfileBtn) viewProfileBtn.style.display = (s._isUncle || isLegacyGuest) ? 'none' : '';

            if (s._isUncle) {
                if (editBtn) editBtn.style.display = '';
                if (deleteBtn) deleteBtn.style.display = '';

                document.getElementById('studentDetails').innerHTML = img + '<div style="padding:14px;text-align:center;color:var(--text-3)">جارٍ التحميل…</div>';
                document.getElementById('studentModal').classList.add('active');
                stopAutoRefresh();
                const full = (window.allUnclesData || []).find(u => u.id === s.id) || s;
                currentStudentForEdit = full;
                buildUncleDetailsFromProfile(full);
                return;
            }

            if (s._isGuest && !dbId) {
                if (editBtn) editBtn.style.display = '';
                if (deleteBtn) deleteBtn.style.display = '';

                document.getElementById('studentDetails').innerHTML = img + '<div style="padding:14px;text-align:center;color:var(--text-3)">جارٍ التحميل…</div>';
                document.getElementById('studentModal').classList.add('active');
                stopAutoRefresh();
                buildGuestDetails(s);
                return;
            }

            // Show a loading stub while we fetch full profile (to get trip_points)
            document.getElementById('studentDetails').innerHTML = img + '<div style="padding:14px;text-align:center;color:var(--text-3)">جارٍ التحميل…</div>';
            document.getElementById('studentModal').classList.add('active');
            stopAutoRefresh();

            // Fetch full student profile (includes trip_points)
            (async function () {
                try {
                    const fd = new FormData(); fd.append('action', 'getStudentProfile'); fd.append('studentId', getStudentDbId(s));
                    const resp = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(r => r.json()).catch(() => ({ success: false }));
                    if (!resp.success || !resp.student) {
                        // fallback to cached details
                        buildStudentDetailsFromCache(s);
                        return;
                    }
                    const full = resp.student;
                    currentStudentForEdit = full;
                    buildStudentDetailsFromProfile(full);
                } catch (e) {
                    buildStudentDetailsFromCache(s);
                }
            })();
        }

        function getStudentGender(s) {
            return (s && (s['النوع'] === 'female' || s['gender'] === 'female')) ? 'female' : 'male';
        }

        function formatGenderLabel(genderOrStudent) {
            const g = (typeof genderOrStudent === 'string')
                ? genderOrStudent
                : getStudentGender(genderOrStudent);
            return (g === 'female' || g === 'أنثى') ? 'بنت' : 'ولد';
        }

        function getStudentDbId(student) {
            if (!student) return 0;
            return parseInt(student._studentId || student.student_id || student.studentId || student['معرف'] || student['id_student'] || student.id || 0) || 0;
        }

        function parseStudentCustomInfo(student) {
            if (!student) return {};
            if (student._customInfo && typeof student._customInfo === 'object') return student._customInfo;
            const raw = student['معلومات إضافية'] ?? student.custom_info ?? student['custom_info'] ?? '';
            if (!raw) return {};
            if (typeof raw === 'object') return raw;
            try {
                const parsed = JSON.parse(raw);
                return parsed && typeof parsed === 'object' ? parsed : {};
            } catch (e) {
                return {};
            }
        }

        function getStudentDisplayName(student) {
            return (student && (student['الاسم'] || student.name)) || '---';
        }

        function getStudentClassName(student) {
            return (student && (student['الفصل'] || student.class)) || '---';
        }

        function getSiblingWordForms(student) {
            const female = getStudentGender(student) === 'female';
            return {
                singular: female ? 'أخت' : 'أخ',
                plural: female ? 'الأخوات' : 'الإخوات',
                panelLabel: female ? 'الأخوات المرتبطات' : 'الإخوات المرتبطون',
                actionLabel: 'إضافة أخت أو أخ',
                searchLabel: 'ابحث عن أخت أو أخ',
                modalTitle: 'إضافة أخت أو أخ',
                successLabel: 'تمت الإضافة بنجاح',
            };
        }

        function getStudentTextValue(student, info, keys) {
            for (const key of keys) {
                const value = String((student && student[key]) || (info && info[key]) || '').trim();
                if (value) return value;
            }
            return '';
        }

        function getSecondNamePart(value) {
            const text = String(value || '').trim();
            if (!text) return '';
            const parts = text.split(/\s+/).filter(Boolean);
            return parts.length >= 2 ? parts[1] : parts[0] || '';
        }

        function getNameFamilyPart(student) {
            return getSecondNamePart(getStudentDisplayName(student));
        }

        function buildSiblingMiniAvatar(student) {
            const gender = getStudentGender(student);
            const photo = (student && (student['صورة'] || student.photo || student.photo_url)) || '';
            const photoSrc = photo && window.photoUrl ? window.photoUrl(photo) : photo;
            const avatar = photoSrc
                ? `<img src="${escHtml(photoSrc)}" alt="" class="sibling-mini-avatar" onerror="this.style.display='none';var n=this.nextElementSibling;if(n)n.style.display='flex'">`
                : '';
            return avatar + `<div class="sibling-mini-avatar-fallback ${gender}" ${photoSrc ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;
        }

        function getFatherFromDisplayName(displayName) {
            const text = String(displayName || '').trim();
            if (!text) return '';
            const parts = text.split(/\s+/).filter(Boolean);
            if (parts.length >= 2) {
                const first = parts[0];
                if ((first === 'عبد' || first === 'ابو' || first === 'أبو' || first === 'ام' || first === 'أم') && parts.length >= 3) {
                    return parts.slice(2).join(' ');
                }
                return parts.slice(1).join(' ');
            }
            return parts[0] || '';
        }

        function getPhoneticRepresentations(word) {
            if (!word) return [];
            const normalized = normalizeArabic(word);
            const francoConverted = francoToArabic(word);
            const reps = new Set();

            reps.add(normalized);

            const lat = arabicToLatin(normalized);
            if (lat) {
                reps.add(phoneticClean(lat));
            }

            if (francoConverted) {
                const normFranco = normalizeArabic(francoConverted);
                reps.add(normFranco);
                const latFranco = arabicToLatin(normFranco);
                if (latFranco) {
                    reps.add(phoneticClean(latFranco));
                }
            }

            reps.add(phoneticClean(word));
            return Array.from(reps).filter(Boolean);
        }

        function wordsMatch(w1, w2) {
            const reps1 = getPhoneticRepresentations(w1);
            const reps2 = getPhoneticRepresentations(w2);
            return reps1.some(r => reps2.includes(r));
        }

        function areFatherNamesMatching(f1, f2) {
            f1 = String(f1 || '').trim();
            f2 = String(f2 || '').trim();
            if (!f1 || !f2) return false;

            const words1 = f1.split(/\s+/).filter(Boolean);
            const words2 = f2.split(/\s+/).filter(Boolean);
            if (words1.length === 0 || words2.length === 0) return false;

            const minLength = Math.min(words1.length, words2.length);
            for (let i = 0; i < minLength; i++) {
                if (!wordsMatch(words1[i], words2[i])) {
                    return false;
                }
            }
            return true;
        }

        function getSiblingSuggestion(current, target) {
            const currentInfo = parseStudentCustomInfo(current);
            const targetInfo = parseStudentCustomInfo(target);
            const currentValues = {
                phone: getStudentTextValue(current, currentInfo, ['رقم التليفون', 'phone', 'تليفون', 'mobile']),
                address: getStudentTextValue(current, currentInfo, ['العنوان', 'address']),
                guardian: getStudentTextValue(current, currentInfo, ['guardian_name', 'parent_name', 'mother_name', 'اسم ولي الأمر', 'ولي الأمر']),
                father: getStudentTextValue(current, currentInfo, ['father_name', 'اسم الأب', 'اسم الاب']),
                nameFamilyPart: getNameFamilyPart(current),
            };
            const targetValues = {
                phone: getStudentTextValue(target, targetInfo, ['رقم التليفون', 'phone', 'تليفون', 'mobile']),
                address: getStudentTextValue(target, targetInfo, ['العنوان', 'address']),
                guardian: getStudentTextValue(target, targetInfo, ['guardian_name', 'parent_name', 'mother_name', 'اسم ولي الأمر', 'ولي الأمر']),
                father: getStudentTextValue(target, targetInfo, ['father_name', 'اسم الأب', 'اسم الاب']),
                nameFamilyPart: getNameFamilyPart(target),
            };

            const currentFather = currentValues.father || getFatherFromDisplayName(getStudentDisplayName(current));
            const targetFather = targetValues.father || getFatherFromDisplayName(getStudentDisplayName(target));

            if (!areFatherNamesMatching(currentFather, targetFather)) {
                return null;
            }

            const norm = value => (window.normalizeArabic ? normalizeArabic(value) : String(value || '').toLowerCase().trim());
            const checks = [
                { basis: 'shared_phone', label: 'رقم تليفون مشترك', detail: 'الرقم متطابق في الملفين', ok: currentValues.phone && targetValues.phone && norm(currentValues.phone) === norm(targetValues.phone) },
                { basis: 'shared_address', label: 'عنوان مشترك', detail: 'العنوان متطابق في الملفين', ok: currentValues.address && targetValues.address && norm(currentValues.address) === norm(targetValues.address) },
                { basis: 'shared_guardian', label: 'اسم ولي الأمر مشترك', detail: 'اسم ولي الأمر متطابق', ok: currentValues.guardian && targetValues.guardian && norm(currentValues.guardian) === norm(targetValues.guardian), strength: 'strong' },
                { basis: 'shared_father', label: 'اسم الأب متطابق', detail: 'اسم الأب متطابق في الملفين', ok: true, strength: 'weak' },
            ].filter(x => x.ok);

            if (!checks.length) return null;
            return {
                basis: checks[0].basis,
                label: checks.map(x => x.label).join('، '),
                detail: checks.map(x => x.detail).join('، '),
                strength: checks.some(x => x.strength === 'weak' && checks.length === 1) ? 'weak' : 'strong',
            };
        }

        function getSiblingGroupInfo(student) {
            if (student._siblingGroup && typeof student._siblingGroup === 'object') {
                return student._siblingGroup;
            }
            if (student._siblingGroupId) {
                return { id: student._siblingGroupId, status: 'approved' };
            }
            const info = parseStudentCustomInfo(student);
            return info.sibling_group && typeof info.sibling_group === 'object' ? info.sibling_group : null;
        }

        function getStudentsForSiblingLookup() {
            return (allStudentsData && allStudentsData.length) ? allStudentsData : students;
        }

        function getSiblingMembersByGroupId(groupId, excludeId = 0) {
            if (!groupId) return [];
            const sid = parseInt(excludeId, 10) || 0;
            return getStudentsForSiblingLookup().filter(s => {
                const id = getStudentDbId(s);
                if (!id || id === sid) return false;
                const group = getSiblingGroupInfo(s);
                return group && group.id === groupId;
            });
        }

        function formatSiblingDate(value) {
            if (!value) return '';
            const d = new Date(value);
            if (isNaN(d.getTime())) return String(value);
            try {
                return d.toLocaleString('ar-EG', {
                    year: 'numeric',
                    month: 'short',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit'
                });
            } catch (e) {
                return d.toLocaleString();
            }
        }

        function inferSiblingBasis(student, members) {
            const all = [student, ...(members || [])].filter(Boolean);
            if (all.length < 2) return 'manual';
            const pick = (keys) => {
                const vals = all.map(s => {
                    const info = parseStudentCustomInfo(s);
                    for (const key of keys) {
                        const v = (s[key] || info[key] || '').toString().trim();
                        if (v) return v;
                    }
                    return '';
                }).filter(Boolean);
                if (!vals.length) return '';
                const first = vals[0].toLowerCase();
                return vals.every(v => v.toLowerCase() === first) ? vals[0] : '';
            };
            const reasons = [];
            if (pick(['رقم التليفون', 'phone', 'emergency_phone'])) reasons.push('رقم تليفون مشترك');
            if (pick(['العنوان', 'address'])) reasons.push('عنوان مشترك');
            if (pick(['guardian_name', 'father_name', 'parent_name', 'mother_name'])) reasons.push('اسم ولي الأمر مشترك');
            if (pick(['معلومات إضافية', 'custom_info'])) reasons.push('معلومات إضافية متطابقة');
            const className = pick(['الفصل', 'class']);
            if (className && reasons.length === 0) reasons.push('نفس الفصل');
            return reasons.length ? reasons.join('، ') : 'ربط يدوي';
        }

        function buildSiblingPanel(student) {
            const studentId = getStudentDbId(student);
            const words = getSiblingWordForms(student);
            const custom = parseStudentCustomInfo(student);
            const group = custom.sibling_group && typeof custom.sibling_group === 'object' ? custom.sibling_group : null;
            const members = group && group.id ? getSiblingMembersByGroupId(group.id, studentId) : [];
            const visibleMembers = members.slice(0, 6);
            const groupId = group?.id;

            const membersHtml = visibleMembers.length
                ? visibleMembers.map(m => {
                    const mId = getStudentDbId(m);
                    const mGender = getStudentGender(m);
                    const icon = mGender === 'female' ? 'fa-user-circle' : 'fa-user-circle';
                    return `<div class="sibling-item">
                        <div class="sibling-item-main" onclick="showStudentDetails('${escJs(getStudentDisplayName(m))}')">
                            ${buildSiblingMiniAvatar(m)}
                            <div class="sibling-item-info">
                                <span class="sibling-item-name">${escHtml(getStudentDisplayName(m))}</span>
                                <span class="sibling-item-class"><i class="fas fa-chalkboard-user"></i> ${escHtml(getStudentClassName(m))}</span>
                            </div>
                        </div>
                        <button type="button" class="sibling-unlink-btn" onclick="unlinkSibling(${studentId || 0}, ${mId || 0}, '${escJs(groupId || '')}')" title="فك الارتباط"><i class="fas fa-trash-can"></i></button>
                    </div>`;
                }).join('')
                : '';

            const studentIdJs = JSON.stringify(studentId || 0);
            return `
                <div class="sibling-panel">
                    <div class="sibling-panel-head">
                        <div>
                            <div class="sibling-panel-title">${escHtml(words.panelLabel)}</div>
                        </div>
                        <button type="button" class="btn btn-ghost sibling-link-btn" title="فتح الاقتراحات وإضافة أخت/أخ" onclick="openSiblingLinkModal(${studentIdJs})"><i class="fas fa-link"></i> <i class="fas fa-plus"></i></button>
                    </div>
                    ${membersHtml ? `<div class="sibling-list">${membersHtml}</div>` : ''}
                </div>
            `;
        }

        let _siblingLinkStudentId = 0;

        function getSiblingSearchText(student) {
            const info = parseStudentCustomInfo(student);
            return [
                getStudentDisplayName(student),
                getStudentClassName(student),
                student['رقم التليفون'] || student.phone || '',
                student['العنوان'] || student.address || '',
                info.guardian_name || '',
                info.father_name || '',
                info.parent_name || '',
                info.mother_name || '',
                JSON.stringify(info || {})
            ].join(' ').toLowerCase();
        }

        function openSiblingLinkModal(studentId = 0) {
            const sid = parseInt(studentId, 10) || getStudentDbId(currentStudentForEdit);
            if (!sid) {
                showToast('خطأ في بيانات الطفل', 'error');
                return;
            }
            _siblingLinkStudentId = sid;
            const current = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === sid) || currentStudentForEdit;
            const words = getSiblingWordForms(current);
            const modal = document.getElementById('siblingLinkModal');
            const title = document.getElementById('siblingLinkModalTitle');
            const suggestion = document.getElementById('siblingLinkSuggestion');
            const searchLabel = document.getElementById('siblingLinkSearchLabel');
            const search = document.getElementById('siblingLinkSearch');
            if (title) title.textContent = words.modalTitle;
            if (suggestion) suggestion.textContent = 'الاقتراحات ستظهر هنا تلقائيًا عندما تختار طفلًا.';
            if (searchLabel) searchLabel.textContent = words.searchLabel;
            if (search) search.value = '';
            renderSiblingLinkCandidates();
            modal.classList.add('active');
            setTimeout(() => search?.focus(), 50);
        }

        function closeSiblingLinkModal() {
            document.getElementById('siblingLinkModal')?.classList.remove('active');
            _siblingLinkStudentId = 0;
        }

        function renderSiblingLinkCandidates() {
            const list = document.getElementById('siblingLinkCandidates');
            const summary = document.getElementById('siblingLinkSummary');
            const suggestionBox = document.getElementById('siblingLinkSuggestion');
            if (!list || !_siblingLinkStudentId) return;

            const current = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === _siblingLinkStudentId) || currentStudentForEdit;
            const words = getSiblingWordForms(current);
            if (!current) {
                list.innerHTML = '<div class="sibling-empty">تعذر تحميل بيانات الطفل الحالي.</div>';
                return;
            }

            const currentGroup = getSiblingGroupInfo(current);
            const currentMembers = currentGroup?.id ? getSiblingMembersByGroupId(currentGroup.id, _siblingLinkStudentId) : [];
            const q = (document.getElementById('siblingLinkSearch')?.value || '').trim().toLowerCase();
            const data = getStudentsForSiblingLookup()
                .filter(s => getStudentDbId(s) !== _siblingLinkStudentId)
                .filter(s => {
                    if (!q) return true;
                    return getSiblingSearchText(s).includes(q);
                })
                .sort((a, b) => getStudentDisplayName(a).localeCompare(getStudentDisplayName(b), 'ar'));

            if (summary) {
                summary.innerHTML = currentGroup?.id
                    ? `المجموعة الحالية فيها <strong>${currentMembers.length + 1}</strong> ${words.plural}.`
                    : 'اختر طفلًا للربط بهذا الطفل.';
            }

            const preview = data
                .map(s => {
                    const suggestion = getSiblingSuggestion(current, s);
                    if (!suggestion) return '';
                    const id = getStudentDbId(s);
                    const tag = suggestion.strength === 'weak' ? 'اقتراح ضعيف' : 'اقتراح';
                    const gender = getStudentGender(s);
                    const avatar = s['صورة']
                        ? `<img src="${window.photoUrl ? window.photoUrl(s['صورة']) : s['صورة']}" alt="" class="sibling-mini-avatar" onerror="this.style.display='none';var n=this.nextElementSibling;if(n)n.style.display='flex'">`
                        : '';
                    const avatarFallback = `<div class="sibling-mini-avatar-fallback ${gender}" ${s['صورة'] ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;
                    return `<div class="sibling-suggestion-row" onclick="openSiblingComparison(${JSON.stringify(_siblingLinkStudentId)}, ${id})" title="اضغط للمقارنة والتحقق" style="display:flex;align-items:center;gap:12px">
                        <div style="display:flex;align-items:center;gap:8px;flex-shrink:0">
                            ${avatar}${avatarFallback}
                        </div>
                        <div style="flex:1;text-align:right">
                            <span class="sibling-suggestion-name">${escHtml(getStudentDisplayName(s))}</span>
                            <span class="sibling-suggestion-tag">${tag}</span>
                            <span class="sibling-suggestion-text">${escHtml(suggestion.label)} - ${escHtml(suggestion.detail)}</span>
                        </div>
                    </div>`;
                })
                .filter(Boolean)
                .slice(0, 4);
            if (suggestionBox) {
                suggestionBox.innerHTML = preview.length
                    ? `<strong><i class="fas fa-wand-magic-sparkles sibling-suggestion-ai"></i> اقتراحات الربط</strong>${preview.join('')}`
                    : 'لا توجد اقتراحات واضحة الآن. يمكنك الربط يدويًا من القائمة.';
            }

            if (!data.length) {
                list.innerHTML = '<div class="sibling-empty">لا توجد نتائج مطابقة للبحث الحالي.</div>';
                return;
            }

            list.innerHTML = data.map(s => {
                const id = getStudentDbId(s);
                const info = parseStudentCustomInfo(s);
                const guardian = info.guardian_name || info.father_name || info.parent_name || info.mother_name || '';
                const targetGroup = getSiblingGroupInfo(s);
                const alreadyLinked = currentGroup?.id && targetGroup?.id && currentGroup.id === targetGroup.id;
                const suggestion = getSiblingSuggestion(current, s);
                const linkedLabel = alreadyLinked ? 'مرتبط بالفعل' : targetGroup?.id ? 'مرتبط مع مجموعة أخرى' : 'غير مرتبط';
                const phone = s['رقم التليفون'] || s.phone || '';
                const address = s['العنوان'] || s.address || '';
                const gender = getStudentGender(s);
                const avatar = s['صورة']
                    ? `<img src="${window.photoUrl ? window.photoUrl(s['صورة']) : s['صورة']}" alt="" class="sibling-mini-avatar" onerror="this.style.display='none';var n=this.nextElementSibling;if(n)n.style.display='flex'">`
                    : '';
                const avatarFallback = `<div class="sibling-mini-avatar-fallback ${gender}" ${s['صورة'] ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;
                return `
                    <div class="sibling-candidate ${alreadyLinked ? 'selected' : ''}">
                        <div class="sibling-item-main">
                            ${avatar}${avatarFallback}
                            <div style="min-width:0;flex:1;">
                                <div style="font-weight:800;color:var(--text);font-size:.86rem">${escHtml(getStudentDisplayName(s))}</div>
                                <div class="sibling-candidate-meta">
                                    <span>${escHtml(getStudentClassName(s))}</span>
                                    ${guardian ? `<span>ولي الأمر: ${escHtml(guardian)}</span>` : ''}
                                    ${phone ? `<span>هاتف: ${escHtml(phone)}</span>` : ''}
                                    ${address ? `<span>العنوان: ${escHtml(address)}</span>` : ''}
                                </div>
                                ${suggestion ? `<div class="sibling-suggestion-inline" style="cursor:pointer" onclick="openSiblingComparison(${JSON.stringify(_siblingLinkStudentId)}, ${id})" title="اضغط للمقارنة والتحقق">${suggestion.strength === 'weak' ? 'اقتراح ضعيف' : 'اقتراح'}: ${escHtml(suggestion.label)} - ${escHtml(suggestion.detail)}</div>` : ''}
                            </div>
                        </div>
                        <div style="display:flex;align-items:center;gap:8px;flex-shrink:0">
                            <span class="sibling-chip gray" style="font-size:.66rem">${linkedLabel}</span>
                            <button type="button" class="btn btn-ghost" style="padding:5px 10px;font-size:.72rem" ${alreadyLinked ? 'disabled' : ''} onclick="openSiblingComparison(${JSON.stringify(_siblingLinkStudentId)}, ${id})"><i class="fas fa-plus"></i> إضافة</button>
                        </div>
                    </div>`;
            }).join('');
        }

        function getAllSiblingSuggestions() {
            const list = getStudentsForSiblingLookup().filter(s => getStudentDbId(s));
            const suggestions = [];
            for (let i = 0; i < list.length; i++) {
                for (let j = i + 1; j < list.length; j++) {
                    const a = list[i];
                    const b = list[j];
                    const aGroup = getSiblingGroupInfo(a);
                    const bGroup = getSiblingGroupInfo(b);
                    if (aGroup?.id && bGroup?.id && aGroup.id === bGroup.id) continue;
                    const suggestion = getSiblingSuggestion(a, b);
                    if (!suggestion) continue;
                    suggestions.push({ a, b, suggestion });
                }
            }
            return suggestions.sort((x, y) => {
                if (x.suggestion.strength !== y.suggestion.strength) return x.suggestion.strength === 'strong' ? -1 : 1;
                return getStudentDisplayName(x.a).localeCompare(getStudentDisplayName(y.a), 'ar');
            });
        }

        function exportSiblingAllSuggestionsAsCSV() {
            const all = getAllSiblingSuggestions();
            if (!all.length) { showToast('لا توجد اقتراحات لتصديرها', 'info'); return; }

            const rows = [['الطفل الأول', 'فصل الأول', 'الطفل الثاني', 'فصل الثاني', 'قوة الاقتراح', 'سبب الربط', 'التفاصيل']];
            all.forEach(item => {
                rows.push([
                    getStudentDisplayName(item.a),
                    getStudentClassName(item.a),
                    getStudentDisplayName(item.b),
                    getStudentClassName(item.b),
                    item.suggestion.strength === 'strong' ? 'قوي' : 'ضعيف',
                    item.suggestion.label,
                    item.suggestion.detail
                ]);
            });

            const csvContent = "\uFEFF" + rows.map(r => r.map(c => `"${String(c || '').replace(/"/g, '""')}"`).join(',')).join("\n");
            const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement("a");
            link.setAttribute("href", url);
            link.setAttribute("download", `اقتراحات_الإخوات_${new Date().toLocaleDateString('ar-EG').replace(/\//g, '-')}.csv`);
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }

        function renderSiblingSuggestionPair(item) {
            const aId = getStudentDbId(item.a);
            const bId = getStudentDbId(item.b);
            const strength = item.suggestion.strength === 'weak' ? 'weak' : 'strong';
            const tag = strength === 'weak' ? 'اقتراح ضعيف' : 'اقتراح قوي';
            return `<div class="sibling-review-card ${strength}" onclick="linkSiblingPair(${aId}, ${bId})" title="اضغط للإضافة">
                <div class="sibling-review-avatars">
                    ${buildSiblingMiniAvatar(item.a)}
                    ${buildSiblingMiniAvatar(item.b)}
                </div>
                <div style="min-width:0;flex:1">
                    <div class="sibling-review-names">${escHtml(getStudentDisplayName(item.a))} + ${escHtml(getStudentDisplayName(item.b))}</div>
                    <div class="sibling-review-meta">${escHtml(getStudentClassName(item.a))} / ${escHtml(getStudentClassName(item.b))} · ${escHtml(item.suggestion.label)} · ${escHtml(item.suggestion.detail)}</div>
                </div>
                <button type="button" class="btn btn-ghost" style="padding:5px 10px;font-size:.72rem" onclick="event.stopPropagation();linkSiblingPair(${aId}, ${bId})"><i class="fas fa-plus"></i> إضافة</button>
                <span class="sibling-chip gray" style="font-size:.66rem">${tag}</span>
            </div>`;
        }

        function renderAllSiblingSuggestionsView() {
            const summary = document.getElementById('siblingSuggestionsSummary');
            const strongBox = document.getElementById('strongSiblingSuggestions');
            const weakBox = document.getElementById('weakSiblingSuggestions');
            if (!strongBox || !weakBox) return;
            const all = getAllSiblingSuggestions();
            const strong = all.filter(x => x.suggestion.strength !== 'weak');
            const weak = all.filter(x => x.suggestion.strength === 'weak');
            if (summary) {
                summary.innerHTML = `<strong>${strong.length}</strong> اقتراح قوي · <strong>${weak.length}</strong> اقتراح ضعيف`;
            }
            strongBox.innerHTML = strong.length
                ? strong.map(renderSiblingSuggestionPair).join('')
                : '<div class="sibling-empty">لا توجد اقتراحات قوية الآن.</div>';
            weakBox.innerHTML = weak.length
                ? weak.map(renderSiblingSuggestionPair).join('')
                : '<div class="sibling-empty">لا توجد اقتراحات ضعيفة الآن.</div>';
        }

        function openSiblingSuggestionsView() {
            renderAllSiblingSuggestionsView();
            document.getElementById('siblingSuggestionsModal')?.classList.add('active');
        }

        function closeSiblingSuggestionsView() {
            document.getElementById('siblingSuggestionsModal')?.classList.remove('active');
        }

        async function linkSiblingPair(currentStudentId, targetStudentId) {
            _siblingLinkStudentId = parseInt(currentStudentId, 10) || 0;
            await linkSiblingToCurrent(targetStudentId);
            renderAllSiblingSuggestionsView();
        }

        async function linkSiblingToCurrent(targetStudentId) {
            const current = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === _siblingLinkStudentId) || currentStudentForEdit;
            const target = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === parseInt(targetStudentId, 10));
            if (!current || !target) {
                showToast('تعذر تحديد الطفل أو الأخ/الأخت المراد ربطه', 'error');
                return;
            }

            const words = getSiblingWordForms(current);

            const currentId = getStudentDbId(current);
            const targetId = getStudentDbId(target);
            if (!currentId || !targetId) {
                showToast('معرفات الطلاب غير مكتملة', 'error');
                return;
            }

            const currentGroup = getSiblingGroupInfo(current);
            const targetGroup = getSiblingGroupInfo(target);
            const currentIds = currentGroup?.id ? getSiblingMembersByGroupId(currentGroup.id, currentId).map(s => getStudentDbId(s)) : [];
            const targetIds = targetGroup?.id ? getSiblingMembersByGroupId(targetGroup.id, targetId).map(s => getStudentDbId(s)) : [];
            const allIds = [...new Set([currentId, targetId, ...currentIds, ...targetIds].filter(Boolean))];
            const groupId = currentGroup?.id || targetGroup?.id || `family_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
            const merged = currentGroup?.id && targetGroup?.id && currentGroup.id !== targetGroup.id;
            if (merged) {
                showToast('سيتم دمج الروابط المرتبطة تلقائيًا', 'info');
            }

            const fd = new FormData();
            fd.append('action', 'saveSiblingGroup');
            fd.append('student_ids', JSON.stringify(allIds));
            fd.append('group_id', groupId);
            fd.append('status', 'approved');
            fd.append('linked_by', localStorage.getItem('uncleName') || '');

            const d = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                .then(r => r.json())
                .catch(() => ({ success: false }));

            if (d.success) {
                showToast(words.successLabel, 'success');
                closeSiblingLinkModal();
                await new Promise(resolve => setTimeout(resolve, 200));
                loadData();
                setTimeout(() => {
                    if (currentStudentForEdit) showStudentDetails(getStudentDisplayName(currentStudentForEdit));
                }, 500);
            } else {
                showToast(d.message || 'فشل في حفظ الربط', 'error');
            }
        }

        async function unlinkSibling(currentStudentId, targetStudentId, groupId) {
            const cid = parseInt(currentStudentId, 10) || 0;
            const tid = parseInt(targetStudentId, 10) || 0;
            if (!cid || !tid || !groupId) {
                showToast('بيانات غير صحيحة', 'error');
                return;
            }

            if (!confirm(`هل تريد فعلًا فك الارتباط بين هذا الطفل وأخيه/أختها؟`)) {
                return;
            }

            const current = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === cid);
            const groupMembers = getSiblingMembersByGroupId(groupId, 0);
            const allGroupIds = [cid, ...groupMembers.map(m => getStudentDbId(m))].filter(Boolean);

            // If the sibling group only has 2 members, unlinking them means disbanding the group (clear both)
            // Otherwise, we only clear the target sibling from the group
            const idsToClear = (allGroupIds.length <= 2) ? allGroupIds : [tid];

            const fd = new FormData();
            fd.append('action', 'saveSiblingGroup');
            fd.append('op', 'clear');
            fd.append('student_ids', JSON.stringify(idsToClear));

            const d = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                .then(r => r.json())
                .catch(() => ({ success: false }));

            if (d.success) {
                showToast('تم فك الارتباط بنجاح', 'success');
                await new Promise(resolve => setTimeout(resolve, 200));
                loadData();
                setTimeout(() => {
                    if (current) showStudentDetails(getStudentDisplayName(current));
                }, 500);
            } else {
                showToast(d.message || 'فشل في فك الارتباط', 'error');
            }
        }

        let _siblingComparisonPair = { current: null, target: null };

        function openSiblingComparison(currentStudentId, targetStudentId) {
            const cid = parseInt(currentStudentId, 10) || 0;
            const tid = parseInt(targetStudentId, 10) || 0;
            if (!cid || !tid) return;

            const current = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === cid);
            const target = getStudentsForSiblingLookup().find(s => getStudentDbId(s) === tid);

            if (!current || !target) {
                showToast('تعذر تحميل بيانات الطلاب', 'error');
                return;
            }

            _siblingComparisonPair = { current, target };
            showSiblingComparison();
            document.getElementById('siblingComparisonModal')?.classList.add('active');
        }

        function closeSiblingComparison() {
            document.getElementById('siblingComparisonModal')?.classList.remove('active');
            _siblingComparisonPair = { current: null, target: null };
        }

        function buildComparisonField(current, target, keys, label) {
            const getValue = (s, keys) => {
                const info = parseStudentCustomInfo(s);
                for (const key of keys) {
                    const v = (s[key] || info[key] || '').toString().trim();
                    if (v) return v;
                }
                return '';
            };
            const currentVal = getValue(current, keys);
            const targetVal = getValue(target, keys);
            const matches = currentVal && targetVal && (window.normalizeArabic ? normalizeArabic(currentVal) : currentVal.toLowerCase()) === (window.normalizeArabic ? normalizeArabic(targetVal) : targetVal.toLowerCase());

            return `
                <div style="padding-bottom:8px">
                    <div style="font-size:.75rem;color:var(--text-3);font-weight:600;margin-bottom:4px">${label}</div>
                    <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:.75rem">
                        <div style="padding:6px;background:var(--surface-3);border-radius:var(--r-sm);text-align:right;color:var(--text)">${escHtml(currentVal || '---')}</div>
                        <div style="padding:6px;background:var(--surface-3);border-radius:var(--r-sm);text-align:right;color:var(--text)">${escHtml(targetVal || '---')}${matches ? '<span class="sibling-comparison-match"><i class="fas fa-check"></i> متطابق</span>' : ''}</div>
                    </div>
                </div>
            `;
        }

        function showSiblingComparison() {
            const { current, target } = _siblingComparisonPair;
            if (!current || !target) return;

            const content = document.getElementById('siblingComparisonContent');
            if (!content) return;

            const currentGender = getStudentGender(current);
            const targetGender = getStudentGender(target);

            const currentAvatar = current['صورة']
                ? `<img src="${window.photoUrl ? window.photoUrl(current['صورة']) : current['صورة']}" alt="" class="sibling-comparison-avatar" onerror="this.style.display='none';this.nextElementSibling?.style.setProperty('display','flex')">`
                : '';
            const currentAvatarFallback = `<div class="sibling-comparison-avatar-fallback ${currentGender}" ${current['صورة'] ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;

            const targetAvatar = target['صورة']
                ? `<img src="${window.photoUrl ? window.photoUrl(target['صورة']) : target['صورة']}" alt="" class="sibling-comparison-avatar" onerror="this.style.display='none';this.nextElementSibling?.style.setProperty('display','flex')">`
                : '';
            const targetAvatarFallback = `<div class="sibling-comparison-avatar-fallback ${targetGender}" ${target['صورة'] ? 'style="display:none"' : ''}><i class="fas fa-user"></i></div>`;

            const suggestion = getSiblingSuggestion(current, target);

            const currentCard = `
                <div class="sibling-comparison-card">
                    <div class="sibling-comparison-header">
                        <div style="display:flex;gap:8px">${currentAvatar}${currentAvatarFallback}</div>
                        <div>
                            <div style="font-weight:800;color:var(--text);font-size:.86rem">${escHtml(getStudentDisplayName(current))}</div>
                            <div style="font-size:.7rem;color:var(--text-3)">${escHtml(getStudentClassName(current))}</div>
                        </div>
                    </div>
                    ${buildComparisonField(current, target, ['الاسم', 'name'], 'الاسم')}
                    ${buildComparisonField(current, target, ['النوع', 'gender'], 'النوع')}
                    ${buildComparisonField(current, target, ['الفصل', 'class'], 'الفصل')}
                    ${buildComparisonField(current, target, ['رقم التليفون', 'phone', 'emergency_phone'], 'رقم التليفون')}
                    ${buildComparisonField(current, target, ['العنوان', 'address'], 'العنوان')}
                    ${buildComparisonField(current, target, ['guardian_name', 'father_name', 'parent_name', 'mother_name', 'اسم ولي الأمر'], 'ولي الأمر')}
                </div>
            `;

            const targetCard = `
                <div class="sibling-comparison-card">
                    <div class="sibling-comparison-header">
                        <div style="display:flex;gap:8px">${targetAvatar}${targetAvatarFallback}</div>
                        <div>
                            <div style="font-weight:800;color:var(--text);font-size:.86rem">${escHtml(getStudentDisplayName(target))}</div>
                            <div style="font-size:.7rem;color:var(--text-3)">${escHtml(getStudentClassName(target))}</div>
                        </div>
                    </div>
                    ${buildComparisonField(target, current, ['الاسم', 'name'], 'الاسم')}
                    ${buildComparisonField(target, current, ['النوع', 'gender'], 'النوع')}
                    ${buildComparisonField(target, current, ['الفصل', 'class'], 'الفصل')}
                    ${buildComparisonField(target, current, ['رقم التليفون', 'phone', 'emergency_phone'], 'رقم التليفون')}
                    ${buildComparisonField(target, current, ['العنوان', 'address'], 'العنوان')}
                    ${buildComparisonField(target, current, ['guardian_name', 'father_name', 'parent_name', 'mother_name', 'اسم ولي الأمر'], 'ولي الأمر')}
                </div>
            `;

            content.innerHTML = currentCard + targetCard;
        }

        async function confirmSiblingComparison() {
            const { current, target } = _siblingComparisonPair;
            if (!current || !target) return;

            const cid = getStudentDbId(current);
            const tid = getStudentDbId(target);
            closeSiblingComparison();
            await linkSiblingToCurrent(tid);
        }

        function buildStudentDetailsFromCache(s) {
            const genderLabel = formatGenderLabel(s);
            const siblingHtml = buildSiblingPanel(s);
            let rowsList = [
                ['معرّف الطفل (ID)', String(getStudentDbId(s)), 'blue', 'fa-fingerprint', String(getStudentDbId(s))],
                ['الاسم الكامل', s['الاسم'] || '---', 'blue', 'fa-id-card', s['الاسم'] || '---'],
                ['النوع', genderLabel, 'purple', 'fa-venus-mars', genderLabel],
                ['الفصل', s['الفصل'] || '---', 'purple', 'fa-chalkboard-teacher', s['الفصل'] || '---'],
                ['العنوان', s['العنوان'] || '---', 'orange', 'fa-map-marker-alt', s['العنوان'] || '---'],
                ['رقم التليفون', s['رقم التليفون'] || '---', 'green', 'fa-phone', s['رقم التليفون'] || '---'],
            ];
            if (s['تليفون الطوارئ']) {
                rowsList.push(['تليفون الطوارئ', s['تليفون الطوارئ'], 'green', 'fa-phone-alt', s['تليفون الطوارئ']]);
            }
            if (s['ملاحظات طبية']) {
                rowsList.push(['ملاحظات طبية', s['ملاحظات طبية'], 'red', 'fa-notes-medical', s['ملاحظات طبية']]);
            }
            rowsList.push(
                ['تاريخ الميلاد', s['عيد الميلاد'] || '---', 'pink', 'fa-birthday-cake', s['عيد الميلاد'] || '---'],
                ['الكوبونات', (s['كوبونات'] || '0') + ' <i class="fas fa-star" style="color:var(--coupon);font-size:.8rem"></i>', 'purple', 'fa-star', String(s['كوبونات'] || '0')]
            );

            let rows = rowsList.map(([l, v, color, icon, copyVal]) => `
        <div class="detail-row">
            <div class="detail-icon ${color}"><i class="fas ${icon}"></i></div>
            <div class="detail-label">${l}</div>
            <div class="detail-val copy-holdable" data-copy-text="${escAttr(copyVal || v)}">${v}</div>
        </div>`).join('');

            // Append custom fields
            const info = parseStudentCustomInfo(s);
            if (churchCustomFields && churchCustomFields.length) {
                churchCustomFields.forEach((cf, idx) => {
                    const key = 'field_' + idx;
                    const val = info[key] || info['field_' + idx] || (idx === 0 ? (info.value || '') : '');
                    if (val) {
                        rows += `
        <div class="detail-row">
            <div class="detail-icon orange"><i class="fas ${cf.icon || 'fa-tag'}"></i></div>
            <div class="detail-label">${cf.name}</div>
            <div class="detail-val copy-holdable" data-copy-text="${escAttr(val)}">${val}</div>
        </div>`;
                    }
                });
            }

            const gender = getStudentGender(s);
            const detailNameStr = escStr(s['الاسم'] || '') + (s._isGuest ? ' <span class="guest-badge" style="font-size:0.65rem; background:#f59e0b; color:#fff; padding:2px 6px; border-radius:4px; margin-right:4px; vertical-align:middle; display:inline-block;">زائر</span>' : '');
            const avatar = s['صورة']
                ? `<div class="detail-avatar-wrap" onclick="showImageModal('${escJs(s['صورة'])}', event)"> <img src="${s['صورة']}" class="detail-avatar"><div class="detail-student-name">${detailNameStr}</div></div>`
                : `<div class="detail-avatar-wrap"><div class="detail-avatar-fallback ${gender}"><i class="fas fa-user"></i></div><div class="detail-student-name">${detailNameStr}</div></div>`;

            // Render Notes Section for Cache (Offline fallback)
            const notesList = info._notes || [];
            let notesHtml = `
            <div class="student-notes-section" style="margin-top:16px; border-top:1px solid var(--border); padding-top:16px;">
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:12px;">
                    <h4 style="font-size:0.95rem; font-weight:700; color:var(--primary); margin:0; display:flex; align-items:center; gap:6px;">
                        <i class="fas fa-sticky-note"></i> الملاحظات (${notesList.length})
                    </h4>
                    <button type="button" class="btn btn-ghost sibling-link-btn" title="إضافة ملاحظة" onclick="toggleAddNoteArea()"><i class="fas fa-sticky-note"></i> <i class="fas fa-plus"></i></button>
                </div>
                
                <!-- Add Note Area (Hidden by default) -->
                <div id="addNoteArea" class="glass-card" style="display:none; margin-bottom:14px; padding:12px; border: 1px solid var(--border-solid); border-radius:10px;">
                    <div class="form-group" style="margin-bottom:8px;">
                        <label class="form-label" style="font-size:0.75rem; font-weight:700; margin-bottom:4px;">نوع الملاحظة (العنوان)</label>
                        <div class="note-suggestions-pills" style="display:flex; gap:6px; flex-wrap:wrap; margin-bottom:6px; direction:rtl;">
                            ${['زيارة منزلية', 'متابعة تلفونية', 'احتياج مالي', 'مستلزمات مدرسية', 'طلب صلاة', 'أخرى'].map(sugg => `
                                <span class="badge" onclick="selectNoteTitleSuggestion('${sugg}')" style="cursor:pointer; font-size:0.68rem; padding:4px 8px; background:rgba(91, 108, 245, 0.08); color:var(--brand); border:1px solid rgba(91, 108, 245, 0.15); font-weight:700;">
                                    ${sugg}
                                </span>
                            `).join('')}
                        </div>
                        <input type="text" id="noteTitleInput" class="form-input" placeholder="اكتب عنوان الملاحظة أو اختر من الاقتراحات..." style="font-size:0.8rem; padding:6px 10px;">
                    </div>
                    <div class="form-group" style="margin-bottom:8px;">
                        <label class="form-label" style="font-size:0.75rem; font-weight:700; margin-bottom:4px;">تفاصيل الملاحظة (الوصف)</label>
                        <textarea id="noteDescInput" class="form-input" rows="3" placeholder="تفاصيل الملاحظة..." style="font-size:0.8rem; padding:6px 10px; font-family:inherit; resize:vertical;"></textarea>
                    </div>
                    <div class="form-group" style="margin-bottom:10px;">
                        <label class="form-label" style="font-size:0.75rem; font-weight:700; margin-bottom:4px;">التاريخ (اختياري)</label>
                        <input type="date" id="noteDateInput" class="form-input" style="font-size:0.8rem; padding:6px 10px;">
                    </div>
                    <div style="display:flex; gap:6px; justify-content:flex-end;">
                        <button class="btn btn-ghost" onclick="toggleAddNoteArea(false)" style="font-size:0.75rem; padding:4px 10px;">إلغاء</button>
                        <button class="btn" onclick="submitStudentNote(${getStudentDbId(s)})" style="font-size:0.75rem; padding:4px 12px; background:var(--brand); color:#fff;">حفظ</button>
                    </div>
                </div>

                <!-- Notes List -->
                <div class="notes-list-wrap" style="display:flex; flex-direction:column; gap:8px;">
                    ${notesList.length === 0 ? '' : notesList.map(note => {
                const noteDateStr = note.date ? new Date(note.date).toLocaleDateString('ar-EG', { year: 'numeric', month: 'short', day: 'numeric' }) : '---';
                return `
                            <div class="glass-card note-item-card" style="padding:10px 12px; border:1px solid var(--border-solid); border-radius:10px; position:relative; direction:rtl; text-align:right;">
                                <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:4px;">
                                    <strong style="font-size:0.82rem; color:var(--text);">${escHtml(note.title)}</strong>
                                    <button onclick="deleteStudentNote(${getStudentDbId(s)}, '${note.id}')" style="background:none; border:none; color:var(--danger); cursor:pointer; font-size:0.8rem; padding:2px;" title="حذف الملاحظة">
                                        <i class="fas fa-trash-alt"></i>
                                    </button>
                                </div>
                                <p style="font-size:0.78rem; color:var(--text-2); margin:0 0 6px 0; line-height:1.4; white-space:pre-wrap;">${escHtml(note.description)}</p>
                                <div style="display:flex; justify-content:space-between; align-items:center; font-size:0.68rem; color:var(--text-3); font-weight:600;">
                                    <span>بواسطة: ${escHtml(note.created_by || 'خادم')}</span>
                                    <span>التاريخ: ${noteDateStr}</span>
                                </div>
                            </div>
                        `;
            }).join('')}
                </div>
            </div>
            `;

            document.getElementById('studentDetails').innerHTML = avatar + rows + siblingHtml + notesHtml;
        }

        function buildStudentDetailsFromProfile(full) {
            const gender = (full.gender === 'female' || full['النوع'] === 'female') ? 'female' : 'male';
            const siblingHtml = buildSiblingPanel(full);
            const showImgClick = full.image_url ? `onclick="showImageModal('${escJs(full.image_url)}', event)"` : '';
            const detailNameStr = escStr(full.name || '') + (full._isGuest ? ' <span class="guest-badge" style="font-size:0.65rem; background:#f59e0b; color:#fff; padding:2px 6px; border-radius:4px; margin-right:4px; vertical-align:middle; display:inline-block;">زائر</span>' : '');
            const img = full.image_url
                ? `<div class="detail-avatar-wrap" ${showImgClick}><img src="${full.image_url}" class="detail-avatar"><div class="detail-student-name">${detailNameStr}</div><div class="detail-student-class">${escStr(full.class || '')}</div></div>`
                : `<div class="detail-avatar-wrap" ${showImgClick}><div class="detail-avatar-fallback ${gender}"><i class="fas fa-user"></i></div><div class="detail-student-name">${detailNameStr}</div><div class="detail-student-class">${escStr(full.class || '')}</div></div>`;

            let rowsList = [
                ['معرّف الطفل (ID)', String(full.id), 'blue', 'fa-fingerprint', String(full.id)],
                ['الاسم الكامل', full.name || '---', 'blue', 'fa-id-card', full.name || '---'],
                ['النوع', formatGenderLabel(full.gender || full['النوع']), 'purple', 'fa-venus-mars', formatGenderLabel(full.gender || full['النوع'])],
                ['الفصل', full.class || '---', 'purple', 'fa-chalkboard-teacher', full.class || '---'],
                ['العنوان', full.address || '---', 'orange', 'fa-map-marker-alt', full.address || '---'],
                ['رقم التليفون', full.phone || '---', 'green', 'fa-phone', full.phone || '---'],
            ];
            if (full.emergency_phone) {
                rowsList.push(['تليفون الطوارئ', full.emergency_phone, 'green', 'fa-phone-alt', full.emergency_phone]);
            }
            if (full.medical_notes) {
                rowsList.push(['ملاحظات طبية', full.medical_notes, 'red', 'fa-notes-medical', full.medical_notes]);
            }
            rowsList.push(
                ['تاريخ الميلاد', full.birthday || '---', 'pink', 'fa-birthday-cake', full.birthday || '---'],
                ['الكوبونات', (full.coupons || 0) + ' <i class="fas fa-star" style="color:var(--coupon);font-size:.8rem"></i>', 'purple', 'fa-star', String(full.coupons || 0)]
            );

            let rows = rowsList.map(([l, v, color, icon, copyVal]) => `
        <div class="detail-row">
            <div class="detail-icon ${color}"><i class="fas ${icon}"></i></div>
            <div class="detail-label">${l}</div>
            <div class="detail-val copy-holdable" data-copy-text="${escAttr(copyVal || v)}">${v}</div>
        </div>`).join('');

            // Append custom fields
            const info = parseStudentCustomInfo(full);
            if (churchCustomFields && churchCustomFields.length) {
                churchCustomFields.forEach((cf, idx) => {
                    const key = 'field_' + idx;
                    const val = info[key] || info['field_' + idx] || (idx === 0 ? (info.value || '') : '');
                    if (val) {
                        rows += `
        <div class="detail-row">
            <div class="detail-icon orange"><i class="fas ${cf.icon || 'fa-tag'}"></i></div>
            <div class="detail-label">${cf.name}</div>
            <div class="detail-val copy-holdable" data-copy-text="${escAttr(val)}">${val}</div>
        </div>`;
                    }
                });
            }

            // Trip points summary
            let tpList = [];
            if (Array.isArray(full.trip_points_details)) {
                tpList = full.trip_points_details;
            } else {
                let tp = {};
                try { tp = typeof full.trip_points === 'string' ? JSON.parse(full.trip_points || '{}') : (full.trip_points || {}); } catch (e) { tp = {}; }
                tpList = Object.keys(tp).map(k => ({
                    id: parseInt(k, 10),
                    title: `رحلة رقم ${k}`,
                    points: tp[k]
                }));
            }
            let tpHtml = '<div class="detail-row"><div class="detail-icon teal"><i class="fas fa-qrcode"></i></div><div class="detail-label">نقاط الرحلات / المؤتمرات</div><div class="detail-val" style="display:flex;flex-direction:column;gap:6px;width:100%;">';
            if (!tpList.length) tpHtml += 'لا توجد نقاط مسجّلة';
            else tpHtml += tpList.map(item => `
                <div onclick="window.location.href='<?php echo $pathPrefix; ?>/uncle/trip/points/?trip_id=${item.id}&student_id=${full.id}'" 
                     style="display:flex;align-items:center;justify-content:space-between;padding:8px 12px;background:var(--surface-3);border:1px solid var(--border-solid);border-radius:var(--r-sm);cursor:pointer;transition:all 0.2s;" 
                     onmouseover="this.style.background='var(--surface-4)';this.style.borderColor='var(--brand)'" 
                     onmouseout="this.style.background='var(--surface-3)';this.style.borderColor='var(--border-solid)'">
                    <div style="font-weight:700;color:var(--text);font-size:0.82rem;">${escHtml(item.title)}</div>
                    <div style="font-weight:800;color:var(--brand);font-size:0.85rem;display:flex;align-items:center;gap:4px;">
                        ${item.points} <i class="fas fa-star" style="color:var(--coupon);font-size:0.8rem;"></i>
                    </div>
                </div>
            `).join('');
            tpHtml += '</div></div>';

            // Paper Exams section inside modal details
            const paperExamsList = full.paper_exams || [];
            let paperExamsHtml = `
            <div class="student-paper-exams-section" style="margin-top:16px; border-top:1px solid var(--border); padding-top:16px;">
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:12px;">
                    <h4 style="font-size:0.95rem; font-weight:700; color:var(--primary); margin:0; display:flex; align-items:center; gap:6px;">
                        <i class="fas fa-file-invoice"></i> الدرجات والامتحانات الورقية (${paperExamsList.length})
                    </h4>
                    <button type="button" class="btn btn-ghost sibling-link-btn" title="إدارة الامتحانات الورقية" onclick="showPaperExamsModal()"><i class="fas fa-file-invoice"></i> <i class="fas fa-plus"></i></button>
                </div>
                <div style="display:flex; flex-direction:column; gap:8px;">
                    ${paperExamsList.length === 0 ? `
                        <div style="text-align:center; padding:16px; color:var(--muted); font-size:0.78rem; font-style:italic;">
                            لا توجد امتحانات ورقية مسجلة.
                        </div>
                    ` : paperExamsList.map(exam => `
                        <div class="glass-card" style="padding:10px 12px; border:1px solid var(--border-solid); border-radius:10px; display:flex; align-items:center; justify-content:space-between; gap:8px;">
                            <div style="display:flex; flex-direction:column; gap:4px; flex:1;">
                                <span style="font-weight:700; font-size:0.82rem; color:var(--text);">${escHtml(exam.name)}</span>
                                <div style="display:flex; gap:8px; align-items:center; font-size:0.75rem;">
                                    <span style="color:var(--text-3);">الدرجة الكلية: ${exam.total_degree}</span>
                                    ${exam.reference_url ? `<a href="${exam.reference_url}" target="_blank" style="color:var(--brand); font-weight:700;"><i class="fas fa-external-link-alt"></i> ورقة الامتحان</a>` : ''}
                                </div>
                            </div>
                            
                            <!-- Answers Paper Picture Section -->
                            <div style="display:flex; align-items:center; gap:4px; margin-left:8px;">
                                ${exam.answers_picture ? `
                                    <img src="${exam.answers_picture}" style="width:36px; height:36px; object-fit:cover; border-radius:4px; border:1px solid var(--border-solid); cursor:pointer;" onclick="window.open('${exam.answers_picture}', '_blank')">
                                    <button class="btn btn-ghost" style="padding:4px; color:var(--danger); font-size:0.75rem;" onclick="deleteModalAnswersPic(${full.id}, ${exam.id})"><i class="fas fa-trash-alt"></i></button>
                                ` : `
                                    <button class="btn btn-ghost" style="color:var(--brand); padding:4px; display:flex; align-items:center; gap:2px;" onclick="triggerModalAnswersPicUpload(${exam.id})">
                                        <i class="fas fa-camera"></i> <span style="font-size:0.7rem; font-weight:700;">إجابة الطفل</span>
                                    </button>
                                `}
                                <input type="file" id="modal-answers-file-input-${exam.id}" style="display:none;" accept="image/*" onchange="uploadModalAnswersPic(${full.id}, ${exam.id})">
                            </div>

                            <!-- Score input section -->
                            <div style="display:flex; align-items:center; gap:6px;">
                                <input type="number" step="any" min="0" max="${exam.total_degree}" class="form-input" style="width:65px; text-align:center; padding:5px 6px; font-family:Cairo,sans-serif; font-size:0.8rem; height:32px;" value="${exam.degree !== null ? exam.degree : ''}" placeholder="---" id="modal-degree-input-${exam.id}" oninput="validateDegreeInput(this, ${exam.total_degree})">
                                <button class="btn btn-primary" style="padding:5px 8px; height:32px; font-size:0.75rem;" onclick="saveModalExamDegree(${full.id}, ${exam.id})"><i class="fas fa-check"></i></button>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
            `;

            document.getElementById('studentDetails').innerHTML = img + rows + siblingHtml + tpHtml + paperExamsHtml + notesHtml;
        }

        function buildUncleDetailsFromProfile(full) {
            const gender = (full.gender === 'female' || full['النوع'] === 'female') ? 'female' : 'male';
            const showImgClick = full.image_url ? `onclick="showImageModal('${escJs(full.image_url)}', event)"` : '';
            const img = full.image_url
                ? `<div class="detail-avatar-wrap" ${showImgClick}><img src="${full.image_url}" class="detail-avatar"><div class="detail-student-name">${escStr(full.name || '')}</div><div class="detail-student-class">${escStr(full.class || '')}</div></div>`
                : `<div class="detail-avatar-wrap" ${showImgClick}><div class="detail-avatar-fallback ${gender}"><i class="fas fa-user"></i></div><div class="detail-student-name">${escStr(full.name || '')}</div><div class="detail-student-class">${escStr(full.class || '')}</div></div>`;

            const roleLabels = {
                'admin': 'مسؤول (Admin)',
                'developer': 'مطور (Developer)',
                'dev': 'مطور (Developer)',
                'uncle': 'خادم (Uncle)',
                'servant': 'خادم (Uncle)'
            };
            const roleKey = String(full.role || '').toLowerCase();
            const roleLabel = roleLabels[roleKey] || 'خادم (Uncle)';

            let rowsList = [
                ['معرّف الخادم (ID)', String(full.id), 'blue', 'fa-fingerprint', String(full.id)],
                ['الاسم الكامل', full.name || '---', 'blue', 'fa-id-card', full.name || '---'],
                ['اسم المستخدم', full.username || '---', 'orange', 'fa-user-tag', full.username || '---'],
                ['النوع', (full.gender === 'female' ? 'خادمة' : 'خادم'), 'purple', 'fa-venus-mars', (full.gender === 'female' ? 'خادمة' : 'خادم')],
                ['الدور / الصلاحية', roleLabel, 'red', 'fa-user-shield', roleLabel],
                ['رقم التليفون', full.phone || '---', 'green', 'fa-phone', full.phone || '---'],
            ];

            let rows = rowsList.map(([l, v, color, icon, copyVal]) => `
        <div class="detail-row">
            <div class="detail-icon ${color}"><i class="fas ${icon}"></i></div>
            <div class="detail-label">${l}</div>
            <div class="detail-val copy-holdable" data-copy-text="${escAttr(copyVal || v)}">${v}</div>
        </div>`).join('');

            let fees = [];
            try {
                const info = full._customInfo || (full.custom_info ? (typeof full.custom_info === 'string' ? JSON.parse(full.custom_info) : full.custom_info) : {});
                fees = info._fees || [];
            } catch (e) { fees = []; }

            const arabicMonths = ["يناير", "فبراير", "مارس", "أبريل", "مايو", "يونيو", "يوليو", "أغسطس", "سبتمبر", "أكتوبر", "نوفمبر", "ديسمبر"];
            const d = new Date();
            const curYear = d.getFullYear();
            const curMonthIdx = d.getMonth();

            const feeForm = `
                <div id="addFeeArea" class="glass-card" style="display:none; padding:12px; border:1px solid var(--border-solid); border-radius:12px; margin-bottom:16px; background:rgba(255,255,255,0.03);">
                    <style>
                        .no-spinner::-webkit-outer-spin-button,
                        .no-spinner::-webkit-inner-spin-button {
                            -webkit-appearance: none;
                            margin: 0;
                        }
                        .no-spinner {
                            -moz-appearance: textfield;
                        }
                    </style>
                    <div style="font-size:0.78rem; font-weight:700; color:var(--text-2); margin-bottom:10px;">تسجيل اشتراك جديد:</div>
                    
                    <div style="display:flex; flex-direction:column; gap:10px;">
                        <div style="display:flex; gap:8px; align-items:center;">
                            <div style="width:120px; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-size:0.7rem; font-weight:700; color:var(--text-3);">حالة الدفع</label>
                                <select id="newFeeStatus" class="form-input" style="height:36px; font-size:0.8rem; padding:4px 8px; font-family:Cairo,sans-serif;" onchange="const amtEl = document.getElementById('newFeeAmount'); const wrapperEl = document.getElementById('newFeeAmountWrapper'); if (this.value === 'unpaid') { amtEl.value = ''; amtEl.removeAttribute('required'); wrapperEl.style.display = 'none'; } else { amtEl.setAttribute('required', 'required'); wrapperEl.style.display = 'flex'; }">
                                    <option value="paid" selected>مدفوع</option>
                                    <option value="unpaid">غير مدفوع</option>
                                </select>
                            </div>
                            <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-size:0.7rem; font-weight:700; color:var(--text-3);">الشهر</label>
                                <select id="newFeeMonth" class="form-input" style="height:36px; font-size:0.8rem; padding:4px 8px; font-family:Cairo,sans-serif;">
                                    ${arabicMonths.map((m, idx) => `<option value="${m}" ${idx === curMonthIdx ? 'selected' : ''}>${m}</option>`).join('')}
                                </select>
                            </div>
                            <div style="width:90px; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-size:0.7rem; font-weight:700; color:var(--text-3);">السنة</label>
                                <select id="newFeeYear" class="form-input" style="height:36px; font-size:0.8rem; padding:4px 8px; font-family:Cairo,sans-serif;">
                                    <option value="${curYear - 1}">${curYear - 1}</option>
                                    <option value="${curYear}" selected>${curYear}</option>
                                    <option value="${curYear + 1}">${curYear + 1}</option>
                                </select>
                            </div>
                            <div id="newFeeAmountWrapper" style="width:100px; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-size:0.7rem; font-weight:700; color:var(--text-3);">القيمة (ج.م)</label>
                                <input type="number" id="newFeeAmount" class="form-input no-spinner" style="height:36px; font-size:0.8rem; text-align:center; padding:4px 8px;" placeholder="المبلغ" required>
                            </div>
                        </div>
                        <div style="display:flex; gap:8px; align-items:center;">
                            <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-size:0.7rem; font-weight:700; color:var(--text-3);">ملاحظات (اختياري)</label>
                                <input type="text" id="newFeeDesc" class="form-input" style="height:36px; font-size:0.8rem; padding:4px 10px;" placeholder="اكتب أي تفاصيل أخرى...">
                            </div>
                        </div>
                        <div style="display:flex; gap:8px; justify-content:flex-end; margin-top:4px;">
                            <button class="btn btn-ghost" onclick="toggleAddFeeArea(false)" style="font-size:0.75rem; padding:4px 10px; height:32px;">إلغاء</button>
                            <button type="button" class="btn btn-primary btn-sm" onclick="saveUncleFee(${full.id})" style="font-size:0.75rem; padding:4px 12px; height:32px; display:flex; align-items:center; justify-content:center; gap:6px; background:var(--brand); color:#fff; border:none;">
                                <i class="fas fa-plus"></i> حفظ الاشتراك
                            </button>
                        </div>
                    </div>
                </div>
            `;

            const isUncleLoggedIn = localStorage.getItem('uncleLoggedIn') === 'true';
            const currentUncleId = window.currentUncle?.id || localStorage.getItem('uncleId');
            const loggedInUsername = (localStorage.getItem('uncleUsername') || '').trim().toLowerCase();
            const allowedList = (allowedViewUncles || '').split(',').map(x => x.trim().toLowerCase());
            const isAssignedManager = loggedInUsername && allowedList.includes(loggedInUsername);

            let canViewFees = (churchUncleFeesEnabled !== 0);
            if (canViewFees && isUncleLoggedIn) {
                if (currentUncleId && String(currentUncleId) === String(full.id)) {
                    canViewFees = true;
                } else if (isAssignedManager) {
                    canViewFees = true;
                } else {
                    canViewFees = false;
                }
            }

            let feesHtml = '';
            if (canViewFees) {
                const extFees = getExtendedFeesList(fees);
                const canManageFees = !isUncleLoggedIn || isAssignedManager;
                const addFeeBtn = canManageFees ? `
                    <button type="button" class="btn btn-ghost sibling-link-btn" title="إضافة اشتراك" onclick="toggleAddFeeArea()"><i class="fas fa-money-bill-wave"></i> <i class="fas fa-plus"></i></button>
                ` : '';

                feesHtml = `
                <div class="uncle-fees-section" style="margin-top:16px; border-top:1px solid var(--border); padding-top:16px;">
                    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:12px;">
                        <h4 style="font-size:0.95rem; font-weight:700; color:var(--primary); margin:0; display:flex; align-items:center; gap:6px;">
                            <i class="fas fa-money-bill-wave"></i> الاشتراكات الشهرية للخدمة (${extFees.length})
                        </h4>
                        ${addFeeBtn}
                    </div>
                    
                    ${canManageFees ? feeForm : ''}

                    <div style="display:flex; flex-direction:column; gap:8px; max-height:250px; overflow-y:auto; padding-inline-end:4px;">
                        ${extFees.length === 0 ? `
                            <div style="text-align:center; padding:20px; color:var(--muted); font-size:0.78rem; font-style:italic;">
                                لا توجد اشتراكات مسجلة.
                            </div>
                        ` : extFees.map(fee => {
                    const isPaid = fee.status !== 'unpaid';
                    const statusBadge = isPaid
                        ? `<span style="background:#10b981; color:white; font-size:0.65rem; font-weight:700; padding:1px 6px; border-radius:6px; margin-inline-start:6px;">مدفوع</span>`
                        : `<span style="background:#ef4444; color:white; font-size:0.65rem; font-weight:700; padding:1px 6px; border-radius:6px; margin-inline-start:6px;">غير مدفوع</span>`;
                    const amountBadge = isPaid
                        ? `<span style="background:var(--brand); color:white; font-size:0.7rem; font-weight:800; padding:2px 6px; border-radius:10px;">${fee.amount} ج.م</span>`
                        : '';

                    const payBtn = (canManageFees && !isPaid) ? `
                                <button class="btn btn-ghost" style="padding:6px; color:#10b981; font-size:0.85rem;" onclick="payUncleFee(${full.id}, '${fee.id}')" title="تسديد الاشتراك">
                                    <i class="fas fa-check-circle"></i>
                                </button>
                            ` : '';
                    const deleteBtn = (canManageFees && !fee.is_virtual) ? `
                                <button class="btn btn-ghost" style="padding:6px; color:var(--danger); font-size:0.8rem;" onclick="deleteUncleFee(${full.id}, '${fee.id}')" title="حذف الاشتراك">
                                    <i class="fas fa-trash-alt"></i>
                                </button>
                            ` : '';
                    return `
                            <div class="glass-card" style="padding:10px 12px; border:1px solid var(--border-solid); border-radius:10px; display:flex; align-items:center; justify-content:space-between; gap:8px; background:rgba(255,255,255,0.01);">
                                <div style="flex:1;">
                                    <div style="display:flex; align-items:center; gap:6px; flex-wrap:wrap;">
                                        <span style="font-weight:700; font-size:0.82rem; color:var(--text);">${escHtml(fee.title)}</span>
                                        ${amountBadge}
                                        ${statusBadge}
                                    </div>
                                    <div style="font-size:0.72rem; color:var(--text-3); margin-top:2px;">
                                        <span>التاريخ: ${fee.date}</span>
                                        ${fee.description ? `<span style="margin-inline-start:8px; color:var(--text-2);">| ${escHtml(fee.description)}</span>` : ''}
                                    </div>
                                    <div style="font-size:0.65rem; color:var(--muted); margin-top:2px; opacity:0.8;">
                                        المستلم: ${escHtml(fee.created_by || '---')} (${fee.created_at || ''})
                                    </div>
                                </div>
                                <div style="display:flex; align-items:center; gap:4px;">
                                    ${payBtn}
                                    ${deleteBtn}
                                </div>
                            </div>
                            `;
                }).join('')}
                    </div>
                </div>
                `;
            }

            document.getElementById('studentDetails').innerHTML = img + rows + feesHtml;
        }

        async function saveUncleFee(uncleId) {
            const month = document.getElementById('newFeeMonth').value;
            const year = document.getElementById('newFeeYear').value;
            const title = `اشتراك شهر ${month} ${year}`;
            let amount = parseFloat(document.getElementById('newFeeAmount').value);
            const description = document.getElementById('newFeeDesc').value.trim();
            const status = document.getElementById('newFeeStatus').value;
            const date = new Date().toISOString().split('T')[0];

            if (isNaN(amount)) {
                amount = 0;
            }

            if (status === 'paid' && amount <= 0) {
                showToast('الرجاء إدخال قيمة صحيحة أكبر من الصفر للاشتراك', 'error');
                return;
            }
            if (status === 'unpaid' && amount < 0) {
                showToast('الرجاء إدخال قيمة صحيحة للاشتراك', 'error');
                return;
            }

            const fd = new FormData();
            fd.append('action', 'addUncleFee');
            fd.append('uncleId', uncleId);
            fd.append('title', title);
            fd.append('amount', amount);
            fd.append('description', description);
            fd.append('status', status);
            fd.append('date', date);

            try {
                const r = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(res => res.json());
                if (r.success) {
                    showToast(r.message || 'تم إضافة الاشتراك بنجاح', 'success');

                    const uncle = (window.allUnclesData || []).find(u => u.id === uncleId);
                    if (uncle) {
                        if (!uncle._customInfo) uncle._customInfo = {};
                        if (!uncle._customInfo._fees) uncle._customInfo._fees = [];
                        uncle._customInfo._fees.push({
                            id: r.feeId || ('fee_' + Math.random().toString(36).substr(2, 9)),
                            title: title,
                            amount: amount,
                            description: description,
                            date: date,
                            status: status,
                            created_by: window.currentUncle?.name || 'أدمن',
                            created_at: new Date().toISOString().replace('T', ' ').substr(0, 19)
                        });
                        uncle.custom_info = JSON.stringify(uncle._customInfo);
                        buildUncleDetailsFromProfile(uncle);
                    }
                    setTimeout(loadData, 500);
                } else {
                    showToast(r.message || 'فشل في إضافة الاشتراك', 'error');
                }
            } catch (e) {
                showToast('خطأ في الاتصال بالسيرفر', 'error');
            }
        }

        function getExtendedFeesList(feesList) {
            const fees = Array.isArray(feesList) ? feesList : [];
            const arabicMonths = ["يناير", "فبراير", "مارس", "أبريل", "مايو", "يونيو", "يوليو", "أغسطس", "سبتمبر", "أكتوبر", "نوفمبر", "ديسمبر"];
            const now = new Date();
            const curYear = now.getFullYear();
            const curMonthIdx = now.getMonth(); // 0 to 11

            const extended = [...fees];

            // Auto-generate virtual unpaid fees for 2025 and 2026 (up to current month).
            const startYear = 2025;
            for (let year = startYear; year <= curYear; year++) {
                const maxMonthIdx = (year === curYear) ? curMonthIdx : 11;
                for (let m = 0; m <= maxMonthIdx; m++) {
                    const monthName = arabicMonths[m];
                    const titleToCheck = `اشتراك شهر ${monthName} ${year}`;
                    
                    // Check if there is an existing fee for this month (paid or unpaid)
                    const exists = fees.some(f => {
                        const fTitle = (f.title || '').trim();
                        const titleMatch = fTitle.includes(monthName) && fTitle.includes(String(year));
                        
                        let dateMatch = false;
                        if (f.date && typeof f.date === 'string') {
                            const parts = f.date.split('-');
                            if (parts.length >= 2) {
                                const fYear = parseInt(parts[0], 10);
                                const fMonth = parseInt(parts[1], 10);
                                if (fYear === year && fMonth === (m + 1)) {
                                    dateMatch = true;
                                }
                            }
                        }
                        return titleMatch || dateMatch;
                    });

                    if (!exists) {
                        extended.push({
                            id: `virtual_${monthName}_${year}`,
                            title: titleToCheck,
                            amount: 0,
                            status: 'unpaid',
                            description: '',
                            is_virtual: true,
                            date: `${year}-${String(m + 1).padStart(2, '0')}-01`
                        });
                    }
                }
            }

            // Sort fees reverse chronologically by date
            extended.sort((a, b) => {
                const dateA = a.date || '';
                const dateB = b.date || '';
                return dateB.localeCompare(dateA);
            });

            return extended;
        }

        async function deleteUncleFee(uncleId, feeId) {
            if (!confirm('هل أنت متأكد من حذف هذا الاشتراك؟')) return;

            const fd = new FormData();
            fd.append('action', 'deleteUncleFee');
            fd.append('uncleId', uncleId);
            fd.append('feeId', feeId);

            try {
                const r = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(res => res.json());
                if (r.success) {
                    showToast(r.message || 'تم حذف الاشتراك', 'success');

                    const uncle = (window.allUnclesData || []).find(u => u.id === uncleId);
                    if (uncle && uncle._customInfo && Array.isArray(uncle._customInfo._fees)) {
                        uncle._customInfo._fees = uncle._customInfo._fees.filter(f => f.id !== feeId);
                        uncle.custom_info = JSON.stringify(uncle._customInfo);
                        buildUncleDetailsFromProfile(uncle);
                    }
                    setTimeout(loadData, 500);
                } else {
                    showToast(r.message || 'فشل الحذف', 'error');
                }
            } catch (e) {
                showToast('خطأ في الاتصال بالسيرفر', 'error');
            }
        }

        async function payUncleFee(uncleId, feeId) {
            openModal('payUncleFeeModal');
            const amountInputEl = document.getElementById('payFeeAmountInput');
            amountInputEl.value = '';
            setTimeout(() => amountInputEl.focus(), 150);

            amountInputEl.onkeydown = function(e) {
                if (e.key === 'Enter') {
                    document.getElementById('payUncleFeeSubmitBtn').click();
                }
            };

            document.getElementById('payUncleFeeSubmitBtn').onclick = async function() {
                const amountInput = amountInputEl.value.trim();
                if (!amountInput) {
                    showToast('الرجاء إدخال قيمة الاشتراك', 'error');
                    return;
                }
                const amount = parseFloat(amountInput);
                if (isNaN(amount) || amount <= 0) {
                    showToast('الرجاء إدخال مبلغ صحيح أكبر من الصفر للاشتراك', 'error');
                    return;
                }

                const fd = new FormData();
                let isVirtual = String(feeId).startsWith('virtual_');
                if (isVirtual) {
                    fd.append('action', 'addUncleFee');
                    const parts = String(feeId).split('_');
                    const month = parts[1];
                    const year = parts[2];
                    fd.append('title', `اشتراك شهر ${month} ${year}`);
                    fd.append('status', 'paid');
                    fd.append('date', new Date().toISOString().split('T')[0]);
                } else {
                    fd.append('action', 'payUncleFee');
                    fd.append('feeId', feeId);
                }
                fd.append('uncleId', uncleId);
                fd.append('amount', amount);

                try {
                    const r = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(res => res.json());
                    if (r.success) {
                        showToast(r.message || 'تم تسديد الاشتراك بنجاح', 'success');
                        closeModal('payUncleFeeModal');

                        const uncle = (window.allUnclesData || []).find(u => u.id === uncleId);
                        if (uncle) {
                            if (!uncle._customInfo) uncle._customInfo = {};
                            if (!Array.isArray(uncle._customInfo._fees)) uncle._customInfo._fees = [];

                            if (isVirtual) {
                                const parts = String(feeId).split('_');
                                const month = parts[1];
                                const year = parts[2];
                                uncle._customInfo._fees.push({
                                    id: r.feeId || ('fee_' + Math.random().toString(36).substr(2, 9)),
                                    title: `اشتراك شهر ${month} ${year}`,
                                    amount: amount,
                                    status: 'paid',
                                    date: new Date().toISOString().split('T')[0],
                                    created_by: window.currentUncle?.name || 'أدمن',
                                    created_at: new Date().toISOString().replace('T', ' ').substr(0, 19)
                                });
                            } else {
                                const fee = uncle._customInfo._fees.find(f => f.id === feeId);
                                if (fee) {
                                    fee.status = 'paid';
                                    fee.amount = amount;
                                    fee.paid_at = new Date().toISOString().replace('T', ' ').substr(0, 19);
                                    fee.paid_by = window.currentUncle?.name || 'أدمن';
                                }
                            }
                            uncle.custom_info = JSON.stringify(uncle._customInfo);
                            buildUncleDetailsFromProfile(uncle);
                        }
                        setTimeout(loadData, 500);
                    } else {
                        showToast(r.message || 'فشل تسديد الاشتراك', 'error');
                    }
                } catch (e) {
                    showToast('خطأ في الاتصال بالسيرفر', 'error');
                }
            };
        }

        // Open a small prompt to update points for a given trip and student
        function openPointsEditor(tripId, studentId) {
            const amount = prompt('أدخل قيمة (إيجابية للإضافة، سلبية للطرح) أو ضع =n لتعيين مباشرة. مثال: 5  -2  =10', '1');
            if (amount === null) return;
            let act = 'increment'; let val = 0;
            if (String(amount).startsWith('=')) { act = 'set'; val = parseInt(String(amount).substring(1)) || 0; }
            else { val = parseInt(amount) || 0; act = val < 0 ? 'decrement' : 'increment'; val = Math.abs(val); }
            if (!confirm(`تأكيد: ${act} ${val} نقطة للرحلة ${tripId}؟`)) return;
            updateStudentTripPoints(tripId, studentId, act, val);
        }

        async function updateStudentTripPoints(tripId, studentId, action, amount) {
            try {
                const fd = new FormData();
                fd.append('action', 'processGameQRCode');
                fd.append('trip', tripId);
                fd.append('id', studentId);
                fd.append('action', action);
                fd.append('amount', amount);
                const d = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(r => r.json()).catch(() => ({ success: false }));
                if (d.success) {
                    showToast('تم تحديث النقاط ✓', 'success');
                    // Refresh modal details
                    if (currentStudentForEdit) showStudentDetails(currentStudentForEdit['الاسم']);
                } else {
                    showToast(d.message || 'فشل التحديث', 'error');
                }
            } catch (e) { showToast('خطأ في الاتصال', 'error'); }
        }
        function hideStudentModal() { document.getElementById('studentModal').classList.remove('active'); currentStudentForEdit = null; startAutoRefresh(); }
        function showEditForm() {
            if (!currentStudentForEdit) return;
            const s = currentStudentForEdit;
            const isUncle = !!s._isUncle;
            const isGuest = !!s._isGuest;

            // Set modal title
            const titleEl = document.getElementById('editStudentModalTitle');
            if (titleEl) {
                if (isUncle) titleEl.textContent = 'تعديل بيانات الخادم';
                else if (isGuest) titleEl.textContent = 'تعديل بيانات الزائر';
                else titleEl.textContent = 'تعديل بيانات الطفل';
            }

            // Adjust labels for guest mode
            const emergLabel = document.querySelector('#editEmergencyPhoneGroup .form-label');
            if (emergLabel) {
                emergLabel.textContent = isGuest ? 'اسم ولي الأمر' : 'تليفون الطوارئ';
            }
            const medLabel = document.querySelector('#editMedicalNotesGroup .form-label');
            if (medLabel) {
                medLabel.textContent = isGuest ? 'ملاحظات' : 'ملاحظات طبية';
            }

            // Define which groups should be visible
            const photoEl = document.getElementById('editPhotoGroup');
            if (photoEl) photoEl.style.display = isUncle ? 'none' : '';

            const addressEl = document.getElementById('editAddressGroup');
            if (addressEl) addressEl.style.display = isUncle ? 'none' : '';

            const classEl = document.getElementById('editClassGroup');
            if (classEl) classEl.style.display = isUncle ? 'none' : '';

            const birthdayEl = document.getElementById('editBirthdayGroup');
            if (birthdayEl) birthdayEl.style.display = isUncle ? 'none' : '';

            const couponsEl = document.getElementById('editCommitmentCouponsGroup');
            if (couponsEl) couponsEl.style.display = isUncle ? 'none' : '';

            const emergEl = document.getElementById('editEmergencyPhoneGroup');
            if (emergEl) emergEl.style.display = isUncle ? 'none' : '';

            const medEl = document.getElementById('editMedicalNotesGroup');
            if (medEl) medEl.style.display = isUncle ? 'none' : '';

            const customFieldsEl = document.getElementById('editCustomFieldsContainer');
            if (customFieldsEl) customFieldsEl.style.display = isUncle ? 'none' : '';

            const guestToggleEl = document.getElementById('editStudentIsGuestGroup');
            if (guestToggleEl) {
                guestToggleEl.style.display = isUncle ? 'none' : '';
                const editPersonIsGuest = document.getElementById('editPersonIsGuest');
                if (editPersonIsGuest) {
                    editPersonIsGuest.checked = !!s._isGuest;
                }
            }

            const uncleEditFields = document.getElementById('uncleEditFields');
            if (uncleEditFields) {
                uncleEditFields.style.display = isUncle ? 'block' : 'none';
            }

            if (isUncle) {
                document.getElementById('editUncleUsername').value = s.username || '';
                const roleSelect = document.getElementById('editUncleRole');
                if (roleSelect) {
                    let devOpt = roleSelect.querySelector('option[value="developer"]');
                    if (isDeveloper) {
                        if (!devOpt) {
                            devOpt = document.createElement('option');
                            devOpt.value = 'developer';
                            devOpt.textContent = 'مطور (Developer)';
                            roleSelect.appendChild(devOpt);
                        }
                        devOpt.style.display = '';
                        devOpt.disabled = false;
                    } else {
                        if (devOpt) {
                            devOpt.style.display = 'none';
                            devOpt.disabled = true;
                        }
                    }
                }
                document.getElementById('editUncleRole').value = s.role || 'uncle';
                document.getElementById('editUnclePassword').value = '';
            }

            const cs = document.getElementById('editStudentClass');
            cs.innerHTML = '<option value="">اختر الفصل</option>';
            classes.forEach(c => { const o = document.createElement('option'); o.value = c.id || c.code; o.textContent = c.arabic_name || c.code; cs.appendChild(o); });
            document.getElementById('editStudentName').value = s.name || s['الاسم'] || '';
            if (document.getElementById('editStudentGender')) {
                document.getElementById('editStudentGender').value = s.gender === 'female' || s['النوع'] === 'female' ? 'female' : 'male';
            }
            // Match student's class by arabic_name or code against class/الفصل
            const studentClass = s.class || s['الفصل'] || '';
            const matchedOption = Array.from(cs.options).find(o =>
                o.textContent === studentClass || o.value === studentClass
            );
            if (matchedOption) cs.value = matchedOption.value;
            document.getElementById('editStudentAddress').value = s.address || s['العنوان'] || '';
            document.getElementById('editStudentPhone').value = s.phone || s['رقم التليفون'] || '';
            const studentEmergEl = document.getElementById('editStudentEmergencyPhone');
            const studentMedEl = document.getElementById('editStudentMedicalNotes');
            if (studentEmergEl) {
                studentEmergEl.value = s.emergency_phone || s['تليفون الطوارئ'] || s.guardian_name || '';
            }
            if (studentMedEl) {
                studentMedEl.value = s.medical_notes || s['ملاحظات طبية'] || s.notes || '';
            }
            const bd = s.birthday || s['عيد الميلاد'] || '';
            document.getElementById('editStudentBirthday').value = bd.match(/^\d{4}-\d{2}-\d{2}$/) ? bd.split('-').reverse().join('/') : bd;
            document.getElementById('editStudentCommitmentCoupons').value = s.commitment_coupons !== undefined ? s.commitment_coupons : (s['كوبونات الالتزام'] || '0');
            // Populate circle photo preview
            const prev = document.getElementById('uploadPreview');
            const ph = document.getElementById('photoPlaceholder');
            const photoVal = s.image_url || s['صورة'] || '';
            const deleteBtn = document.getElementById('deleteStudentPhotoBtn');
            if (photoVal && prev) {
                prev.src = (typeof window.photoUrl === 'function' && !photoVal.startsWith('http') && !photoVal.startsWith('/')) ? window.photoUrl(photoVal) : photoVal;
                prev.style.display = 'block';
                if (ph) ph.style.display = 'none';
                if (deleteBtn) deleteBtn.style.display = 'flex';
            } else {
                if (prev) prev.style.display = 'none';
                if (ph) ph.style.display = 'flex';
                if (deleteBtn) deleteBtn.style.display = 'none';
            }
            // Custom fields (multiple)
            const cfContainer = document.getElementById('editCustomFieldsContainer');
            if (cfContainer) {
                if (churchCustomFields && churchCustomFields.length && !isUncle) {
                    const info = s._customInfo || {};
                    cfContainer.innerHTML = churchCustomFields.map((cf, idx) => {
                        const key = 'field_' + idx;
                        const val = info[key] || info['field_' + idx] || (idx === 0 ? (info.value || '') : '');
                        return `<div class="form-group">
                    <label class="form-label"><i class="fas ${cf.icon || 'fa-tag'}"></i> ${cf.name}</label>
                    <div class="input-icon-wrap"><i class="fas ${cf.icon || 'fa-tag'} input-icon"></i><input type="text" class="form-input" data-cf-key="${key}" value="${escHtml(val)}" placeholder="${cf.name}..."></div>
                </div>`;
                    }).join('');
                    cfContainer.style.display = '';
                } else {
                    cfContainer.innerHTML = '';
                    cfContainer.style.display = 'none';
                }
            }
            document.getElementById('editStudentForm').classList.add('active');
        }
        function hideEditForm() { document.getElementById('editStudentForm').classList.remove('active'); }
        function updateStudentInfo(e) {
            e.preventDefault(); if (!currentStudentForEdit) return;
            const id = getStudentDbId(currentStudentForEdit); if (!id) { showToast('خطأ في البيانات', 'error'); return; }
            const name = document.getElementById('editStudentName').value.trim();
            if (!name) { showToast('الاسم مطلوب', 'error'); return; }

            const isUncle = !!currentStudentForEdit._isUncle;
            if (isUncle) {
                const username = document.getElementById('editUncleUsername').value.trim();
                const role = document.getElementById('editUncleRole').value;
                const newPassword = document.getElementById('editUnclePassword').value;
                if (!username) { showToast('اسم المستخدم مطلوب', 'error'); return; }

                const updatePayload = {
                    action: 'updateUncle',
                    uncle_id: id,
                    name: name,
                    username: username,
                    new_password: newPassword,
                    role: role,
                    gender: document.getElementById('editStudentGender').value,
                    phone: document.getElementById('editStudentPhone').value.trim(),
                    classes: JSON.stringify(currentStudentForEdit.classes || [])
                };

                showLoading('جاري التحديث...');
                makeApiCall(updatePayload, r => {
                    showToast('تم تحديث بيانات الخادم بنجاح', 'success');
                    hideEditForm();
                    hideStudentModal();
                    setTimeout(loadData, 1000);
                }, e => showToast('فشل: ' + e, 'error'));
                return;
            }

            const cls = document.getElementById('editStudentClass').value;
            if (!cls) { showToast('الفصل مطلوب للطفل', 'error'); return; }
            const cfContainer = document.getElementById('editCustomFieldsContainer');
            const existingInfo = (currentStudentForEdit && currentStudentForEdit._customInfo)
                ? { ...currentStudentForEdit._customInfo } : {};
            const siblingGroup = getSiblingGroupInfo(currentStudentForEdit);
            if (siblingGroup) existingInfo.sibling_group = siblingGroup;

            let customInfoPayload = null;
            if (cfContainer && churchCustomFields.length) {
                cfContainer.querySelectorAll('[data-cf-key]').forEach((inp, idx) => {
                    const key = inp.getAttribute('data-cf-key') || ('field_' + idx);
                    existingInfo[key] = inp.value.trim();
                });
                customInfoPayload = JSON.stringify(existingInfo);
            } else if (siblingGroup) {
                customInfoPayload = JSON.stringify({ sibling_group: siblingGroup });
            }

            const updatePayload = {
                action: 'updateStudent', studentId: id, name, classId: cls,
                gender: document.getElementById('editStudentGender').value,
                address: document.getElementById('editStudentAddress').value.trim(),
                phone: document.getElementById('editStudentPhone').value.trim(),
                emergency_phone: (document.getElementById('editStudentEmergencyPhone')?.value || '').trim(),
                medical_notes: (document.getElementById('editStudentMedicalNotes')?.value || '').trim(),
                birthday: document.getElementById('editStudentBirthday').value.trim(),
                coupons: parseInt(document.getElementById('editStudentCommitmentCoupons').value) || 0,
                is_guest: document.getElementById('editPersonIsGuest').checked ? '1' : '0'
            };
            if (customInfoPayload !== null) updatePayload.custom_info = customInfoPayload;

            showLoading('جاري التحديث...');
            makeApiCall(updatePayload, r => {
                showToast('تم التحديث بنجاح', 'success'); hideEditForm(); hideStudentModal(); setTimeout(loadData, 1000);
            }, e => showToast('فشل: ' + e, 'error'));
        }
        function addNewPerson(e) {
            e.preventDefault();
            const name = document.getElementById('studentName').value.trim();
            const isUncleClass = (currentClass === 'الخدام');
            const isGuestClass = (currentClass === 'الزوار');

            if (isUncleClass) {
                // Add Uncle/Servant
                const username = document.getElementById('uncleUsernameField').value.trim();
                const password = document.getElementById('unclePasswordField').value;
                const role = document.getElementById('uncleRoleField').value;
                const gender = document.getElementById('studentGender').value;
                const phone = document.getElementById('studentPhone').value.trim();

                if (!name || !username || !password) {
                    showToast('الاسم واسم المستخدم وكلمة المرور مطلوبة', 'error');
                    return;
                }

                showLoading('جاري إضافة الخادم...');
                const fd = new FormData();
                fd.append('action', 'addUncle');
                fd.append('name', name);
                fd.append('username', username);
                fd.append('password', password);
                fd.append('role', role);
                fd.append('gender', gender);
                fd.append('phone', phone);

                // Add photo if cropped photo exists
                if (currentCroppedBlob && currentPhotoEditorType === 'new') {
                    fd.append('photo', new File([currentCroppedBlob], `profile_${Date.now()}.jpg`, { type: 'image/jpeg' }));
                }

                fetch(API_URL, { method: 'POST', body: fd }).then(r => r.json()).then(d => {
                    if (d.success) {
                        showToast('تم إضافة الخادم بنجاح', 'success');
                        hideAddPersonModal();
                        document.getElementById('addPersonForm').reset();
                        cancelNewStudentPhotoUpload();
                        currentCroppedBlob = null;
                        setTimeout(loadData, 1000);
                    } else {
                        showToast('فشل: ' + (d.message || 'خطأ'), 'error');
                    }
                }).catch(() => showToast('خطأ في الاتصال', 'error'));

            } else {
                // Add Student (standard logic)
                const cls = document.getElementById('studentClass').value;
                if (!name || !cls) { showToast('الاسم والفصل مطلوبان', 'error'); return; }
                showLoading('جاري الإضافة...');
                const fd = new FormData();
                fd.append('action', 'addStudent'); fd.append('name', name); fd.append('classId', cls);
                fd.append('gender', document.getElementById('studentGender').value);
                fd.append('address', document.getElementById('studentAddress').value.trim() || '');
                fd.append('phone', document.getElementById('studentPhone').value.trim() || '');
                fd.append('emergency_phone', (document.getElementById('studentEmergencyPhone')?.value || '').trim());
                fd.append('medical_notes', (document.getElementById('studentMedicalNotes')?.value || '').trim());
                fd.append('birthday', document.getElementById('studentBirthday').value.trim() || '');
                fd.append('coupons', parseInt(document.getElementById('studentCoupons').value) || 0);
                fd.append('is_guest', document.getElementById('addPersonIsGuest').checked ? '1' : '0');
                // Multiple custom fields
                const cfContainer = document.getElementById('addCustomFieldsContainer');
                if (cfContainer && churchCustomFields.length) {
                    const infoObj = {};
                    cfContainer.querySelectorAll('[data-cf-key]').forEach((inp, idx) => {
                        const key = 'field_' + idx; // stable sequential key
                        const v = inp.value.trim();
                        if (v) infoObj[key] = v;
                    });
                    if (Object.keys(infoObj).length) fd.append('custom_info', JSON.stringify(infoObj));
                }
                if (currentCroppedBlob && currentPhotoEditorType === 'new') fd.append('photo', new File([currentCroppedBlob], `profile_${Date.now()}.jpg`, { type: 'image/jpeg' }));
                fd.append('enhanceImage', 'false');
                fetch(API_URL, { method: 'POST', body: fd }).then(r => r.json()).then(d => {
                    if (d.success) { showToast('تم الإضافة بنجاح', 'success'); hideAddPersonModal(); document.getElementById('addPersonForm').reset(); cancelNewStudentPhotoUpload(); currentCroppedBlob = null; setTimeout(loadData, 1000); }
                    else showToast('فشل: ' + (d.message || 'خطأ'), 'error');
                }).catch(() => showToast('خطأ في الاتصال', 'error'));
            }
        }
        function showDeleteStudentModal(s) { studentToDelete = s; document.getElementById('deleteStudentName').textContent = `هل تريد حذف: ${s.name || s['الاسم']}؟`; document.getElementById('deleteStudentModal').classList.add('active'); }
        function hideDeleteStudentModal() { studentToDelete = null; document.getElementById('deleteStudentModal').classList.remove('active'); }
        function deleteStudent() {
            if (!studentToDelete) return;
            const id = getStudentDbId(studentToDelete); if (!id) { showToast('المعرف غير موجود', 'error'); return; }
            showLoading('جاري الحذف...');
            const isUncle = !!studentToDelete._isUncle;
            const isLegacyGuest = !!studentToDelete._isGuest && !studentToDelete._studentId;
            const deletePayload = isUncle
                ? { action: 'deleteUncle', uncle_id: id }
                : (isLegacyGuest ? { action: 'deleteGuest', guest_id: id } : { action: 'deleteStudent', studentId: id });
            makeApiCall(deletePayload, r => { showToast('تم الحذف بنجاح', 'success'); hideDeleteStudentModal(); hideStudentModal(); setTimeout(loadData, 1000); }, e => { showToast('فشل: ' + e, 'error'); hideDeleteStudentModal(); });
        }

        // ── MODALS ────────────────────────────────────────────────────
        function showAddPersonModal() {
            document.getElementById('addPersonForm').reset(); cancelNewStudentPhotoUpload(); currentCroppedBlob = null;
