                    { key: 'username', label: 'اسم المستخدم', source: 'username', selected: true },
                    { key: 'role', label: 'الصلاحية / الدور', type: 'role', selected: true },
                    { key: 'gender', label: 'النوع', type: 'gender', source: 'النوع', selected: false },
                    { key: 'phone', label: 'رقم التليفون', source: 'رقم التليفون', selected: true },
                    { key: 'fees', label: 'الاشتراكات الشهرية', type: 'fees', selected: true },
                ];
            }
            const fields = [
                { key: 'id', label: 'كود الطفل (ID)', type: 'id', selected: true },
                { key: 'photo', label: 'الصورة', type: 'photo', selected: false },
                { key: 'qrcode', label: 'كود QR', type: 'qrcode', selected: false },
                { key: 'name', label: 'الاسم', source: 'الاسم', selected: true },
                { key: 'class', label: 'الفصل', source: 'الفصل', selected: true },
                { key: 'gender', label: 'النوع', type: 'gender', source: 'النوع', selected: false },
                { key: 'siblings', label: 'الإخوات', type: 'siblings', selected: false },
                { key: 'phone', label: 'رقم التليفون', source: 'رقم التليفون', selected: true },
                { key: 'emergency_phone', label: 'تليفون الطوارئ', source: 'تليفون الطوارئ', selected: false },
                { key: 'address', label: 'العنوان', source: 'العنوان', selected: false },
                { key: 'birthday', label: 'عيد الميلاد', source: 'عيد الميلاد', selected: false },
                { key: 'age', label: 'السن', type: 'age', selected: false },
                { key: 'medical_notes', label: 'ملاحظات طبية', source: 'ملاحظات طبية', selected: false },
                { key: 'coupons', label: 'إجمالي الكوبونات', source: 'كوبونات', selected: false },
                { key: 'attendance_coupons', label: 'كوبونات الحضور', source: 'كوبونات الحضور', selected: false },
                { key: 'commitment_coupons', label: 'كوبونات الالتزام', source: 'كوبونات الالتزام', selected: false },
                { key: 'task_coupons', label: 'كوبونات المهام', source: 'كوبونات المهام', selected: false },
                { key: 'attended_count', label: 'إجمالي الحضور', type: 'attendance_count', selected: false },
            ];
            if (churchCustomFields && churchCustomFields.length) {
                churchCustomFields.forEach((cf, idx) => fields.push({
                    key: 'custom_' + idx,
                    label: cf.name || ('حقل مخصص ' + (idx + 1)),
                    type: 'custom',
                    customIndex: idx,
                    selected: false
                }));
            }
            return fields;
        }
        function initCustomExportFields(force = false) {
            if (force || !customExportFields.length) customExportFields = getCustomExportDefaultFields();
            customExportFields = customExportFields.filter(f =>
                f.key !== 'custom_info' && f.source !== 'معلومات إضافية' && f.type !== 'custom_info'
            );
            if (force || !customExportSortLayers.length) {
                customExportSortLayers = [{ field: 'name', order: 'asc' }];
            }
            renderCustomExportFields();
            renderCustomExportSortLayers();
        }

        function renderCustomExportSortLayers() {
            const container = document.getElementById('customExportSortLayersContainer');
            if (!container) return;
            
            container.innerHTML = customExportSortLayers.map((layer, idx) => {
                const optionsHtml = customExportFields.map(f => 
                    `<option value="${f.key}" ${f.key === layer.field ? 'selected' : ''}>${f.label}</option>`
                ).join('');
                
                return `
                    <div class="sort-layer-row" style="display:flex; gap:6px; align-items:center;">
                        <select class="form-input sort-layer-field" style="flex:1.5; padding: 4px 8px; font-size:0.8rem; height: 32px;" onchange="updateCustomExportSortLayerField(${idx}, this.value)">
                            ${optionsHtml}
                        </select>
                        <select class="form-input sort-layer-order" style="flex:1; padding: 4px 8px; font-size:0.8rem; height: 32px;" onchange="updateCustomExportSortLayerOrder(${idx}, this.value)">
                            <option value="asc" ${layer.order === 'asc' ? 'selected' : ''}>تصاعدي</option>
                            <option value="desc" ${layer.order === 'desc' ? 'selected' : ''}>تنازلي</option>
                        </select>
                        <button type="button" class="export-mini-btn" onclick="removeCustomExportSortLayer(${idx})" style="color:var(--danger); background:transparent; border:none; padding:4px; cursor:pointer;" title="حذف"><i class="fas fa-trash"></i></button>
                    </div>
                `;
            }).join('');
        }

        function addCustomExportSortLayer() {
            customExportSortLayers.push({ field: 'name', order: 'asc' });
            renderCustomExportSortLayers();
            renderCustomExportPreview();
        }

        function removeCustomExportSortLayer(idx) {
            customExportSortLayers.splice(idx, 1);
            renderCustomExportSortLayers();
            renderCustomExportPreview();
        }

        function updateCustomExportSortLayerField(idx, value) {
            if (customExportSortLayers[idx]) customExportSortLayers[idx].field = value;
            renderCustomExportPreview();
        }

        function updateCustomExportSortLayerOrder(idx, value) {
            if (customExportSortLayers[idx]) customExportSortLayers[idx].order = value;
            renderCustomExportPreview();
        }

        window.addCustomExportSortLayer = addCustomExportSortLayer;
        window.removeCustomExportSortLayer = removeCustomExportSortLayer;
        window.updateCustomExportSortLayerField = updateCustomExportSortLayerField;
        window.updateCustomExportSortLayerOrder = updateCustomExportSortLayerOrder;
        function renderCustomExportFields() {
            const box = document.getElementById('customExportFields');
            if (!box) return;
            box.innerHTML = customExportFields.map((f, i) => `
        <div class="export-field-row">
            <input type="checkbox" id="cef_${f.key}" ${f.selected ? 'checked' : ''} onchange="toggleCustomExportField('${f.key}',this.checked)">
            <label for="cef_${f.key}">${f.label}</label>
            <div class="export-field-actions">
                <button class="export-mini-btn" onclick="moveCustomExportField(${i},-1)" title="أعلى"><i class="fas fa-arrow-up"></i></button>
                <button class="export-mini-btn" onclick="moveCustomExportField(${i},1)" title="أسفل"><i class="fas fa-arrow-down"></i></button>
            </div>
        </div>
    `).join('');
        }
        function toggleCustomExportField(key, checked) {
            const f = customExportFields.find(x => x.key === key);
            if (f) f.selected = checked;
            renderCustomExportPreview();
        }
        function moveCustomExportField(index, dir) {
            const next = index + dir;
            if (next < 0 || next >= customExportFields.length) return;
            const tmp = customExportFields[index];
            customExportFields[index] = customExportFields[next];
            customExportFields[next] = tmp;
            renderCustomExportFields();
            renderCustomExportPreview();
        }
        function getAllAttendanceDateColumnsForStudents(fs) {
            const dates = new Set();
            fs.forEach(s => {
                Object.keys(s || {}).forEach(k => {
                    if (k.includes('/') && k.length === 10) {
                        const v = s[k];
                        if (['ح', 'غ', 'حاضر', 'غائب', 'present', 'absent'].includes(v)) dates.add(k);
                    }
                });
                if (s._allAttendance) Object.keys(s._allAttendance).forEach(d => {
                    if (d.includes('/')) dates.add(d);
                });
            });
            return [...dates].sort((a, b) => parseDate(b) - parseDate(a));
        }
        function parseCustomExportDates() {
            const fs = getActiveViewStudents();
            const mode = document.getElementById('customExportDateMode')?.value || 'none';
            const allDates = getAllAttendanceDateColumnsForStudents(fs);
            if (mode === 'none') return [];
            if (mode === 'current') return currentFriday ? [currentFriday] : [];
            if (mode === 'all') return allDates;
            if (mode === 'range') {
                const from = (document.getElementById('customExportFromDate')?.value || '').trim();
                const to = (document.getElementById('customExportToDate')?.value || '').trim();
                const valid = v => !v || /^\d{2}\/\d{2}\/\d{4}$/.test(v);
                if (!valid(from) || !valid(to)) return [];
                if (from && to && parseDate(from) > parseDate(to)) return [];
                return allDates.filter(d => (!from || parseDate(d) >= parseDate(from)) && (!to || parseDate(d) <= parseDate(to)));
            }
            if (mode === 'custom') {
                const raw = (document.getElementById('customExportDates')?.value || '').trim();
                return raw.split(/[\s,،]+/).map(x => x.trim()).filter(x => /^\d{2}\/\d{2}\/\d{4}$/.test(x));
            }
            return [];
        }
        function getCustomFieldValue(s, idx) {
            const info = s._customInfo || {};
            return info['field_' + idx] || (idx === 0 ? (info.value || '') : '') || '';
        }
        function getAbsolutePhotoUrl(rawUrl) {
            if (!rawUrl) return '';
            const versioned = window.photoUrl ? window.photoUrl(rawUrl) : rawUrl;
            try { return new URL(versioned, window.location.origin).href; }
            catch (e) { return versioned; }
        }
        function getCustomExportCellValue(s, field, forCsv = false) {
            if (field.type === 'role') {
                const roleLabels = {
                    'admin': 'مسؤول (Admin)',
                    'developer': 'مطور (Developer)',
                    'dev': 'مطور (Developer)',
                    'uncle': 'خادم (Uncle)',
                    'servant': 'خادم (Uncle)'
                };
                return roleLabels[String(s.role || '').toLowerCase()] || 'خادم (Uncle)';
            }
            if (field.type === 'fees') {
                let fees = [];
                try {
                    const info = s._customInfo || (s.custom_info ? (typeof s.custom_info === 'string' ? JSON.parse(s.custom_info) : s.custom_info) : {});
                    fees = info._fees || [];
                } catch (e) { fees = []; }
                return fees.map(f => {
                    const cleanTitle = (f.title || '').replace('اشتراك شهر ', '').replace('اشتراك ', '').trim();
                    return `${cleanTitle}: ${f.amount} ج.م`;
                }).join(forCsv ? ' | ' : ' - ');
            }
            if (field.type === 'id') return getStudentDbId(s) || '';
            if (field.type === 'qrcode') {
                const studentId = getStudentDbId(s);
                if (!studentId) return '';
                const text = `${window.location.origin}/user/profile/?id=${encodeURIComponent(studentId)}`;
                const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent(text)}`;
                if (forCsv) return qrUrl ? `=IMAGE("${qrUrl.replace(/"/g, '""')}")` : '';
                return qrUrl
                    ? `<img class="custom-export-qr" src="${qrUrl}" crossorigin="anonymous" referrerpolicy="no-referrer" alt="" style="width:50px; height:50px; display:block; margin:0 auto;">`
                    : '';
            }
            if (field.type === 'photo') {
                const url = getAbsolutePhotoUrl(s['صورة'] || '');
                if (forCsv) return url ? `=IMAGE("${url.replace(/"/g, '""')}")` : '';
                return url
                    ? `<img class="custom-export-photo" src="${url}" crossorigin="anonymous" referrerpolicy="no-referrer" alt="" onerror="this.outerHTML='<div class=&quot;custom-export-photo-fallback&quot;><i class=&quot;fas fa-user&quot;></i></div>'">`
                    : '<div class="custom-export-photo-fallback"><i class="fas fa-user"></i></div>';
            }
            if (field.type === 'age') return _calcAge(s['عيد الميلاد'] || '') || '';
            if (field.type === 'gender') return formatGenderLabel(s);
            if (field.type === 'siblings') {
                const studentId = getStudentDbId(s);
                const info = parseStudentCustomInfo(s);
                const group = info.sibling_group && typeof info.sibling_group === 'object' ? info.sibling_group : null;
                const members = (group && group.id) ? getSiblingMembersByGroupId(group.id, studentId) : [];
                return members.map(m => getStudentDisplayName(m)).join(forCsv ? '، ' : ' - ');
            }
            if (field.type === 'attendance_count') return getAttendanceCountForStudent(s);
            if (field.type === 'custom') return getCustomFieldValue(s, field.customIndex);
            return s[field.source] || '';
        }
        function getAttendanceDisplayValue(s, date) {
            let v = s[date] || (s._allAttendance && s._allAttendance[date]) || '';
            if (v === 'present' || v === 'حاضر') v = 'ح';
            if (v === 'absent' || v === 'غائب') v = 'غ';
            return v;
        }
        function getCustomExportConfig() {
            const fields = customExportFields.filter(f => f.selected);
            const dates = parseCustomExportDates();
            const title = (document.getElementById('customExportTitle')?.value || '').trim() || ('تقرير ' + getActiveViewLabel());
            return { fields, dates, title, sortRules: customExportSortLayers };
        }
        function getCustomExportSortedStudents() {
            const cfg = getCustomExportConfig();
            const list = getActiveViewStudents();
            const collator = new Intl.Collator('ar', { sensitivity: 'base', numeric: true });
            const arr = [...(list || [])];
            arr.sort((a, b) => {
                for (let rule of cfg.sortRules) {
                    const fieldCfg = customExportFields.find(f => f.key === rule.field || f.label === rule.field);
                    if (!fieldCfg) continue;
                    
                    let vA = getCustomExportCellValue(a, fieldCfg, true);
                    let vB = getCustomExportCellValue(b, fieldCfg, true);
                    
                    let res = 0;
                    const isNumeric = ['paid_amount', 'donation', 'remaining_amount', 'coupons', 'attendance_coupons', 'commitment_coupons', 'task_coupons', 'age', 'attendance_count'].includes(fieldCfg.type || fieldCfg.key || fieldCfg.source);
                    
                    if (isNumeric) {
                        res = (parseFloat(vA) || 0) - (parseFloat(vB) || 0);
                    } else if (fieldCfg.key === 'birthday' || fieldCfg.label === 'عيد الميلاد') {
                        const pA = String(vA).split('/'), pB = String(vB).split('/');
                        if (pA.length === 3 && pB.length === 3) {
                            res = new Date(pA[2], pA[1] - 1, pA[0]) - new Date(pB[2], pB[1] - 1, pB[0]);
                        } else {
                            res = collator.compare(String(vA), String(vB));
                        }
                    } else if (fieldCfg.type === 'gender') {
                        const gA = (a['النوع'] === 'female' || a['gender'] === 'female') ? '2' : '1';
                        const gB = (b['النوع'] === 'female' || b['gender'] === 'female') ? '2' : '1';
                        res = collator.compare(gA, gB);
                    } else if (fieldCfg.type === 'photo' || fieldCfg.key === 'photo' || fieldCfg.label === 'الصورة الشخصية') {
                        const hasPicA = (a['صورة'] || a.student_image || a.guest_image || a.image_url) ? 1 : 0;
                        const hasPicB = (b['صورة'] || b.student_image || b.guest_image || b.image_url) ? 1 : 0;
                        res = hasPicB - hasPicA;
                    } else if (fieldCfg.type === 'siblings') {
                        const studentIdA = getStudentDbId(a);
                        const infoA = parseStudentCustomInfo(a);
                        const groupA = infoA.sibling_group && typeof infoA.sibling_group === 'object' ? infoA.sibling_group : null;
                        const membersA = (groupA && groupA.id) ? getSiblingMembersByGroupId(groupA.id, studentIdA) : [];
                        const studentIdB = getStudentDbId(b);
                        const infoB = parseStudentCustomInfo(b);
                        const groupB = infoB.sibling_group && typeof infoB.sibling_group === 'object' ? infoB.sibling_group : null;
                        const membersB = (groupB && groupB.id) ? getSiblingMembersByGroupId(groupB.id, studentIdB) : [];
                        res = membersA.length - membersB.length;
                    } else {
                        res = collator.compare(String(vA), String(vB));
                    }
                    
                    if (rule.order === 'desc') res = -res;
                    
                    if (res !== 0) return res;
                }
                
                // Fallback default sort by name
                return collator.compare(a['الاسم'] || '', b['الاسم'] || '');
            });
            return arr;
        }
        function renderCustomExportPreview() {
            const preview = document.getElementById('customExportPreview');
            if (!preview) return;
            const cfg = getCustomExportConfig();
            const fs = getCustomExportSortedStudents();
            if (!cfg.fields.length && !cfg.dates.length) {
                preview.innerHTML = '<div style="text-align:center;padding:3rem;color:#64748b">اختر عموداً واحداً على الأقل</div>';
                return;
            }
            const headers = [...cfg.fields.map(f => f.label), ...cfg.dates];
            const dateLabel = cfg.dates.length ? cfg.dates.join('، ') : 'بدون أعمدة حضور';
            preview.innerHTML = `
        <div class="custom-export-title">
            <div>
                <h2>${escHtml(cfg.title)}</h2>
                <small>${escHtml(getActiveViewLabel())} - ${fs.length} ${window.IS_YOUTH ? 'عضو' : 'طفل'}</small>
                <small>${escHtml(dateLabel)}</small>
            </div>
            <small>${new Date().toLocaleDateString('ar-EG')}</small>
        </div>
        <table class="custom-export-table">
            <thead><tr>${headers.map(h => `<th>${escHtml(h)}</th>`).join('')}</tr></thead>
            <tbody>
                ${fs.map(s => `<tr>
                    ${cfg.fields.map(f => `<td>${f.type === 'photo' ? getCustomExportCellValue(s, f, false) : escHtml(String(getCustomExportCellValue(s, f, false) || ''))}</td>`).join('')}
                    ${cfg.dates.map(d => {
                const v = getAttendanceDisplayValue(s, d);
                const cls = v === 'ح' ? 'att-p' : (v === 'غ' ? 'att-a' : '');
                return `<td class="${cls}">${escHtml(v || '')}</td>`;
            }).join('')}
                </tr>`).join('')}
            </tbody>
        </table>`;
        }
