            on('uncleProfileForm', 'submit', e => {
                e.preventDefault();
                const name = document.getElementById('uncleProfileName').value.trim();
                const username = document.getElementById('uncleProfileUsername').value.trim();
                const email = (document.getElementById('uncleProfileEmail')?.value || '').trim();
                const phone = (document.getElementById('uncleProfilePhone')?.value || '').trim();
                const gender = (document.getElementById('uncleProfileGender')?.value || 'male');

                if (!name || !username) { showToast('الاسم واسم المستخدم مطلوبان', 'error'); return; }

                showLoading('جاري التحديث...');
                const payload = { action: 'updateUncleProfile', name, username, email, phone, gender };

                makeApiCall(payload, r => {
                    showToast('تم التحديث', 'success');
                    if (document.getElementById('accountDisplayName')) document.getElementById('accountDisplayName').textContent = name;
                    if (document.getElementById('aiName')) document.getElementById('aiName').textContent = name;
                    if (document.getElementById('aiUsername')) document.getElementById('aiUsername').textContent = username;
                    if (document.getElementById('aiEmail')) document.getElementById('aiEmail').textContent = email || 'غير مسجل';
                    if (document.getElementById('aiPhone')) document.getElementById('aiPhone').textContent = phone || 'غير مسجل';

                    localStorage.setItem('uncleName', name);
                    localStorage.setItem('uncleUsername', username);
                    localStorage.setItem('uncleEmail', email);
                    localStorage.setItem('unclePhone', phone);
                    localStorage.setItem('uncleGender', gender);

                    if (window.currentUncle) { window.currentUncle.name = name; window.currentUncle.username = username; window.currentUncle.email = email; window.currentUncle.phone = phone; window.currentUncle.gender = gender; }
                    hideAccountEditForm();
                }, e => showToast('فشل: ' + e, 'error'));
            });
            on('changePasswordForm', 'submit', e => {
                e.preventDefault();
                const currentPass = document.getElementById('changePassCurrent').value.trim();
                const newPass = document.getElementById('changePassNew').value.trim();
                const confirmPass = document.getElementById('changePassConfirm').value.trim();

                if (!currentPass || !newPass || !confirmPass) { showToast('يرجى ملء جميع الحقول', 'error'); return; }
                if (newPass !== confirmPass) { showToast('كلمة المرور الجديدة غير متطابقة', 'error'); return; }
                if (newPass.length < 6) { showToast('كلمة المرور الجديدة يجب أن تكون 6 أحرف على الأقل', 'error'); return; }

                showLoading('جاري تحديث كلمة المرور...');
                const payload = {
                    action: 'updateUncleProfile',
                    name: document.getElementById('uncleProfileName').value.trim(),
                    username: document.getElementById('uncleProfileUsername').value.trim(),
                    email: (document.getElementById('uncleProfileEmail')?.value || '').trim(),
                    phone: (document.getElementById('uncleProfilePhone')?.value || '').trim(),
                    gender: (document.getElementById('uncleProfileGender')?.value || 'male'),
                    current_password: currentPass,
                    new_password: newPass
                };

                makeApiCall(payload, r => {
                    showToast('تم تغيير كلمة المرور بنجاح', 'success');
                    closeModal('changePasswordModal');
                    document.getElementById('changePassCurrent').value = '';
                    document.getElementById('changePassNew').value = '';
                    document.getElementById('changePassConfirm').value = '';
                }, e => showToast('فشل: ' + e, 'error'));
            });
            on('resetToTodayBtn', 'click', resetToCurrentFriday);
            on('pendingSearchBtn', 'click', searchPendingRegistrations);
            on('approveAllSelectedBtn', 'click', approveAllSelected);
            on('rejectAllSelectedBtn', 'click', rejectAllSelected);
            on('approveRegistrationBtn', 'click', () => { if (currentRegistrationDetails) approveRegistration(currentRegistrationDetails.id || currentRegistrationDetails.ID); });
            on('rejectRegistrationBtn', 'click', () => { if (currentRegistrationDetails) document.getElementById('rejectionNoteContainer').style.display = 'block'; });
            on('addAnnouncementForm', 'submit', e => {
                e.preventDefault();
                const type = document.getElementById('announcementType').value;
                const text = document.getElementById('announcementText').value.trim();
                const link = document.getElementById('announcementLink').value.trim();
                const button_text = document.getElementById('announcementButtonText').value.trim();
                const image_url = document.getElementById('announcementImageUrl').value.trim();
                const description = document.getElementById('announcementDescription').value.trim();
                const target_type = document.getElementById('announcementTargetType').value;

                const classEl = document.getElementById('announcementClass');
                const cls = classEl ? Array.from(classEl.selectedOptions || []).map(o => o.value).filter(Boolean) : ['الجميع'];
                let stds = document.getElementById('announcementStudents').value.trim();
                // If no explicit students selected but "has photo only" is checked, auto-fill students list
                if (!stds && document.getElementById('announcementHasPhotoOnly')?.checked) {
                    const pool = getAnnouncementPickerStudents();
                    stds = pool.map(s => s['الاسم'] || s.name || '').filter(Boolean).join(', ');
                }
                const hasPhotoOnly = document.getElementById('announcementHasPhotoOnly')?.checked ? '1' : '0';
                if (!text) { showToast('أدخل نص الإعلان', 'error'); return; } if (type === 'button' && !link) { showToast('أدخل رابطاً للزر', 'error'); return; }
                showLoading('...');
                makeApiCall({
                    action: 'addAnnouncement',
                    type,
                    text,
                    link,
                    button_text,
                    image_url,
                    description,
                    target_type,
                    classes: cls,
                    students: stds,
                    hasPhotoOnly
                }, r => {
                    showToast(r.message, 'success');
                    document.getElementById('addAnnouncementForm').reset();
                    document.getElementById('linkFieldContainer').style.display = 'none';
                    resetAnnouncementStudentPicker();
                    loadAnnouncements();
                }, () => showToast('فشل', 'error'));
            });
            on('clearAnnouncementForm', 'click', () => { document.getElementById('addAnnouncementForm').reset(); document.getElementById('linkFieldContainer').style.display = 'none'; resetAnnouncementStudentPicker(); });
            on('announcementType', 'change', () => { document.getElementById('linkFieldContainer').style.display = document.getElementById('announcementType').value === 'button' ? 'block' : 'none'; });
            on('announcementClass', 'change', () => {
                const allowed = new Set(getAnnouncementPickerStudents().map(s => String(getStudentId(s))));
                selectedAnnouncementStudents = selectedAnnouncementStudents.filter(s => allowed.has(s.id));
                renderAnnouncementSelectedCards();
                renderAnnouncementStudentGrid();
            });
            on('announcementStudentSearch', 'input', () => { renderAnnouncementStudentGrid(); });
            on('announcementHasPhotoOnly', 'change', () => { renderAnnouncementStudentGrid(); });
            on('actionsStripBtn', 'click', e => { e.stopPropagation(); toggleDropdown('actionsDropdownMenu', 'actionsStripBtn'); });
            on('couponsStripBtn', 'click', e => { e.stopPropagation(); toggleDropdown('couponsDropdownMenu', 'couponsStripBtn'); });
            // Overlay click & swipe-to-close
            document.querySelectorAll('.modal-overlay').forEach(overlay => {
                overlay.addEventListener('click', e => {
                    if (e.target === overlay) { overlay.classList.remove('active'); startAutoRefresh(); if (overlay.id === 'studentModal') currentStudentForEdit = null; if (overlay.id === 'accountModal') hideAccountEditForm(); }
                });
                initSwipeToClose(overlay);
            });

            // Monitor modal overlays to toggle body class for scroll locking and overscroll containment
            const modalObserver = new MutationObserver(() => {
                const hasActiveModal = Array.from(document.querySelectorAll('.modal-overlay, .image-modal, #swipeOverlay, #pwaInstallModal')).some(el => {
                    return el.classList.contains('active') || el.classList.contains('show') || el.style.display === 'flex' || el.style.display === 'block';
                });
                document.documentElement.classList.toggle('modal-open', hasActiveModal);
                document.body.classList.toggle('modal-open', hasActiveModal);
            });
            document.querySelectorAll('.modal-overlay, .image-modal, #swipeOverlay, #pwaInstallModal').forEach(el => {
                modalObserver.observe(el, { attributes: true, attributeFilter: ['class', 'style'] });
            });
            // Sync initial state
            const syncModalOpenState = () => {
                const hasActiveModal = Array.from(document.querySelectorAll('.modal-overlay, .image-modal, #swipeOverlay, #pwaInstallModal')).some(el => {
                    return el.classList.contains('active') || el.classList.contains('show') || el.style.display === 'flex' || el.style.display === 'block';
                });
                document.documentElement.classList.toggle('modal-open', hasActiveModal);
                document.body.classList.toggle('modal-open', hasActiveModal);
            };
            syncModalOpenState();

            // ── Mouse swipe selection in attendance view ──
            const attendanceList = document.getElementById('attendanceList');
            if (attendanceList) {
                let isMouseDown = false;
                let mouseHoldTimer = null;

                attendanceList.addEventListener('mousedown', e => {
                    const card = e.target.closest('.attendance-item');
                    if (!card) return;

                    // Ignore clicks on buttons/inputs/action zones
                    if (e.target.closest('button') || e.target.closest('input') || e.target.closest('.coupon-toggle-row') || e.target.closest('.attend-btn-row') || e.target.closest('.student-avatar')) {
                        return;
                    }

                    isMouseDown = true;
                    _holdStartX = e.clientX;
                    _holdStartY = e.clientY;
                    _holdScrolled = false;

                    // Start long press timer (350ms for snappy response)
                    mouseHoldTimer = setTimeout(() => {
                        if (!isMouseDown) return;
                        navigator.vibrate && navigator.vibrate([12, 60, 20]);

                        // Enter select mode if not active
                        if (!isBulkSelectMode) {
                            toggleBulkSelectMode();
                        }

                        // Select the current card
                        const dbId = parseInt(card.getAttribute('data-db-id'));
                        if (dbId) {
                            if (!selectedStudentIds.has(dbId)) {
                                selectedStudentIds.add(dbId);
                                const allList = isCombinedView ? combinedStudents : students;
                                const s = allList.find(x => getStudentDbId(x) === dbId);
                                if (s) {
                                    _updateAttendanceRow(getStudentId(s));
                                }
                                updateBulkUI();
                            }
                        }

                        _swipeClientX = e.clientX;
                        _swipeClientY = e.clientY;
                        _isSwipingSelection = true;
                        startAutoScrollLoop();
                    }, 350);
                });

                attendanceList.addEventListener('mousemove', e => {
                    if (!isMouseDown) return;

                    const dx = Math.abs(e.clientX - _holdStartX);
                    const dy = Math.abs(e.clientY - _holdStartY);
                    if (dx > 8 || dy > 8) {
                        if (!_isSwipingSelection) {
                            clearTimeout(mouseHoldTimer);
                        }
                    }

                    if (_isSwipingSelection) {
                        e.preventDefault();
                        _swipeClientX = e.clientX;
                        _swipeClientY = e.clientY;
                    }
                });

                const clearMouseSelection = () => {
                    isMouseDown = false;
                    _isSwipingSelection = false;
                    _swipeClientX = null;
                    _swipeClientY = null;
                    stopAutoScrollLoop();
                    clearTimeout(mouseHoldTimer);
                };

                attendanceList.addEventListener('mouseup', clearMouseSelection);
                attendanceList.addEventListener('mouseleave', clearMouseSelection);
            }
        }


        // ── UNCLE ACTIVITY HISTORY ────────────────────────────────────
        // ── History: human-readable action map ────────────────────────
