        async function doPwaInstall() {
            if (!_pwaPrompt) return;
            _pwaPrompt.prompt();
            const { outcome } = await _pwaPrompt.userChoice;
            if (outcome === 'accepted') {
                _pwaPrompt = null;
                closePwaModal();
            }
        }

        function closePwaModal() {
            const modal = document.getElementById('pwaInstallModal');
            if (modal) modal.classList.remove('show');
        }

        // ── VAPID public key (set this to your server's VAPID public key) ──────────
        // Generate a VAPID key pair on your server with:
        //   php artisan webpush:vapid  OR  npx web-push generate-vapid-keys
        // Then paste the PUBLIC key string here:
        const VAPID_PUBLIC_KEY = '<?php echo defined("VAPID_PUBLIC_KEY") ? VAPID_PUBLIC_KEY : (getenv("VAPID_PUBLIC_KEY") ?: ""); ?>';

        // Update toast disabled (removed to avoid automatic update prompts)

        // ── Register service worker ───────────────────────────────────

        if ('serviceWorker' in navigator) {
            window.addEventListener('load', () => {
                navigator.serviceWorker.register('/sw.js')
                    .then(reg => {
                        _initPushSubscription(reg);
                        // ── Re-subscribe whenever SW becomes active after an update ──
                        reg.addEventListener('updatefound', () => {
                            const newSW = reg.installing;
                            if (newSW) newSW.addEventListener('statechange', () => {
                                if (newSW.state === 'activated') _initPushSubscription(reg);
                            });
                        });
                    })
                    .catch(() => { });
            });

            // ── Re-subscribe + reload data when coming back online ───────
            window.addEventListener('online', async () => {
                try {
                    const reg = await navigator.serviceWorker.ready;
                    _doSubscribe(reg); // silently re-subscribe in case it lapsed
                    if (reg.active) reg.active.postMessage({ type: 'FLUSH_QUEUE' });
                } catch (e) { }
                setTimeout(() => { if (navigator.onLine) loadData(); }, 1000);
            });

            // ── Messages from the Service Worker ─────────────────────────
            navigator.serviceWorker.addEventListener('message', e => {
                const d = e.data;
                if (!d) return;

                // NEW_VERSION_INSTALLED handling removed (update UI disabled)

                // Silent reload requested by new service worker activation
                if (d.type === 'RELOAD_NOW') {
                    try { window.location.reload(); } catch (err) { }
                    return;
                }

                // Background sync completed — reload data so UI reflects server state
                if (d.type === 'SYNC_COMPLETE') {
                    const uName = d.uncleName || '';
                    const msg = `تمت المزامنة وحفظ البيانات بنجاح ✅`;
                    showToast(msg, 'success', { dur: 5000 });
                    clearOfflineSavedData();
                    setTimeout(() => { if (navigator.onLine) loadData(); }, 800);
                }

                // New registration pushed to this device
                if (d.type === 'NEW_REGISTRATION') {
                    showToast(`📋 طلب تسجيل جديد في ${d.className || 'الفصل'}`, 'info', { dur: 8000 });
                    // Reload pending registrations no matter which class we're viewing
                    if (currentClass) loadPendingRegistrationsForClass(currentClass);
                    else if (typeof loadPendingRegistrationsForClass === 'function') {
                        // Reload for all classes in the background so badge counts update
                        const cls = [...new Set(students.map(s => s['الفصل']).filter(Boolean))];
                        cls.forEach(c => loadPendingRegistrationsForClass(c));
                    }
                }

                // Attendance saved by another device/tab
                if (d.type === 'ATTENDANCE_SAVED') {
                    showToast(`🔄 تم حفظ الحضور من جهاز آخر`, 'info', { dur: 4000 });
                    setTimeout(() => { if (navigator.onLine) loadData(); }, 500);
                }

                // Birthday reminder from SW
                if (d.type === 'BIRTHDAY_REMINDER') {
                    const names = (d.names || []).join('، ');
                    showToast(`🎂 عيد ميلاد اليوم: ${names}`, 'info', { dur: 9000 });
                }

                // User tapped a notification while app was in background
                if (d.type === 'NOTIFICATION_CLICK') {
                    if (d.notifType === 'registration') {
                        if (currentClass) {
                            loadPendingRegistrationsForClass(currentClass);
                            document.getElementById('pendingRegistrationsSection')?.scrollIntoView({ behavior: 'smooth' });
                        } else {
                            // Navigate to classes view and scroll to pending
                            showClassesView();
                        }
                    } else if (d.notifType === 'sync') {
                        showUnsavedModal();
                    } else if (d.notifType === 'birthday') {
                        showBirthdayModal();
                    }
                }
            });
        }

        // ── Push subscription bootstrap ──────────────────────────────
        async function _initPushSubscription(reg) {
            const perm = ('Notification' in window) ? Notification.permission : 'denied';
            if (perm === 'default') {
                try {
                    const newPerm = await Notification.requestPermission();
                    if (newPerm === 'granted') {
                        await _doSubscribe(reg);
                        _maybeSendBirthdayNotification();
                    }
                } catch (e) { }
            } else if (perm === 'granted') {
                await _doSubscribe(reg);
                _maybeSendBirthdayNotification();
            }
            _updateNotifBtnVisibility();
        }

        // ── Called once per day to notify about today's birthdays ────
        async function _maybeSendBirthdayNotification() {
            if (!navigator.onLine || !VAPID_PUBLIC_KEY) return;
            const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD
            const storageKey = `bdayNotifSent_${today}`;
            if (localStorage.getItem(storageKey)) return; // already sent today

            // Wait for students data to be loaded (may be called before loadData finishes)
            const tryCheck = () => {
                const data = allStudentsData.length ? allStudentsData : students;
                if (!data.length) return;
                const now = new Date();
                const todayKids = data.filter(s => {
                    if (!s['عيد الميلاد']) return false;
                    const p = s['عيد الميلاد'].split('/');
                    return p.length >= 2 && parseInt(p[0]) === now.getDate() && parseInt(p[1]) - 1 === now.getMonth();
                });
                if (!todayKids.length) return;
                localStorage.setItem(storageKey, '1');
                const names = todayKids.map(s => s['الاسم'] || '').filter(Boolean);
                _sendBirthdayPush(names).catch(() => { });
            };
            // Try immediately; if data not ready yet, retry after loadData
            tryCheck();
            setTimeout(tryCheck, 3000);
            setTimeout(tryCheck, 8000);
        }

        async function _sendBirthdayPush(names) {
            if (!names.length || !navigator.onLine || !VAPID_PUBLIC_KEY) return;
            try {
                await makeApiCallRaw({
                    action: 'sendPushNotification',
                    target: 'self',
                    uncle_id: window.currentUncle?.id || '',
                    notifType: 'birthday',
                    title: `🎂 أعياد ميلاد اليوم (${names.length})`,
                    body: names.join('، '),
                    url: window.location.href
                });
            } catch (e) { }
        }

        // Called from every notification button — asks permission then subscribes
        async function requestNotifPermission() {
            if (!('Notification' in window)) {
                showToast('المتصفح لا يدعم الإشعارات', 'error'); return;
            }
            // Web Push requires PushManager + Service Worker support (not available on iOS Safari)
            if (!('serviceWorker' in navigator) || !('PushManager' in window)) {
                showToast('الإشعارات غير مدعومة على هذا الجهاز/المتصفح', 'warning', { dur: 6000 });
                return;
            }
            if (Notification.permission === 'denied') {
                showToast('الإشعارات محظورة — افتح إعدادات المتصفح لتفعيلها', 'warning', { dur: 7000 }); return;
            }
            if (Notification.permission === 'granted') {
                const reg = await navigator.serviceWorker.ready;
                await _doSubscribe(reg);
                showToast('الإشعارات مفعّلة بالفعل ✅', 'success');
                _updateNotifBtnVisibility();
                _maybeSendBirthdayNotification();
                return;
            }
            const perm = await Notification.requestPermission();
            if (perm === 'granted') {
                try {
                    const reg = await navigator.serviceWorker.ready;
                    await _doSubscribe(reg);
                    showToast('✅ تم تفعيل الإشعارات!', 'success', { dur: 5000 });
                    _maybeSendBirthdayNotification();
                } catch (e) {
                    showToast('تم القبول، لكن فشل التسجيل — حاول مجدداً', 'warning');
                }
            } else {
                showToast('تم رفض الإشعارات — يمكنك تفعيلها لاحقاً من الإعدادات', 'info', { dur: 6000 });
            }
            _updateNotifBtnVisibility();
        }

        // Subscribes the device to Web Push and saves to server
        async function _doSubscribe(reg) {
            if (!VAPID_PUBLIC_KEY) return;
            try {
                let sub = await reg.pushManager.getSubscription();
                let needsResubscribe = false;
                if (sub) {
                    if (sub.options && sub.options.applicationServerKey) {
                        const currentKeyUint8 = _urlBase64ToUint8Array(VAPID_PUBLIC_KEY);
                        const subKey = new Uint8Array(sub.options.applicationServerKey);
                        let mismatch = subKey.length !== currentKeyUint8.length;
                        if (!mismatch) {
                            for (let i = 0; i < subKey.length; i++) {
                                if (subKey[i] !== currentKeyUint8[i]) {
                                    mismatch = true;
                                    break;
                                }
                            }
                        }
                        if (mismatch) {
                            try {
                                await sub.unsubscribe();
                            } catch (unsubErr) { }
                            sub = null;
                            needsResubscribe = true;
                        }
                    } else {
                        needsResubscribe = true;
                    }
                }
                if (!sub) {
                    sub = await reg.pushManager.subscribe({
                        userVisibleOnly: true,
                        applicationServerKey: _urlBase64ToUint8Array(VAPID_PUBLIC_KEY)
                    });
                    needsResubscribe = true;
                }
                const savedEndpoint = localStorage.getItem('push_sub_saved_endpoint');
                if (needsResubscribe || !savedEndpoint || savedEndpoint !== sub.endpoint) {
                    await _savePushSubscriptionToServer(sub);
                    localStorage.setItem('push_sub_saved_endpoint', sub.endpoint);
                }
            } catch (e) { }
        }

        // Shows/hides all notification buttons based on current Notification.permission
        function _updateNotifBtnVisibility() {
            const perm = ('Notification' in window) ? Notification.permission : 'denied';
            const isStandalone = window.matchMedia('(display-mode: standalone)').matches
                || window.navigator.standalone === true;

            // Only show notification buttons if PushManager + ServiceWorker are supported
            const pushSupported = ('Notification' in window) && ('serviceWorker' in navigator) && ('PushManager' in window);

            // Hide old/standalone notifications toggle button from showing elsewhere
            const notifBtn = document.getElementById('notifPermBtn');
            if (notifBtn) notifBtn.style.display = 'none';

            const offlineNotifBtn = document.getElementById('offlineNotifBtn');
            if (offlineNotifBtn) offlineNotifBtn.style.display = 'none';

            const panelNotifBtn = document.getElementById('panelNotifToggleBtn');
            if (panelNotifBtn) {
                panelNotifBtn.style.display = 'flex';
                if (!pushSupported) {
                    panelNotifBtn.querySelector('span').textContent = 'تفعيل الإشعارات';
                    panelNotifBtn.querySelector('i').className = 'fas fa-bell';
                    panelNotifBtn.disabled = false;
                    panelNotifBtn.style.background = '';
                    panelNotifBtn.style.color = '';
                    panelNotifBtn.style.borderColor = '';
                } else if (perm === 'denied') {
                    panelNotifBtn.querySelector('span').textContent = 'محظورة بالمتصفح';
                    panelNotifBtn.querySelector('i').className = 'fas fa-exclamation-triangle';
                    panelNotifBtn.disabled = true;
                } else if (perm === 'default') {
                    panelNotifBtn.querySelector('span').textContent = 'تفعيل الإشعارات';
                    panelNotifBtn.querySelector('i').className = 'fas fa-bell';
                    panelNotifBtn.disabled = false;
                    panelNotifBtn.style.background = '';
                    panelNotifBtn.style.color = '';
                    panelNotifBtn.style.borderColor = '';
                } else if (perm === 'granted') {
                    navigator.serviceWorker.ready.then(async reg => {
                        const sub = await reg.pushManager.getSubscription();
                        if (sub) {
                            panelNotifBtn.querySelector('span').textContent = 'إيقاف الإشعارات';
                            panelNotifBtn.style.setProperty('background', 'var(--danger-bg)', 'important');
                            panelNotifBtn.style.setProperty('color', 'var(--danger)', 'important');
                            panelNotifBtn.style.setProperty('border-color', 'var(--danger)', 'important');
                            panelNotifBtn.querySelector('i').className = 'fas fa-bell-slash';
                        } else {
                            panelNotifBtn.querySelector('span').textContent = 'تفعيل الإشعارات';
                            panelNotifBtn.style.background = '';
                            panelNotifBtn.style.color = '';
                            panelNotifBtn.style.borderColor = '';
                            panelNotifBtn.querySelector('i').className = 'fas fa-bell';
                        }
                        panelNotifBtn.disabled = false;
                    }).catch(() => {
                        panelNotifBtn.querySelector('span').textContent = 'تفعيل الإشعارات';
                        panelNotifBtn.querySelector('i').className = 'fas fa-bell';
                        panelNotifBtn.disabled = false;
                    });
                }
            }
        }

        async function _savePushSubscriptionToServer(sub) {
            if (!sub || !navigator.onLine) return;
            try {
                const subJson = sub.toJSON();
                await makeApiCallRaw({
                    action: 'savePushSubscription',
                    endpoint: subJson.endpoint,
                    p256dh: subJson.keys?.p256dh || '',
                    auth: subJson.keys?.auth || '',
                    uncle_id: window.currentUncle?.id || ''
                });
            } catch (e) { }
        }

        // makeApiCall wrapper that returns a promise (for async/await)
        function makeApiCallRaw(params) {
            return new Promise((res, rej) => {
                makeApiCall(params, res, rej);
            });
        }

        // Converts a URL-safe base64 VAPID key to Uint8Array for subscribe()
        function _urlBase64ToUint8Array(base64String) {
            const padding = '='.repeat((4 - base64String.length % 4) % 4);
            const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
            const raw = atob(base64);
            return new Uint8Array([...raw].map(c => c.charCodeAt(0)));
        }

        // Called after a successful attendance/coupon save — push to all subscribed devices
        async function _sendSyncCompletePush(savedCount, type) {
            // Disabled: only notify locally or offline sync in background. No church-wide notifications.
            return;
        }



        async function toggleNotificationsFromModal() {
            if (!('Notification' in window) || !('serviceWorker' in navigator) || !('PushManager' in window)) {
                showToast('المتصفح الحالي لا يدعم الإشعارات. يرجى إضافة التطبيق للشاشة الرئيسية وتفعيله منه. 📲', 'warning', 6000);
                triggerPwaInstall('لتفعيل الإشعارات وتنبيهات أعياد الميلاد، يرجى إضافة التطبيق إلى شاشتك الرئيسية 📲');
                return;
            }

            try {
                const reg = await navigator.serviceWorker.ready;
                let sub = await reg.pushManager.getSubscription();

                if (Notification.permission === 'default') {
                    await requestNotifPermission();
                } else if (Notification.permission === 'granted') {
                    if (sub) {
                        // Unsubscribe (disable)
                        await sub.unsubscribe();
                        await makeApiCallRaw({
                            action: 'deletePushSubscription',
                            endpoint: sub.endpoint
                        });
                        localStorage.removeItem('push_sub_saved_endpoint');
                        showToast('❌ تم إيقاف الإشعارات', 'info');
                    } else {
                        // Subscribe (enable)
                        await _doSubscribe(reg);
                        showToast('✅ تم تفعيل الإشعارات بنجاح!', 'success');
                        _maybeSendBirthdayNotification();
                    }
                    _updateNotifBtnVisibility();
                } else if (Notification.permission === 'denied') {
                    showToast('الإشعارات محظورة في إعدادات المتصفح. تأكد من السماح بها أو افتح التطبيق بعد إضافته للشاشة الرئيسية. 📲', 'warning', 6000);
                }
            } catch (e) {
                console.error("Error toggling notifications:", e);
            }
        }

        // Offline/online detection
        let _connectivityState = { ok: true, ts: 0 };
        async function _isActuallyOnline(force = false) {
            const now = Date.now();
            if (!force && (now - _connectivityState.ts) < 15000) return _connectivityState.ok;

            try {
                const ctrl = new AbortController();
                const timer = setTimeout(() => ctrl.abort(), 3500);
                const fd = new FormData();
                fd.append('action', '__connectivityProbe');
                const res = await fetch(API_URL + `?_probe=${now}`, {
                    method: 'POST',
                    body: fd,
                    cache: 'no-store',
                    credentials: 'same-origin',
                    signal: ctrl.signal
                });
                clearTimeout(timer);
                const ok = !!(res && res.ok);
                _connectivityState = { ok, ts: Date.now() };
                return ok;
            } catch (_) {
                _connectivityState = { ok: false, ts: Date.now() };
                return false;
            }
        }

        function _countAllPendingLocalChanges() {
            // Count only genuinely-unsaved changes and offline saved changes pending sync.
            let total = 0;
            const keysToDelete = [];

            Object.keys(localStorage).forEach(k => {
                if (k.startsWith('changedStudents_')) {
                    try {
                        const arr = JSON.parse(localStorage.getItem(k) || '[]');
                        const unsaved = arr.filter(id => !savedStudents.has(id));
                        if (unsaved.length === 0) {
                            keysToDelete.push(k);
                        } else {
                            total += unsaved.length;
                        }
                    } catch (e) { }
                }
                if (k.startsWith('changedCouponStudents_')) {
                    try {
                        const arr = JSON.parse(localStorage.getItem(k) || '[]');
                        const unsaved = arr.filter(id => !savedCouponStudents.has(id));
                        if (unsaved.length === 0) {
                            keysToDelete.push(k);
                        } else {
                            total += unsaved.length;
                        }
                    } catch (e) { }
                }
                if (k.startsWith('offlineSavedAttendance_')) {
                    try {
                        const arr = JSON.parse(localStorage.getItem(k) || '[]');
                        total += arr.length;
                    } catch (e) { }
                }
                if (k.startsWith('offlineSavedCoupons_')) {
                    try {
                        const arr = JSON.parse(localStorage.getItem(k) || '[]');
                        total += arr.length;
                    } catch (e) { }
                }
            });

            keysToDelete.forEach(k => { try { localStorage.removeItem(k); } catch (e) { } });
            return total;
        }

        function markAttendanceAsOfflineSaved(date) {
            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
            const key = `offlineSavedAttendance_${cls}_${date}`;
            let offlineSaved = JSON.parse(localStorage.getItem(key) || '[]');

            changedStudents.forEach(id => {
                if (!offlineSaved.includes(id)) {
                    offlineSaved.push(id);
                }
                originalAttendanceData[id] = attendanceData[id] || 'pending';
            });

            localStorage.setItem(key, JSON.stringify(offlineSaved));

            changedStudents.clear();
            localStorage.removeItem(`changedStudents_${cls}_${date}`);
            saveAttendanceDataForClass(currentClass, date);

            renderAttendanceList(currentClass);
            updateSaveBtns();
            updateOfflineSyncIndicator();
        }

        function markCouponsAsOfflineSaved() {
            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;
            const key = `offlineSavedCoupons_${cls}`;
            let offlineSaved = JSON.parse(localStorage.getItem(key) || '[]');

            changedCouponStudents.forEach(id => {
                if (!offlineSaved.includes(id)) {
                    offlineSaved.push(id);
                }
                const accKey = `offlineAccumulatedCoupons_${cls}`;
                let acc = JSON.parse(localStorage.getItem(accKey) || '{}');
                acc[id] = (acc[id] || 0) + (couponData[id] || 0);
                localStorage.setItem(accKey, JSON.stringify(acc));
            });

            localStorage.setItem(key, JSON.stringify(offlineSaved));

            changedCouponStudents.clear();
            couponData = {};
            saveCouponDataForClass(currentClass);

            renderAttendanceList(currentClass);
            updateSaveBtns();
            updateOfflineSyncIndicator();
        }

        function clearOfflineSavedData() {
            const keysToRemove = [];
            for (let i = 0; i < localStorage.length; i++) {
                const key = localStorage.key(i);
                if (key && (key.startsWith('offlineSavedAttendance_') || key.startsWith('offlineSavedCoupons_') || key.startsWith('offlineAccumulatedCoupons_'))) {
                    keysToRemove.push(key);
                }
            }
            keysToRemove.forEach(k => localStorage.removeItem(k));
            updateOfflineSyncIndicator();
            if (currentClass) {
                renderAttendanceList(currentClass);
            }
        }

        function getIndexedDbQueueCount() {
            return new Promise((resolve) => {
                try {
                    const req = indexedDB.open('ss-queue', 2);
                    req.onerror = () => resolve(0);
                    req.onsuccess = () => {
                        const db = req.result;
                        if (!db.objectStoreNames.contains('queue')) {
                            db.close();
                            resolve(0);
                            return;
                        }
                        const tx = db.transaction('queue', 'readonly');
                        const store = tx.objectStore('queue');
                        const countReq = store.count();
                        countReq.onsuccess = () => {
                            const count = countReq.result;
                            db.close();
                            resolve(count);
                        };
                        countReq.onerror = () => {
                            db.close();
                            resolve(0);
                        };
                    };
                } catch (e) {
                    resolve(0);
                }
            });
        }

        async function updateOfflineSyncIndicator() {
            const ind = document.getElementById('offlineSyncIndicator');
            const cnt = document.getElementById('offlineSyncCount');
            if (!ind || !cnt) return;

            const queueCount = await getIndexedDbQueueCount();
            if (queueCount === 0) {
                // Queue is empty, clear any residual offline flags in localStorage
                const keysToRemove = [];
                for (let i = 0; i < localStorage.length; i++) {
                    const key = localStorage.key(i);
                    if (key && (key.startsWith('offlineSavedAttendance_') || key.startsWith('offlineSavedCoupons_') || key.startsWith('offlineAccumulatedCoupons_'))) {
                        keysToRemove.push(key);
                    }
                }
                keysToRemove.forEach(k => localStorage.removeItem(k));
                ind.style.display = 'none';
            } else {
                cnt.textContent = queueCount;
                ind.style.display = 'inline-flex';
            }
        }

        function triggerManualSync() {
            if (navigator.onLine) {
                showToast('جاري بدء مزامنة التغييرات المحفوظة أوفلاين…', 'info');
                if ('serviceWorker' in navigator && navigator.serviceWorker.controller) {
                    navigator.serviceWorker.controller.postMessage({ type: 'FLUSH_QUEUE' });
                }
            } else {
                showToast('لا تزال غير متصل بالإنترنت. ستتم المزامنة تلقائياً بمجرد توفر اتصال.', 'warning');
            }
        }

        async function _updateOnlineStatus() {
            const banner = document.getElementById('offlineBanner');
            if (!banner) return;

            const onlineNow = await _isActuallyOnline(true);
            if (!onlineNow) {
                banner.classList.add('show');
                _wasOffline = true;
                if (typeof _updateNotifBtnVisibility === 'function') _updateNotifBtnVisibility();
                updateOfflineSyncIndicator();
                return;
            }

            // We are online
            banner.classList.remove('show');
            updateOfflineSyncIndicator();

            // Only run the "came back online" logic if we actually went offline first.
            // This prevents the toast from firing on initial page load.
            if (!_wasOffline) return;
            _wasOffline = false;

            const inMemory = changedStudents.size + changedCouponStudents.size;
            const allStored = _countAllPendingLocalChanges();
            const hasPending = inMemory > 0 || allStored > 0;

            if (hasPending) {
                const count = Math.max(inMemory, allStored);
                showToast(`عدت للإنترنت — جاري رفع ${count} تغيير تلقائياً…`, 'info', { dur: 5000 });
                setTimeout(() => { if (navigator.onLine) saveAllData(); }, 1200);
            }
            setTimeout(() => { if (navigator.onLine) loadData(); }, 2500);
        }

        // Returns first-letter of first name + first-letter of last name (Arabic-safe)
        function _getInitials(name) {
            const parts = (name || '').trim().split(/\s+/).filter(Boolean);
            if (!parts.length) return '؟';
            if (parts.length === 1) return parts[0][0];
            return parts[0][0] + parts[parts.length - 1][0];
        }

        // Sends uncle identity + API URL to SW so background registration checks work
        // even when the app is fully closed (periodic sync reads this from IDB)
        async function _sendUnclMetaToSW() {
            if (!('serviceWorker' in navigator)) return;
            try {
                const reg = await navigator.serviceWorker.ready;
                if (!reg.active) return;
                reg.active.postMessage({
                    type: 'SET_UNCLE_META',
                    meta: {
                        apiUrl: (typeof API_URL !== 'undefined' ? API_URL : '/api.php'),
                        uncleId: window.currentUncle?.id || '',
                        uncleName: window.currentUncle?.name || '',
                        lastRegCount: 0   // SW will update this after first check
                    }
                });
                // Also request periodic sync permission if not already set up
                _requestPeriodicSyncPermission(reg);
            } catch (err) { }
        }

        async function _requestPeriodicSyncPermission(reg) {
            try {
                if (!('periodicSync' in reg)) return;
                const status = await navigator.permissions.query({ name: 'periodic-background-sync' });
                if (status.state === 'granted') {
                    await reg.periodicSync.register('check-registrations', { minInterval: 15 * 60 * 1000 });
                }
            } catch (err) { }
        }
        function toggleDevChurchDropdown(event) {
            if (event) event.stopPropagation();
            const el = document.getElementById('devChurchDropdownMenu');
            if (!el) return;
            const isHidden = el.style.display === 'none' || el.style.display === '' || getComputedStyle(el).display === 'none';
            if (isHidden) {
                el.style.display = 'flex';
                const searchInput = document.getElementById('devChurchDropdownSearch');
                if (searchInput) {
                    searchInput.value = '';
                    searchInput.focus();
                }
                renderDevChurchDropdownList(allChurchesCache || []);
            } else {
                el.style.display = 'none';
            }
        }

        function renderDevChurchDropdownList(churches) {
            const listContainer = document.getElementById('devChurchDropdownList');
            if (!listContainer) return;

            let html = '';

            // Default option
            const isSelectedDefault = !devViewChurchId;
            html += `
                <div class="dev-church-dropdown-item ${isSelectedDefault ? 'selected' : ''}" 
                     onclick="devSelectChurch(0, 'كنيستي الافتراضية')">
                    كنيستي الافتراضية
                </div>
            `;

            if (!churches || churches.length === 0) {
                if (document.getElementById('devChurchDropdownSearch')?.value.trim()) {
                    html += `<div class="dev-church-dropdown-item-empty">لا توجد نتائج</div>`;
                }
            } else {
                churches.forEach(church => {
                    const isSelected = devViewChurchId === parseInt(church.id);
                    html += `
                        <div class="dev-church-dropdown-item ${isSelected ? 'selected' : ''}" 
                             onclick="devSelectChurch(${church.id}, '${escJs(church.church_name)}')">
                            ${escHtml(church.church_name)}
                        </div>
                    `;
                });
            }
            listContainer.innerHTML = html;
        }

        function devSelectChurch(churchId, label) {
            const hiddenSelect = document.getElementById('devChurchSelect');
            if (hiddenSelect) hiddenSelect.value = churchId || '';
            devSwitchChurch(churchId);
            const labelEl = document.getElementById('devChurchSelectedLabel');
            if (labelEl) labelEl.textContent = label;
            const dropdown = document.getElementById('devChurchDropdownMenu');
            if (dropdown) dropdown.style.display = 'none';
            // Clear search query
            const searchInput = document.getElementById('devChurchDropdownSearch');
            if (searchInput) searchInput.value = '';
        }

        function filterDevChurches(query) {
            const q = (query || '').trim();
            if (!q) {
                renderDevChurchDropdownList(allChurchesCache || []);
                return;
            }

            const scored = (allChurchesCache || []).map(church => {
                return {
                    ...church,
                    _score: getMatchScore({ 'الاسم': church.church_name }, q)
                };
            }).filter(c => c._score > 0)
                .sort((a, b) => b._score - a._score);

            renderDevChurchDropdownList(scored);
        }

        // Close dropdown when clicking outside
        window.addEventListener('click', e => {
            const dropdown = document.getElementById('devChurchDropdownMenu');
            if (dropdown && !e.target.closest('#devDashboardChurchSwitcher')) {
                dropdown.style.display = 'none';
            }
        });

        async function initDevSwitcher() {
            if (!isDeveloper) return;
            const container = document.getElementById('devDashboardChurchSwitcher');
            const select = document.getElementById('devChurchSelect');
            if (!container || !select) return;

            // Make container visible
            container.style.display = 'flex';

            try {
                makeApiCall({ action: 'getAllChurchesForAdmin' }, r => {
                    if (r.success && Array.isArray(r.churches)) {
                        allChurchesCache = r.churches;
                        select.innerHTML = '<option value="">كنيستي الافتراضية</option>';
                        r.churches.forEach(church => {
                            const opt = document.createElement('option');
                            opt.value = church.id;
                            opt.textContent = church.church_name;
                            select.appendChild(opt);
                        });

                        // Set active select value & label
                        let activeLabel = 'كنيستي الافتراضية';
                        if (devViewChurchId > 0) {
                            select.value = devViewChurchId;
                            const target = r.churches.find(c => c.id == devViewChurchId);
                            if (target) activeLabel = target.church_name;
                            updateSwitchedChurchHeader();
                        }
                        const labelEl = document.getElementById('devChurchSelectedLabel');
                        if (labelEl) labelEl.textContent = activeLabel;

                        renderDevChurchDropdownList(r.churches);
                    }
                }, () => {
                    console.error("Failed to load dev church list.");
                });
            } catch (e) {
                console.error("Error in initDevSwitcher:", e);
            }
        }

        function devSwitchChurch(churchId) {
            if (!isDeveloper) return;
            const select = document.getElementById('devChurchSelect');
            if (churchId) {
                devViewChurchId = parseInt(churchId);
                localStorage.setItem('devViewChurchId', devViewChurchId);
            } else {
                devViewChurchId = 0;
                localStorage.removeItem('devViewChurchId');
            }
            if (select) {
                select.value = devViewChurchId || '';
            }

            // Sync custom dropdown menu label and list highlight
            if (typeof allChurchesCache !== 'undefined') {
                renderDevChurchDropdownList(allChurchesCache);
                let activeLabel = 'كنيستي الافتراضية';
                if (devViewChurchId > 0 && allChurchesCache.length) {
                    const target = allChurchesCache.find(c => c.id == devViewChurchId);
                    if (target) activeLabel = target.church_name;
                }
                const labelEl = document.getElementById('devChurchSelectedLabel');
                if (labelEl) labelEl.textContent = activeLabel;
            }

            // Clear students cache
            localStorage.removeItem('lastStudentsData');

            // Reset current class view and switch back to main grid
            disableBulkSelectMode();
            isCombinedView = false;
            combinedGroupLabel = '';
            combinedStudents = [];
            localStorage.removeItem('currentClass');
            const classesView = document.getElementById('classesView');
            const classView = document.getElementById('classView');
            if (classesView) classesView.style.display = 'flex';
            if (classView) classView.classList.remove('active');
            currentClass = '';
            location.hash = '';

            updateSwitchedChurchHeader();

            // Load data for switched church
            loadData();
        }

        function updateSwitchedChurchHeader() {
            if (!isDeveloper) return;
            const select = document.getElementById('devChurchSelect');
            if (devViewChurchId > 0 && allChurchesCache.length) {
                const targetChurch = allChurchesCache.find(c => c.id == devViewChurchId);
                if (targetChurch) {
                    const topbarTitle = document.querySelector('.topbar-title');
                    if (topbarTitle) topbarTitle.textContent = targetChurch.church_name;
                    document.title = 'Sunday School — ' + targetChurch.church_name;
                    return;
                }
            }
            // fallback
            const origChurchName = localStorage.getItem('churchName') || 'مدارس الأحد';
            const topbarTitle = document.querySelector('.topbar-title');
            if (topbarTitle) topbarTitle.textContent = origChurchName;
            document.title = 'Sunday School — ' + origChurchName;
        }

        window.addEventListener('online', _updateOnlineStatus);
        window.addEventListener('offline', _updateOnlineStatus);
        document.addEventListener('DOMContentLoaded', async () => {
            initDevSwitcher();
            localStorage.setItem('lastVisitedPortal', 'uncle_dashboard');
            // On first load: only show the offline banner if we're already offline.
            // Do NOT run the "came back online" reconnect logic — that's for transitions only.
            const onlineNow = await _isActuallyOnline(true);
            if (!onlineNow) {
                const banner = document.getElementById('offlineBanner');
                if (banner) banner.classList.add('show');
                _wasOffline = true;
            } else {
                const banner = document.getElementById('offlineBanner');
                if (banner) banner.classList.remove('show');
            }
            _updateNotifBtnVisibility();
            updateOfflineSyncIndicator();
            // Hide bulk-add button unless the user is an admin/developer
            try {
                const role = (window.currentUncle && window.currentUncle.role) || localStorage.getItem('uncleRole') || '';
                ['bulkAddKidsBtn', 'homeBulkAddKidsBtn', 'allToolsBulkAddBtn'].forEach(id => {
                    const bulkBtn = document.getElementById(id);
                    if (bulkBtn && !['admin', 'developer'].includes(String(role).toLowerCase())) {
                        bulkBtn.style.display = 'none';
                    }
                });
            } catch (e) { }
            // React to permission changes live (Chrome 93+)
            if ('permissions' in navigator) {
                navigator.permissions.query({ name: 'notifications' }).then(status => {
                    status.onchange = () => _updateNotifBtnVisibility();
                }).catch(() => { });
            }

            // Check if ?tab=pending or #pending was opened
            const urlParams = new URLSearchParams(window.location.search);
            if (urlParams.get('tab') === 'pending' || window.location.hash === '#pending') {
                setTimeout(() => {
                    const body = document.getElementById('pendingBody');
                    const btn = document.getElementById('pendingCollapseBtn');
                    if (body && body.style.display === 'none') {
                        body.style.display = 'block';
                        btn?.classList.add('open');
                    }
                    document.getElementById('pendingRegistrationsSection')?.scrollIntoView({ behavior: 'smooth' });
                }, 1000);
            }
        });

        // ══════════════════════════════════════════════════════════════
        // SWIPE MODE
        // ══════════════════════════════════════════════════════════════
        let _swipeList = [];      // students yet to swipe
        let _swipeIdx = 0;       // current index
        let _swipePres = 0;       // present count
        let _swipeAbs = 0;       // absent count
        let _swipeStartX = 0, _swipeStartY = 0, _swipeCurX = 0;
        let _swipeDragging = false, _swipeCard = null;
        const SWIPE_THRESHOLD = 80; // px to commit a swipe

        function _sortSwipeRemaining() {
            const done = _swipeList.slice(0, _swipeIdx);
            const remaining = sortStudentsForCurrentView(_swipeList.slice(_swipeIdx));
            _swipeList = done.concat(remaining);
            _renderSwipeCard();
            _updateSwipeProgress();
        }

        function startSwipeMode() {
            const src = (currentClass === 'الخدام')
                ? (window.allUnclesData || [])
                : (isCombinedView ? combinedStudents : students.filter(s => s['الفصل'] === currentClass));
            if (!src.length) {
                const emptyMsg = (currentClass === 'الخدام') ? 'لا يوجد خدام في هذا الفصل' : 'لا يوجد أطفال في هذا الفصل';
                showToast(emptyMsg, 'info');
                return;
            }
            _swipeList = sortStudentsForCurrentView(src);
            _swipeIdx = 0;
            _swipePres = 0;
            _swipeAbs = 0;
            const btns = document.querySelector('.swipe-btns');
            const hints = document.querySelector('.swipe-hints');
            if (btns) btns.style.display = '';
            if (hints) hints.style.display = '';
            const lbl = document.getElementById('swipeClassLabel');
            if (lbl) lbl.textContent = currentClass || '';
            const swipeSortSelect = document.getElementById('swipeSortSelect');
            if (swipeSortSelect) swipeSortSelect.value = classSortMode || 'name_az';
            document.getElementById('swipeOverlay').classList.add('active');
            document.body.style.overflow = 'hidden';
            _renderSwipeCard();
            _updateSwipeProgress();
        }

        function exitSwipeMode() {
            document.getElementById('swipeOverlay').classList.remove('active');
            document.body.style.overflow = '';
        }

        function _renderSwipeCard() {
            const card = document.getElementById('swipeCard');
            if (!card) return;
            card.style.transition = '';
            card.style.transform = 'translateX(0) rotate(0deg)';
            card.style.opacity = '1';

            if (_swipeIdx >= _swipeList.length) { _showSwipeDone(); return; }

            const s = _swipeList[_swipeIdx];
            const id = getStudentId(s);
            const st = attendanceData[id] || 'pending';
            const totC = (parseInt(s['كوبونات'] || 0)) + (parseInt(couponData[id] || 0));
            const left = _swipeList.length - _swipeIdx - 1;

            const prevPill =
                st === 'present' ? `<span class="swipe-prev-pill present"><i class="fas fa-check"></i> حضر سابقاً</span>` :
                    st === 'absent' ? `<span class="swipe-prev-pill absent"><i class="fas fa-times"></i> غائب سابقاً</span>` :
                        `<span class="swipe-prev-pill pending"><i class="fas fa-minus"></i> لا بيانات</span>`;

            const photoEl = s['صورة']
                ? `<img class="swipe-card-photo" src="${s['صورة']}" alt=""
               onerror="this.outerHTML='<div class=\\'swipe-card-photo-placeholder\\'><i class=\\'fas fa-user\\'></i><span>لا توجد صورة</span></div>'">`
                : `<div class="swipe-card-photo-placeholder"><i class="fas fa-user"></i><span>لا توجد صورة</span></div>`;

            const rightPill = s._isUncle
                ? `<div class="swipe-coupon-pill" style="background:var(--brand);color:white;font-weight:700;"><i class="fas fa-user-shield" style="font-size:.65rem"></i> ${s.role === 'admin' ? 'مسؤول' : (s.role === 'developer' || s.role === 'dev' ? 'مطور' : 'خادم')}</div>`
                : `<div class="swipe-coupon-pill"><i class="fas fa-star" style="font-size:.65rem"></i> ${totC}</div>`;

            card.innerHTML = `
        ${photoEl}
        <div class="swipe-card-wash" id="swipeCardWash"></div>
        <div class="swipe-stamp present-stamp" id="swipeStampPresent"><i class="fas fa-check-circle"></i> حضر</div>
        <div class="swipe-stamp absent-stamp"  id="swipeStampAbsent"><i class="fas fa-times-circle"></i> غاب</div>
        <div class="swipe-card-info">
            <div class="swipe-info-row1">
                <div class="swipe-card-name">${s['الاسم'] || '---'}</div>
                ${rightPill}
            </div>
            <div class="swipe-info-row2">
                <span class="swipe-class-pill">${s['الفصل'] || ''}</span>
                ${prevPill}
                ${left > 0 ? `<span class="swipe-remaining-pill">${left} متبقي</span>` : ''}
            </div>
        </div>`;

            const fresh = card.cloneNode(true);
            fresh.className = 'swipe-card';
            // Apply pre-assigned border class before replacing
            if (st === 'present') fresh.classList.add('pre-present');
            else if (st === 'absent') fresh.classList.add('pre-absent');
            card.parentNode.replaceChild(fresh, card);
            _swipeCard = document.getElementById('swipeCard');
            _attachSwipeListeners(_swipeCard);
        }

        function _attachSwipeListeners(card) {
            // Touch
            card.addEventListener('touchstart', e => {
                _swipeStartX = e.touches[0].clientX;
                _swipeStartY = e.touches[0].clientY;
                _swipeCurX = 0;
                _swipeDragging = true;
                card.classList.add('dragging');
            }, { passive: true });

            card.addEventListener('touchmove', e => {
                if (!_swipeDragging) return;
                _swipeCurX = e.touches[0].clientX - _swipeStartX;
                _animateDrag(card, _swipeCurX);
            }, { passive: true });

            card.addEventListener('touchend', () => {
                card.classList.remove('dragging');
                _commitSwipe(card, _swipeCurX);
                _swipeDragging = false;
            });

            // Mouse
            card.addEventListener('mousedown', e => {
                _swipeStartX = e.clientX;
                _swipeCurX = 0;
                _swipeDragging = true;
                card.classList.add('dragging');
                e.preventDefault();
            });
            // Inject Rooms Stylesheet
            (function () {
                const style = document.createElement('style');
                style.textContent = `
          .rooms-ws-container { display: grid; grid-template-columns: 300px 1fr; gap: 20px; direction: rtl; margin-top: 15px; }
          .rooms-sidebar { background: var(--surface); border: 1.5px solid var(--border); border-radius: 12px; padding: 16px; display: flex; flex-direction: column; gap: 12px; max-height: 75vh; overflow-y: auto; }
          .rooms-sidebar-overlay { display: none; }
          .rooms-mobile-toggle-btn { display: none; }
