            .rooms-actions-row > div { width: 100%; }
            .rooms-actions-row > div:last-child input { width: 100% !important; }
            .ws-room-search-popover {
              width: auto;
              left: -10px;
              right: -10px;
              max-width: calc(100vw - 40px);
            }
            .ws-kid-action-btn { padding: 6px; font-size: 0.85rem; }
          }
        `;
                document.head.appendChild(style);
            })();
            document.addEventListener('mousemove', e => {
                if (!_swipeDragging) return;
                _swipeCurX = e.clientX - _swipeStartX;
                _animateDrag(card, _swipeCurX);
            });
            document.addEventListener('mouseup', () => {
                if (!_swipeDragging) return;
                card.classList.remove('dragging');
                _commitSwipe(card, _swipeCurX);
                _swipeDragging = false;
            });
        }

        function _animateDrag(card, dx) {
            const rot = dx / 14;
            const prog = Math.min(Math.abs(dx) / SWIPE_THRESHOLD, 1);
            card.style.transform = `translateX(${dx}px) rotate(${rot}deg)`;
            // Labels
            const lP = document.getElementById('swipeStampPresent');
            const lA = document.getElementById('swipeStampAbsent');
            const ti = document.getElementById('swipeCardWash');
            if (lP) lP.style.opacity = dx > 20 ? Math.min((dx - 20) / 60, 1) : 0;
            if (lA) lA.style.opacity = dx < -20 ? Math.min((-dx - 20) / 60, 1) : 0;
            if (ti) {
                if (dx > 20) { ti.style.background = `rgba(16,185,129,${prog * 0.15})`; ti.style.opacity = 1; }
                else if (dx < -20) { ti.style.background = `rgba(239,68,68,${prog * 0.15})`; ti.style.opacity = 1; }
                else { ti.style.opacity = 0; }
            }
            // Also tint the hint arrows
            const hL = document.querySelector('.swipe-hint-left');
            const hR = document.querySelector('.swipe-hint-right');
            if (hL) hL.style.opacity = dx < -20 ? Math.min(0.18 + (-dx - 20) / 120, 0.9) : 0.18;
            if (hR) hR.style.opacity = dx > 20 ? Math.min(0.18 + (dx - 20) / 120, 0.9) : 0.18;
        }

        function _commitSwipe(card, dx) {
            _resetDragVisuals(card);
            if (Math.abs(dx) >= SWIPE_THRESHOLD) {
                if (dx > 0) swipeDecide('present');
                else swipeDecide('absent');
            } else {
                // Spring back
                card.style.transition = 'transform .35s var(--spring)';
                card.style.transform = 'translateX(0) rotate(0deg)';
            }
        }

        function _resetDragVisuals(card) {
            const lP = document.getElementById('swipeStampPresent');
            const lA = document.getElementById('swipeStampAbsent');
            const ti = document.getElementById('swipeCardWash');
            if (lP) lP.style.opacity = 0;
            if (lA) lA.style.opacity = 0;
            if (ti) ti.style.opacity = 0;
            const hL = document.querySelector('.swipe-hint-left');
            const hR = document.querySelector('.swipe-hint-right');
            if (hL) hL.style.opacity = 0.18;
            if (hR) hR.style.opacity = 0.18;
        }

        function swipeDecide(verdict) {
            const card = document.getElementById('swipeCard');
            if (!card || _swipeIdx >= _swipeList.length) return;

            const s = _swipeList[_swipeIdx];
            const id = getStudentId(s);

            if (verdict === 'present') {
                // Apply to attendance state
                attendanceData[id] = 'present';
                const srv = originalAttendanceData[id] || 'pending';
                if ('present' !== srv) changedStudents.add(id); else changedStudents.delete(id);
                saveAttendanceDataForClass(currentClass); saveChangedStudentsToLocalStorage(currentClass);
                _swipePres++;
                card.style.transition = 'transform .32s ease, opacity .32s ease';
                card.style.transform = 'translateX(120vw) rotate(22deg)';
                card.style.opacity = '0';
                navigator.vibrate && navigator.vibrate(18);
            } else if (verdict === 'absent') {
                attendanceData[id] = 'absent';
                const srv = originalAttendanceData[id] || 'pending';
                if ('absent' !== srv) changedStudents.add(id); else changedStudents.delete(id);
                saveAttendanceDataForClass(currentClass); saveChangedStudentsToLocalStorage(currentClass);
                _swipeAbs++;
                card.style.transition = 'transform .32s ease, opacity .32s ease';
                card.style.transform = 'translateX(-120vw) rotate(-22deg)';
                card.style.opacity = '0';
                navigator.vibrate && navigator.vibrate(18);
            } else {
                // skip — fade up
                card.style.transition = 'transform .28s ease, opacity .28s ease';
                card.style.transform = 'translateY(-50px) scale(.88)';
                card.style.opacity = '0';
            }

            _swipeIdx++;
            _updateSwipeProgress();
            setTimeout(() => {
                _renderSwipeCard();
                // Also refresh the normal list in background
                renderAttendanceList(currentClass);
                updateClassStats();
                updateSaveBtns();
            }, 280);
        }

        function _updateSwipeProgress() {
            const total = _swipeList.length;
            const done = _swipeIdx;
            const fill = document.getElementById('swipeProgressFill');
            const ctr = document.getElementById('swipeCounter');
            const presC = document.getElementById('swipePresCount');
            const absC = document.getElementById('swipeAbsCount');
            if (fill) fill.style.width = total ? (done / total * 100) + '%' : '0%';
            if (ctr) ctr.textContent = `${Math.min(done + 1, total)} / ${total}`;
            if (presC) presC.innerHTML = `<i class="fas fa-check-circle"></i> ${_swipePres}`;
            if (absC) absC.innerHTML = `<i class="fas fa-times-circle"></i> ${_swipeAbs}`;
        }

        function _showSwipeDone() {
            const area = document.getElementById('swipeCardArea');
            const btns = document.querySelector('.swipe-btns');
            const hints = document.querySelector('.swipe-hints');
            const skip = _swipeList.length - _swipePres - _swipeAbs;
            if (area) area.innerHTML = `
        <div class="swipe-done">
            <div class="swipe-done-icon"><i class="fas fa-check"></i></div>
            <h2>انتهينا! 🎉</h2>
            <p>${window.t ? window.t('تم مراجعة جميع الأطفال') : 'تم مراجعة جميع الأطفال'} — اضغط زر الحفظ لرفع البيانات</p>
            <div class="swipe-done-stats">
                <div class="swipe-done-stat">
                    <span class="swipe-done-stat-val" style="color:var(--success)">${_swipePres}</span>
                    <span class="swipe-done-stat-lbl">حاضر</span>
                </div>
                <div class="swipe-done-stat">
                    <span class="swipe-done-stat-val" style="color:var(--danger)">${_swipeAbs}</span>
                    <span class="swipe-done-stat-lbl">غائب</span>
                </div>
                ${skip > 0 ? `<div class="swipe-done-stat">
                    <span class="swipe-done-stat-val" style="color:var(--text-3)">${skip}</span>
                    <span class="swipe-done-stat-lbl">تخطي</span>
                </div>` : ''}
            </div>
            <button class="btn" style="font-size:1rem;padding:12px 32px;border-radius:var(--r-full)" onclick="exitSwipeMode()">
                <i class="fas fa-arrow-right"></i> العودة للقائمة
            </button>
        </div>`;
            if (btns) btns.style.display = 'none';
            if (hints) hints.style.display = 'none';
        }



        // ── CLEAR ALL UNSAVED ─────────────────────────────────────────
        function _clearAllUnsaved() {
            if (!confirm('مسح جميع التغييرات غير المحفوظة؟ لا يمكن التراجع.')) return;
            const cls = isCombinedView ? (combinedGroupLabel || currentClass) : currentClass;

            // Clear in-memory attendance changes
            changedStudents.clear();
            const list = getActiveViewStudents();
            list.forEach(s => {
                const id = getStudentId(s);
                attendanceData[id] = originalAttendanceData[id] || 'pending';
            });

            // Clear all localStorage keys for this class
            Object.keys(localStorage).forEach(k => {
                if (k.startsWith(`changedStudents_${cls}_`) || k.startsWith(`attendanceData_${cls}_`)) {
                    localStorage.removeItem(k);
                }
            });

            // Clear coupon changes
            changedCouponStudents.clear();
            couponData = {};
            saveCouponDataForClass(cls);

            document.getElementById('unsavedModal').classList.remove('active');
            renderAttendanceList(currentClass);
            updateClassStats();
            updateSaveBtns();
            showToast('تم مسح جميع التغييرات', 'info');
        }

        // ══════════════════════════════════════════════════════════════
        // EXPOSE NEW FUNCTIONS GLOBALLY
        // ══════════════════════════════════════════════════════════════
        document.addEventListener('DOMContentLoaded', () => {
            // Instantly render from cache so the user sees content immediately (especially offline)
            const cached = localStorage.getItem('lastStudentsData');
            if (cached) {
                try {
                    const d = JSON.parse(cached);
                    students = d.students || d.allStudents || [];
                    allStudentsData = d.allStudents || d.students || students;
                    if (d.classes && d.classes.length) {
                        classes = d.classes.sort((a, b) => getClassOrderWeight(a.arabic_name || a.code) - getClassOrderWeight(b.arabic_name || b.code));
                    }
                    displayClasses(); // also calls renderTodayBirthdayBanner()
                    updateDashboardStats();
                    updateCurrentDateDisplay();
                } catch (e) { }
            }
            initApp();
        });

        // Global exposure
        Object.assign(window, {
            showClassView, showClassesView, showCombinedClassView, showAllTogetherView, markStudentAttendance, showStudentDetails,
            showCustomExportModal, showAllKidsCustomExport, toggleStats, toggleTripsCollapse, addCouponsToAll, resetCouponDataForClass, copyAttendedData, copyAbsentData,
            showImageModal, hideImageModal, showAddPersonModal, showBirthdayModal, showBirthdaysByMonth,
            showPastFridaysModal, loadFridayAttendance, performSearch, clearSearch, showRegistrationDetails,
            approveRegistration, rejectRegistration, toggleRegistrationSelection, searchPendingRegistrations,
            clearAllStudentsSearch, performAllStudentsSearch, showAnnouncementsModal, toggleAnnouncementStatus,
            deleteAnnouncement, adjustStudentCoupons, toggleCouponValue, closeAllDropdowns, logout,
            showAccountModal, showUncleHistory, showUncleFees, openUncleAccountPage, closeUncleAccountPage, retryConnection: () => { },
            resetToCurrentFriday, showUnsavedModal, toggleTheme, escJs,
            shareAbsentToWhatsApp, shareAttendedToWhatsApp, saveAttendedAsCSV,
            toggleAbsentDropdown, executeAbsentAction,
            toggleCustomExportField, moveCustomExportField, renderCustomExportPreview,
            exportCustomAsCSV, exportCustomPreviewAsImage, exportCustomPreviewAsPdf,
            requestNotifPermission, _updateNotifBtnVisibility, triggerPwaInstall, doPwaInstall, closePwaModal,
            _holdStart, _holdMove, _holdEnd, _holdCancel, _rowHoldStart, _rowHoldMove, _rowHoldEnd, _rowContextMenu, _ctxAction, _closeCtxMenu,
            _imgZoomChange, _imgZoomReset, _imgDownload,
            startSwipeMode, exitSwipeMode, swipeDecide,
            _removeUnsavedEntry, _removeUnsavedCoupon, _jumpToDate,
            _loadDataFromCache, _clearAllUnsaved, addCustomDate, removeCustomDate, toggleCustomDateSection, autoFormatCustomDate,
            _sendSyncCompletePush, _sendUnclMetaToSW,
            showAllTogetherView,
            renderTodayBirthdayBanner, getTodayBirthdays, _maybeSendBirthdayNotification, _sendBirthdayPush, _updateAttendanceRow
        });

        // ══════════════════════════════════════════════════════════════
        // YOUTH VOCABULARY ENGINE — auto-swap all kids terms to youth
        // ══════════════════════════════════════════════════════════════
        (function _initYouthMode() {
            if (!window.IS_YOUTH) return;

            // ── 1. Apply accent colour override for youth (purple palette) ──
            const style = document.createElement('style');
            style.id = 'youth-theme';
            style.textContent = `
        :root {
            --brand:        #7c3aed !important;
            --brand-dark:   #5b21b6 !important;
            --brand-light:  #c4b5fd !important;
            --brand-bg:     #ede9fe !important;
            --brand-glow:   rgba(124,58,237,.18) !important;
        }
        /* Youth badge shown in class chips */
        .youth-badge {
            display:inline-flex;align-items:center;gap:4px;
            background:#ede9fe;color:#5b21b6;
            font-size:0.65rem;font-weight:700;
            padding:2px 7px;border-radius:20px;
        }
    `;
            document.head.appendChild(style);

            // ── 2. First full-page vocab pass on DOMContentLoaded ──
            document.addEventListener('DOMContentLoaded', () => {
                window.applyYouthVocab();
            });

            // ── 3. MutationObserver — re-runs swap whenever DOM updates ──
            //       Debounced to avoid thrashing during heavy renders.
            let _vocabTimer = null;
            const observer = new MutationObserver(() => {
                clearTimeout(_vocabTimer);
                _vocabTimer = setTimeout(() => window.applyYouthVocab(), 80);
            });
            document.addEventListener('DOMContentLoaded', () => {
                observer.observe(document.body, {
                    childList: true,
                    subtree: true,
                    characterData: false  // text-node changes handled by childList
                });
            });

            // ── 4. Patch showToast so runtime toasts are also translated ──
            const _origShowToast = window.showToast;
            if (typeof _origShowToast === 'function') {
                window.showToast = function (msg, type) {
                    return _origShowToast(window.t ? window.t(msg) : msg, type);
                };
            }
        })();

        // ══════════════════════════════════════════════════════════
        // UNIFIED NOTIFICATIONS (DB + push)
        // ══════════════════════════════════════════════════════════
        let _notifPanelOpen = false;
        let _notifData = [];

        async function loadUnifiedNotifications() {
            if (!navigator.onLine) return;
            try {
                const fd = new FormData();
                fd.append('action', 'getNotifications');
                const d = await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' }).then(r => r.json());
                if (!d.success) return;
                _notifData = d.notifications || [];
                const unread = d.unread_count || 0;
                // Update bell badge
                const badge = document.getElementById('notifBellBadge');
                if (badge) {
                    if (unread > 0) {
                        badge.textContent = unread > 99 ? '99+' : unread;
                        badge.style.display = 'flex';
                    } else {
                        badge.style.display = 'none';
                    }
                }
                // Update task submission badge
                const taskSubCount = _notifData.filter(n => n.type === 'task_submission' && n.is_read == 0).length;
                const dot = document.getElementById('tasksSubmissionDot');
                const globalBadge = document.getElementById('globalTasksBadge');
                if (dot) { dot.style.display = taskSubCount > 0 ? 'flex' : 'none'; if (taskSubCount > 0) dot.textContent = taskSubCount > 9 ? '9+' : taskSubCount; }
                if (globalBadge) { if (taskSubCount > 0) { globalBadge.style.display = 'flex'; globalBadge.textContent = taskSubCount > 9 ? '9+' : taskSubCount; } else globalBadge.style.display = 'none'; }
                // Re-render if panel open
                if (_notifPanelOpen) renderNotifPanel();
            } catch (e) { }
        }

        function renderNotifPanel() {
            const el = document.getElementById('notifPanelList');
            if (!el) return;
            if (!_notifData.length) {
                el.innerHTML = `<div class="nps-empty">
            <div class="nps-empty-icon"><i class="fas fa-bell-slash"></i></div>
            <strong style="color:var(--text-2);font-size:.92rem;">لا توجد إشعارات</strong>
            <span>ستظهر هنا أحدث التنبيهات والتحديثات</span>
        </div>`;
                return;
            }
            const typeIcon = {
                registration: 'fa-user-plus',
                task_submission: 'fa-paper-plane',
                developer_message: 'fa-envelope',
                system: 'fa-circle-check',
                announcement: 'fa-bullhorn',
            };
            const typeLabel = {
                registration: 'تسجيل جديد',
                task_submission: 'مهمة',
                developer_message: 'رسالة',
                system: 'نظام',
                announcement: 'إعلان',
            };
            const typeAction = {
                registration: 'عرض الطلبات',
                task_submission: 'فتح المهام',
                developer_message: 'فتح الرسالة',
                announcement: 'عرض الإعلان',
            };
            const typeUrl = {
                registration: '#pending',
                task_submission: currentClass
                    ? `/uncle/dashboard/tasks?class=${encodeURIComponent(currentClass)}`
                    : '/uncle/dashboard/tasks/',
                developer_message: '/uncle/dashboard/', // Fallback, will be overridden dynamically
                announcement: '/uncle/dashboard/',
            };
            el.innerHTML = _notifData.map(n => {
                const icon = typeIcon[n.type] || 'fa-bell';
                const label = typeLabel[n.type] || '';
                const action = typeAction[n.type];

                // Override developer message dynamically with actual redirect_url if available
                let url = typeUrl[n.type] || '';
                if (n.type === 'developer_message') {
                    url = n.redirect_url || '/uncle/dashboard/';
                }

                const typeClass = 'type-' + (n.type || 'default');
                const t = new Date(n.created_at).toLocaleString('ar-EG', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
                return `<div class="nps-item ${n.is_read == 0 ? 'unread' : ''}" onclick="onUnifNotifClick(${n.id}, '${n.type}', '${url || ''}')">
            <div style="display:flex;align-items:flex-start;gap:12px;">
                <div class="nps-icon ${typeClass}"><i class="fas ${icon}"></i></div>
                <div style="flex:1;min-width:0;">
                    ${label ? `<div style="font-size:.64rem;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--text-3);margin-bottom:3px;">${label}</div>` : ''}
                    <div class="nps-item-title">${escStr(n.title)}</div>
                    ${n.body ? `<div class="nps-item-body">${escStr(n.body)}</div>` : ''}
                    <div class="nps-item-footer">
                        <span class="nps-item-time"><i class="fas fa-clock"></i> ${t}</span>
                        ${action ? `<span class="nps-item-action"><i class="fas fa-arrow-left"></i> ${action}</span>` : ''}
                    </div>
                </div>
                ${n.is_read == 0 ? '<div class="nps-unread-dot" style="margin-top:4px;flex-shrink:0;"></div>' : ''}
                <button onclick="deleteUnifNotif(event,${n.id})" class="nps-delete-btn" title="حذف"><i class="fas fa-trash" style="font-size:.72rem;"></i></button>
            </div>
        </div>`;
            }).join('');
        }

        async function onUnifNotifClick(id, type, url) {
            // Mark read
            const fd = new FormData(); fd.append('action', 'markNotificationRead'); fd.append('id', id);
            fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' });
            const notif = _notifData.find(n => n.id === id);
            if (notif) notif.is_read = 1;
            loadUnifiedNotifications();
            // Navigate
            toggleNotifPanel();

            if (type === 'registration') {
                const body = document.getElementById('pendingBody');
                const btn = document.getElementById('pendingCollapseBtn');
                if (body && body.style.display === 'none') {
                    body.style.display = 'block';
                    btn?.classList.add('open');
                }
                setTimeout(() => {
                    document.getElementById('pendingRegistrationsSection')?.scrollIntoView({ behavior: 'smooth' });
                }, 100);
            } else if (url) {
                setTimeout(() => window.location.href = url, 200);
            }
        }

        async function deleteUnifNotif(e, id) {
            e.stopPropagation();
            const fd = new FormData(); fd.append('action', 'deleteNotification'); fd.append('id', id);
            await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' });
            _notifData = _notifData.filter(n => n.id !== id);
            renderNotifPanel();
            loadUnifiedNotifications();
        }

        async function markAllNotifsRead() {
            const fd = new FormData(); fd.append('action', 'markAllNotificationsRead');
            await fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' });
            _notifData.forEach(n => n.is_read = 1);
            renderNotifPanel();
            loadUnifiedNotifications();
        }

        function toggleNotifPanel() {
            _notifPanelOpen = !_notifPanelOpen;
            const overlay = document.getElementById('notifPanelOverlay');
            if (overlay) {
                overlay.classList.toggle('open', _notifPanelOpen);
                document.body.style.overflow = _notifPanelOpen ? 'hidden' : '';
            }
            if (_notifPanelOpen) { loadUnifiedNotifications(); renderNotifPanel(); }
        }

        function getClassOrderWeight(name) {
            if (!name) return 999;
            const clean = name.trim();
            if (clean.includes('حضانة')) return 1;
            if (clean.includes('أولى') || clean.includes('اولى')) return 2;
            if (clean.includes('تانية') || clean.includes('ثانية')) return 3;
            if (clean.includes('تالتة') || clean.includes('ثالثة')) return 4;
            if (clean.includes('رابعة')) return 5;
            if (clean.includes('خامسة')) return 6;
            if (clean.includes('سادسة') || clean.includes('سادسه')) return 7;
            if (clean.includes('سابعة')) return 8;
            if (clean.includes('ثامنة')) return 9;
            return 100 + clean.localeCompare('', 'ar');
        }

        // ── INTELLIGENT SEARCH ──────────────────────────────────────────
        function normalizeArabic(text) {
            if (!text) return "";
            return String(text)
                .replace(/[أإآٱ]/g, "ا")
                .replace(/[ىئ]/g, "ي")
                .replace(/ة/g, "ه")
                .replace(/ؤ/g, "و")
                .replace(/[\u064B-\u0652]/g, "") // Remove Harakat
                .toLowerCase()
                .trim();
        }

        /**
         * Egyptian Franco (Franko) Arabic → Arabic transliteration
         * Converts Latin-letter input like "mo7amed" → "محامد"
         * Handles multi-char combos first, then single chars + numbers.
         */
        function francoToArabic(text) {
            if (!text) return "";
            let s = text.toLowerCase().trim();

            // Check if the input has any Latin characters; if purely Arabic, skip
            if (!/[a-z0-9]/.test(s)) return "";

            // Multi-character combos (order matters – longest first)
            const multiMap = [
                ['sh', 'ش'], ['ch', 'تش'], ['kh', 'خ'], ['gh', 'غ'],
                ['th', 'ث'], ['dh', 'ذ'], ['zh', 'ج'],
                ['ph', 'ف'],
                ['ou', 'و'], ['oo', 'و'], ['ee', 'ي'], ['ei', 'اي'],
                ['aa', 'ا'], ['ii', 'ي'],
            ];
            for (const [from, to] of multiMap) {
                s = s.split(from).join(to);
            }

            // Single-character map (includes number substitutions)
            const singleMap = {
                'a': 'ا', 'b': 'ب', 't': 'ت', 'g': 'ج', 'j': 'ج',
                'h': 'ح', 'd': 'د', 'r': 'ر', 'z': 'ز', 's': 'س',
                'c': 'ك',
                'f': 'ف', 'q': 'ق', 'k': 'ك', 'l': 'ل', 'm': 'م',
                'n': 'ن', 'w': 'و', 'u': 'و', 'o': 'و',
                'y': 'ي', 'i': 'ي', 'e': 'ي',
                'x': 'اكس', 'v': 'ف', 'p': 'ب',
                // Number substitutions (Egyptian Franco convention)
                '2': 'ء', '3': 'ع', '4': 'ش', '5': 'خ',
                '6': 'ط', '7': 'ح', '8': 'غ', '9': 'ق',
            };

            let result = '';
            for (let i = 0; i < s.length; i++) {
                const ch = s[i];
                if (singleMap[ch]) {
                    result += singleMap[ch];
                } else if (ch === ' ' || ch === '-' || ch === '_') {
                    result += ' ';
                } else {
                    // Keep Arabic characters that might already be mixed in
                    result += ch;
                }
            }
            return normalizeArabic(result);
        }

        function arabicToLatin(text) {
            if (!text) return "";
            let s = text.toLowerCase().trim();
            // Check if the input contains any Arabic characters; if not, skip
            if (!/[\u0600-\u06FF]/.test(s)) return "";

            // Normalize first to simplify maps
            s = normalizeArabic(s);

            // Multi-character maps (important combinations)
            const multiMap = [
                ['ش', 'sh'], ['خ', 'kh'], ['غ', 'gh'], ['ث', 'th'],
                ['ذ', 'dh'], ['ج', 'g'], ['ف', 'f'], ['ع', '3'],
                ['ط', '6'], ['ح', '7']
            ];
            for (const [from, to] of multiMap) {
                s = s.split(from).join(to);
            }

            // Single-character maps
            const singleMap = {
                'ا': 'a', 'ب': 'b', 'ت': 't', 'ة': 'a',
                'د': 'd', 'ر': 'r', 'ز': 'z', 'س': 's', 'ص': 's', 'ض': 'd',
                'ق': 'q', 'ك': 'k', 'ل': 'l', 'م': 'm', 'ن': 'n',
                'ه': 'h', 'و': 'w', 'ي': 'y', 'ى': 'y', 'ئ': 'e', 'ء': '2', 'ؤ': 'o'
            };

            let result = '';
            for (let i = 0; i < s.length; i++) {
                const ch = s[i];
                if (singleMap[ch]) {
                    result += singleMap[ch];
                } else if (ch === ' ' || ch === '-' || ch === '_') {
                    result += ' ';
                } else {
                    result += ch;
                }
            }
            return result;
        }

        function phoneticClean(str) {
            if (!str) return "";
            let s = str.toLowerCase().trim();
            s = s.replace(/p/g, 'b');      // p and b are equivalent in Arabic transliteration
            s = s.replace(/v/g, 'f');      // v and f/ph
            s = s.replace(/c/g, 'k');      // c and k
            s = s.replace(/q/g, 'k');      // q and k
            s = s.replace(/j/g, 'g');      // j and g (e.g. George)
            s = s.replace(/z/g, 's');      // z and s (e.g. Girgis/Gerges)
            s = s.replace(/x/g, 'ks');
            s = s.replace(/[aeiouywh]/g, ''); // strip all vowels and silent letters (h, w)
            return s;
        }

        function getMatchScore(student, query) {
            const dbId = String(getStudentDbId(student));
            const queryClean = query.trim();
            if (dbId && queryClean && dbId === queryClean) {
                return 10000;
            }

            const qNormalized = normalizeArabic(query);
            const qRaw = query.trim().toLowerCase();
            const qFranco = francoToArabic(query); // Franco → Arabic conversion
            const qLatin = arabicToLatin(query);   // Arabic → Latin conversion
            const qPhonetic = phoneticClean(query.includes(' ') ? query : (qLatin || qRaw));

            let maxScore = 0;
            const fields = [
                { val: student['الاسم'] || student['name'], weight: 1.0 },
                { val: student['الفصل'] || student['class'] || student['class_name'], weight: 0.7 },
                { val: student['_studentId'] || student['id'] || student['معرف'] || student['id_student'] || student['uncle_id'], weight: 1.1 },
                { val: student['رقم التليفون'] || student['phone'], weight: 1.1 },
                { val: student['تليفون الطوارئ'] || student['emergency_phone'], weight: 1.1 },
                { val: student['username'], weight: 1.0 }
            ];

            fields.forEach(field => {
                if (!field.val) return;
                const target = String(field.val);
                const tNormalized = normalizeArabic(target);
                const tRaw = target.toLowerCase();
                const tLatin = arabicToLatin(target); // Convert target name to Latin if it's Arabic
                const tPhonetic = phoneticClean(tLatin || tRaw);
                let currentScore = 0;

                if (tRaw === qRaw || tNormalized === qNormalized) currentScore = 100;
                else if (tRaw.startsWith(qRaw) || tNormalized.startsWith(qNormalized)) currentScore = 80;
                else if (tRaw.includes(qRaw) || tNormalized.includes(qNormalized)) currentScore = 60;
                // Franco Arabic matching (transliterated English query vs Arabic name field)
                else if (qFranco && tNormalized === qFranco) currentScore = 92;
                else if (qFranco && tNormalized.startsWith(qFranco)) currentScore = 72;
                else if (qFranco && tNormalized.includes(qFranco)) currentScore = 52;
                // Latin conversion matching (transliterated Arabic query vs English/Latin name field)
                else if (qLatin && tRaw === qLatin) currentScore = 92;
                else if (qLatin && tRaw.startsWith(qLatin)) currentScore = 72;
                else if (qLatin && tRaw.includes(qLatin)) currentScore = 52;
                // Target conversion matching (English/Latin query vs transliterated Arabic target name)
                else if (tLatin && tLatin === qRaw) currentScore = 90;
                else if (tLatin && tLatin.startsWith(qRaw)) currentScore = 70;
                else if (tLatin && tLatin.includes(qRaw)) currentScore = 50;
                // Phonetic consonant matching
                else if (qPhonetic && tPhonetic && tPhonetic === qPhonetic) currentScore = 88;
                else if (qPhonetic && tPhonetic && tPhonetic.startsWith(qPhonetic)) currentScore = 68;
                else if (qPhonetic && tPhonetic && tPhonetic.includes(qPhonetic)) currentScore = 48;
                else {
                    let score = 0, queryIdx = 0;
                    for (let i = 0; i < tNormalized.length && queryIdx < qNormalized.length; i++) {
                        if (tNormalized[i] === qNormalized[queryIdx]) { queryIdx++; score++; }
                    }
                    if (queryIdx === qNormalized.length) currentScore = (score / tNormalized.length) * 40;

                    if (qFranco) {
                        // Forward: Franco query chars found in order inside target
                        let fScore = 0, fIdx = 0;
                        for (let i = 0; i < tNormalized.length && fIdx < qFranco.length; i++) {
                            if (tNormalized[i] === qFranco[fIdx]) { fIdx++; fScore++; }
                        }
                        if (fIdx === qFranco.length) {
                            currentScore = Math.max(currentScore, (fScore / tNormalized.length) * 38);
                        }

                        // Reverse: target chars found in order inside Franco query
                        let rScore = 0, rIdx = 0;
                        for (let i = 0; i < qFranco.length && rIdx < tNormalized.length; i++) {
                            if (qFranco[i] === tNormalized[rIdx]) { rIdx++; rScore++; }
                        }
                        if (rIdx === tNormalized.length) {
                            const ratio = tNormalized.length / qFranco.length;
                            currentScore = Math.max(currentScore, ratio * 70);
                        }
                    }
                }
                maxScore = Math.max(maxScore, currentScore * field.weight);
            });
            return maxScore;
        }

        function openIntelligentSearchModal() {
            document.getElementById('intelligentSearchModal').classList.add('active');
            document.getElementById('intelligentSearchInput').value = '';
            document.getElementById('intelligentSearchResults').innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-3);font-size:0.9rem"><i class="fas fa-search" style="font-size:2rem;opacity:0.2;margin-bottom:10px;display:block"></i>اكتب للبحث...</div>';
            setTimeout(() => document.getElementById('intelligentSearchInput').focus(), 100);
        }

        function closeIntelligentSearchModal() {
            document.getElementById('intelligentSearchModal').classList.remove('active');
        }

        function performIntelligentSearch() {
            const q = document.getElementById('intelligentSearchInput').value.trim();
            const container = document.getElementById('intelligentSearchResults');

            if (!q) {
                container.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-3);font-size:0.9rem"><i class="fas fa-search" style="font-size:2rem;opacity:0.2;margin-bottom:10px;display:block"></i>اكتب للبحث...</div>';
                return;
            }

            const searchData = allStudentsData.length ? allStudentsData : students;
            if (!searchData || !searchData.length) {
                container.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-3);font-size:0.9rem">البيانات غير متاحة. الرجاء التأكد من الاتصال بالإنترنت.</div>';
                return;
            }

            let results = searchData.map(s => ({ ...s, _searchScore: getMatchScore(s, q) }))
                .filter(s => s._searchScore > 0)
                .sort((a, b) => b._searchScore - a._searchScore)
                .slice(0, 50); // Limit to top 50

            if (!results.length) {
                container.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-3);font-size:0.9rem">لا توجد نتائج مطابقة</div>';
                return;
            }

            container.innerHTML = results.map(s => {
                const name = s['الاسم'] || '---';
                const cls = s['الفصل'] || '---';
                const id = s['_studentId'] || s['id'] || s['معرف'] || s['id_student'] || 0;
                const photo = s['صورة']
                    ? `<img src="${window.photoUrl ? window.photoUrl(s['صورة']) : s['صورة']}" style="width:36px;height:36px;border-radius:50%;object-fit:cover;">`
                    : `<div style="width:36px;height:36px;border-radius:50%;background:var(--brand-bg);color:var(--brand);display:flex;align-items:center;justify-content:center;"><i class="fas fa-user"></i></div>`;
                const isExactIdMatch = String(id).trim() === q.trim();

                return `
                <div style="background:var(--surface-2); padding:10px 14px; border-radius:10px; border:1px solid var(--border-solid); display:flex; align-items:center; gap:10px; cursor:pointer; transition:all 0.2s;" onmouseover="this.style.background='var(--surface-3)'" onmouseout="this.style.background='var(--surface-2)'" onclick="selectStudentFromIntelligentSearch(${id})">
                    ${photo}
                    <div style="flex:1; overflow:hidden;">
                        <div style="font-weight:700; color:var(--text); font-size:0.95rem; display:flex; align-items:center; gap:6px; overflow:hidden;">
                            <span style="white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${name}</span>
                            ${isExactIdMatch ? `<span style="background:var(--brand); color:#fff; font-size:0.65rem; padding:2px 6px; border-radius:4px; font-weight:bold; white-space:nowrap; flex-shrink:0;">ID: ${id}</span>` : ''}
                        </div>
                        <div style="font-size:0.75rem; color:var(--text-3);"><i class="fas fa-chalkboard-teacher"></i> ${cls}</div>
                    </div>
                    <div style="font-size:0.8rem; color:var(--brand); font-weight:700;"><i class="fas fa-chevron-left"></i></div>
                </div>`;
            }).join('');
        }

        function selectStudentFromIntelligentSearch(studentId) {
            const searchData = allStudentsData.length ? allStudentsData : students;
            const s = searchData.find(x => x['_studentId'] == studentId || x['id'] == studentId || x['معرف'] == studentId || x['id_student'] == studentId);
            if (!s) return;

            closeIntelligentSearchModal();

            ['inlineSearchDropdown', 'topbarSearchDropdown'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.classList.remove('show');
            });
            ['inlineSearchInput', 'topbarSearchInput'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.value = '';
            });
            ['clearInlineSearchBtn', 'clearTopbarSearchBtn'].forEach(id => {
                const el = document.getElementById(id);
                if (el) el.style.display = 'none';
            });

            // Go to his class
            if (s['الفصل']) {
                showClassView(s['الفصل']);

                // Wait for render, then scroll to row and highlight
                setTimeout(() => {
                    const rowId = `ai-${s['الفصل']}_${s['الاسم']}`;
                    const row = document.getElementById(rowId);
                    if (row) {
                        row.scrollIntoView({ behavior: 'smooth', block: 'center' });
                        // Add a temporary highlight class or style
                        const originalBg = row.style.background;
                        row.style.transition = 'background 0.5s ease';
                        row.style.background = 'var(--brand-glow)';
                        setTimeout(() => {
                            row.style.background = originalBg;
                        }, 2000);

                        // Open his menu
                        setTimeout(() => {
                            showStudentDetails(s['الاسم']);
                        }, 300);
                    } else {
                        // If row not found, just open menu
                        showStudentDetails(s['الاسم']);
                    }
                }, 300);
            } else {
                // If no class, just open his menu
                showStudentDetails(s['الاسم']);
            }
        }

        function _renderInlineSearchResults(q, source = 'inline') {
            const container = document.getElementById(source === 'topbar' ? 'topbarSearchDropdown' : 'inlineSearchDropdown');
            const clearBtn = document.getElementById(source === 'topbar' ? 'clearTopbarSearchBtn' : 'clearInlineSearchBtn');
            if (!container) return;

            if (clearBtn) {
                clearBtn.style.display = q ? 'flex' : 'none';
            }

            if (!q) {
                container.innerHTML = '';
                container.classList.remove('show');
                return;
            }

            const searchData = allStudentsData.length ? allStudentsData : students;
            if (!searchData || !searchData.length) {
                container.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-3);font-size:0.85rem;">البيانات غير متاحة.</div>';
                container.classList.add('show');
                return;
            }

            let results = searchData.map(s => ({ ...s, _searchScore: getMatchScore(s, q) }))
                .filter(s => s._searchScore > 0)
                .sort((a, b) => b._searchScore - a._searchScore)
                .slice(0, 15);

            if (!results.length) {
                container.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-3);font-size:0.85rem;">لا توجد نتائج مطابقة</div>';
                container.classList.add('show');
                return;
            }

            container.innerHTML = results.map(s => {
                const name = s['الاسم'] || '---';
                const cls = s['الفصل'] || '---';
                const id = s['_studentId'] || s['id'] || s['معرف'] || s['id_student'] || 0;
                const photo = s['صورة']
                    ? `<img src="${window.photoUrl ? window.photoUrl(s['صورة']) : s['صورة']}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;">`
                    : `<div style="width:32px;height:32px;border-radius:50%;background:var(--brand-bg);color:var(--brand);display:flex;align-items:center;justify-content:center;font-size:0.85rem;"><i class="fas fa-user"></i></div>`;
                const isExactIdMatch = String(id).trim() === q.trim();

                return `
                <div class="inline-search-item" onclick="selectStudentFromIntelligentSearch(${id})">
                    ${photo}
                    <div class="inline-search-item-body">
                        <div class="inline-search-item-name" style="display:flex; align-items:center; gap:6px; overflow:hidden;">
                            <span style="white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${name}</span>
                            ${isExactIdMatch ? `<span style="background:var(--brand); color:#fff; font-size:0.6rem; padding:1px 5px; border-radius:3px; font-weight:bold; white-space:nowrap; flex-shrink:0;">ID: ${id}</span>` : ''}
                        </div>
                        <div class="inline-search-item-class"><i class="fas fa-chalkboard-teacher"></i> ${cls}</div>
                    </div>
                    <div class="inline-search-item-arrow"><i class="fas fa-chevron-left"></i></div>
                </div>`;
            }).join('');

            container.classList.add('show');
        }

        function performClassInlineSearch(val) {
            searchQuery = (val || '').trim();
            const clearBtn = document.getElementById('clearClassSearchBtn');
            if (clearBtn) {
                clearBtn.style.display = searchQuery ? 'flex' : 'none';
            }
            if (currentClass) {
                renderAttendanceList(currentClass);
            }
        }

        function clearClassSearch() {
            searchQuery = '';
            const input = document.getElementById('classSearchInput');
            if (input) input.value = '';
            const clearBtn = document.getElementById('clearClassSearchBtn');
            if (clearBtn) clearBtn.style.display = 'none';
            if (currentClass) renderAttendanceList(currentClass);
        }

        function performInlineSearch(val, source = 'inline') {
            const q = (val || '').trim();
            const currentInput = document.getElementById(source === 'topbar' ? 'topbarSearchInput' : 'inlineSearchInput');
            const otherInput = document.getElementById(source === 'topbar' ? 'inlineSearchInput' : 'topbarSearchInput');
            const rawValue = currentInput ? currentInput.value : val;
            if (otherInput && otherInput.value !== rawValue) otherInput.value = rawValue;
            _renderInlineSearchResults(q, 'inline');
            _renderInlineSearchResults(q, 'topbar');
        }

        function clearInlineSearch(source = 'inline') {
            ['inlineSearchInput', 'topbarSearchInput'].forEach(id => {
                const input = document.getElementById(id);
                if (input) input.value = '';
            });
            _renderInlineSearchResults('', 'inline');
            _renderInlineSearchResults('', 'topbar');
            const input = document.getElementById(source === 'topbar' ? 'topbarSearchInput' : 'inlineSearchInput');
            if (input) input.focus();
        }

        // Close inline search dropdown on outside clicks
        document.addEventListener('click', function (e) {
            const wrap = document.querySelector('.inline-search-wrap');
            const topbarWrap = document.querySelector('.topbar-search-wrap');
            if (wrap && !wrap.contains(e.target)) {
                const dropdown = document.getElementById('inlineSearchDropdown');
                if (dropdown) dropdown.classList.remove('show');
            }
            if (topbarWrap && !topbarWrap.contains(e.target)) {
                const dropdown = document.getElementById('topbarSearchDropdown');
                if (dropdown) dropdown.classList.remove('show');
            }
        });

        // Re-open search dropdown on focus if input has content
        [['inlineSearchInput', 'inlineSearchDropdown'], ['topbarSearchInput', 'topbarSearchDropdown']].forEach(([inputId, dropdownId]) => {
            const input = document.getElementById(inputId);
            if (!input) return;
            input.addEventListener('focus', function () {
                if (this.value.trim()) {
                    const dropdown = document.getElementById(dropdownId);
                    if (dropdown) dropdown.classList.add('show');
                }
            });
        });

        function escStr(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }

        // Load on boot and every 60s
        window.addEventListener('load', () => {
            setTimeout(loadUnifiedNotifications, 2000);
            setInterval(loadUnifiedNotifications, 60000);
        });

        // Push → DB notification bridge: when SW sends NEW_REGISTRATION push,
        // also create a DB notification so it shows in the panel
        navigator.serviceWorker?.addEventListener('message', e => {
            if (!e.data) return;
            if (e.data.type === 'NEW_REGISTRATION') {
                loadUnifiedNotifications();
            }
            if (e.data.type === 'NOTIFICATION_CLICK') {
                loadUnifiedNotifications();
            }
        });

        window.selectNoteTitleSuggestion = function (sugg) {
            const inp = document.getElementById('noteTitleInput');
            if (inp) inp.value = sugg;
        };

        window.toggleAddNoteArea = function (show = true) {
            const area = document.getElementById('addNoteArea');
            if (area) {
                area.style.display = (show && area.style.display === 'none') ? 'block' : 'none';
                if (area.style.display === 'block') {
                    const dt = document.getElementById('noteDateInput');
                    if (dt) dt.value = new Date().toISOString().split('T')[0];
                }
            }
        };

        window.toggleAddFeeArea = function (show = true) {
            const area = document.getElementById('addFeeArea');
            if (area) {
                area.style.display = (show && area.style.display === 'none') ? 'block' : 'none';
            }
        };

        window.submitStudentNote = function (studentId) {
            const title = document.getElementById('noteTitleInput').value.trim();
            const desc = document.getElementById('noteDescInput').value.trim();
            const date = document.getElementById('noteDateInput').value;

            if (!title || !desc) {
                showToast('يرجى ملء العنوان والتفاصيل', 'warning');
                return;
            }

            showLoading('جاري حفظ الملاحظة...');
            const fd = new FormData();
            fd.append('action', 'addStudentNote');
            fd.append('studentId', studentId);
            fd.append('title', title);
            fd.append('description', desc);
            fd.append('date', date);

            fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                .then(r => r.json())
                .then(d => {
                    hideLoading();
                    if (d.success) {
                        showToast(d.message || 'تم حفظ الملاحظة بنجاح', 'success');
                        showStudentDetails(currentStudentForEdit['الاسم']);
                    } else {
                        showToast(d.message || 'فشل حفظ الملاحظة', 'error');
                    }
                })
                .catch(err => {
                    hideLoading();
                    showToast('حدث خطأ في الاتصال بالخادم', 'error');
                });
        };

        window.deleteStudentNote = function (studentId, noteId) {
            if (!confirm('هل أنت متأكد من حذف هذه الملاحظة؟')) return;

            showLoading('جاري حذف الملاحظة...');
            const fd = new FormData();
            fd.append('action', 'deleteStudentNote');
            fd.append('studentId', studentId);
            fd.append('noteId', noteId);

            fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                .then(r => r.json())
                .then(d => {
                    hideLoading();
                    if (d.success) {
                        showToast(d.message || 'تم حذف الملاحظة بنجاح', 'success');
                        showStudentDetails(currentStudentForEdit['الاسم']);
                    } else {
                        showToast(d.message || 'فشل حذف الملاحظة', 'error');
                    }
                })
                .catch(err => {
                    hideLoading();
                    showToast('حدث خطأ في الاتصال بالخادم', 'error');
                });
        };

        window.openBulkNoteModal = function () {
            if (selectedStudentIds.size === 0) {
                showToast('الرجاء تحديد أطفال أولاً', 'warning');
                return;
            }
            const dt = document.getElementById('bulkNoteDateInput');
            if (dt) dt.value = new Date().toISOString().split('T')[0];

            document.getElementById('bulkNoteTitleInput').value = '';
            document.getElementById('bulkNoteDescInput').value = '';

            openModal('bulkNoteModal');
        };

        window.selectBulkNoteTitleSuggestion = function (sugg) {
            const inp = document.getElementById('bulkNoteTitleInput');
            if (inp) inp.value = sugg;
        };

        window.submitBulkNotes = function (event) {
            if (event) event.preventDefault();
            if (selectedStudentIds.size === 0) {
                showToast('الرجاء تحديد أطفال أولاً', 'warning');
                return;
            }

            const title = document.getElementById('bulkNoteTitleInput').value.trim();
            const desc = document.getElementById('bulkNoteDescInput').value.trim();
            const date = document.getElementById('bulkNoteDateInput').value;

            if (!title || !desc) {
                showToast('يرجى ملء العنوان والتفاصيل', 'warning');
                return;
            }

            showLoading('جاري حفظ الملاحظات...');
            const fd = new FormData();
            fd.append('action', 'bulkAddStudentNotes');
            fd.append('student_ids', Array.from(selectedStudentIds).join(','));
            fd.append('title', title);
            fd.append('description', desc);
            fd.append('date', date);

            fetch(API_URL, { method: 'POST', body: fd, credentials: 'include' })
                .then(r => r.json())
                .then(d => {
                    hideLoading();
                    if (d.success) {
                        showToast(d.message || 'تم حفظ الملاحظات الجماعية بنجاح', 'success');
                        closeModal('bulkNoteModal');
                        selectedStudentIds.clear();
                        updateBulkUI();
                        loadData();
                    } else {
                        showToast(d.message || 'فشل حفظ الملاحظات الجماعية', 'error');
                    }
                })
                .catch(err => {
                    hideLoading();
                    showToast('حدث خطأ في الاتصال بالخادم', 'error');
                });
        };

